import {} from '../types';

const CODE_CONTROLLER = `
// 1. CONTROLLER (Main Entry & Routing)
// RESOLVED: This script will NEVER automatically create sheets in the spreadsheet.
// All sheets must be created manually with the exact case-sensitive names.

function doPost(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(30000); 

  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const body = e.postData ? JSON.parse(e.postData.contents) : {};
    return routeRequest(ss, body);
  } catch (err) {
    return ResponseBuilder.error("System Exception: " + err.toString());
  } finally {
    lock.releaseLock();
  }
}

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  SystemHandlers.cleanupOldNotifications(ss);
  return DataHandlers.handleGetRequest(ss);
}

function routeRequest(ss, body) {
  const action = body.action;
  const routes = {
    'login': () => AuthHandlers.handleLogin(ss, body),
    'register_user': () => AuthHandlers.handleRegisterUser(ss, body),
    'get_users': () => AuthHandlers.handleGetUsers(ss),
    'delete_user': () => AuthHandlers.handleDeleteUser(ss, body),
    'update_user': () => AuthHandlers.handleUpdateUser(ss, body),
    'heartbeat': () => AuthHandlers.handleHeartbeat(ss, body),
    'manage_fleet': () => SystemHandlers.handleManageFleet(ss, body),
    'bulk_manage_fleet': () => SystemHandlers.handleBulkManageFleet(ss, body),
    'acknowledge_issue': () => SystemHandlers.handleAcknowledgeIssue(ss, body),
    'request_inspection': () => SystemHandlers.handleRequestInspection(ss, body),
    'get_acknowledgements': () => SystemHandlers.handleGetAcknowledgements(ss),
    'mark_notification_read': () => SystemHandlers.handleMarkNotificationRead(ss, body),
    'update_settings': () => SystemHandlers.handleUpdateSettings(ss, body),
    'broadcast': () => SystemHandlers.handleBroadcast(ss, body),
    'check_subscription': () => SubscriptionHandlers.handleCheckSubscription(ss),
    'extend_subscription': () => SubscriptionHandlers.handleExtendSubscription(ss, body),
    'submit_support_ticket': () => SupportHandlers.handleSubmitSupport(ss, body),
    'get_tickets': () => SupportHandlers.handleGetTickets(ss, body),
    'update_ticket': () => SupportHandlers.handleUpdateTicket(ss, body),
    'initiate_mobile_payment': () => PaymentHandlers.handleMobileMoney(ss, body)
  };

  if (!action || action === 'create' || !routes[action]) {
    return DataHandlers.handleDataSubmission(ss, body);
  }
  return routes[action]();
}`;

const CODE_AUTH = `
// 2. AUTHENTICATION HANDLERS
const AuthHandlers = {
  handleLogin: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.error("Configuration Error: 'Users' sheet not found in the database.");
    const data = userSheet.getDataRange().getValues();
    const username = body.username.toLowerCase();
    for (let i = 1; i < data.length; i++) {
        if (data[i][1].toLowerCase() === username && data[i][2] === body.password) {
            return ResponseBuilder.success({ user: { id: data[i][0], username: data[i][1], name: data[i][3], role: data[i][4] } });
        }
    }
    return ResponseBuilder.error("Invalid credentials.");
  },
  handleHeartbeat: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.error("Users sheet missing");
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][1].toLowerCase() === body.username.toLowerCase()) {
        sheet.getRange(i + 1, 10).setValue(new Date().toISOString()); 
        sheet.getRange(i + 1, 11).setValue(body.isTyping ? "TRUE" : "FALSE");
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("User context lost");
  },
  handleRegisterUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.error("Database Error: 'Users' sheet must be created manually before enrolling staff.");
    const id = "USR-" + Date.now();
    sheet.appendRow([id, body.username.toLowerCase(), body.password, body.name, body.role, body.position, new Date().toISOString(), "{}", "TRUE", "", "FALSE"]);
    return ResponseBuilder.success();
  },
  handleGetUsers: function(ss) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.success({ users: [] });
    const data = sheet.getDataRange().getValues();
    const users = data.slice(1).map(r => ({ 
      id: r[0],
      username: r[1], 
      name: r[3], 
      role: r[4], 
      position: r[5], 
      isActive: r[8] === "TRUE",
      lastSeen: r[9],
      isTyping: r[10] === "TRUE"
    }));
    return ResponseBuilder.success({ users });
  },
  handleDeleteUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.error("Database Access Failed: 'Users' sheet missing.");
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][1].toLowerCase() === body.username.toLowerCase()) {
        sheet.deleteRow(i + 1);
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("Target user not found in registry.");
  },
  handleUpdateUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.error("Users sheet missing");
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][1].toLowerCase() === (body.originalUsername || body.username).toLowerCase()) {
        if (body.username) sheet.getRange(i + 1, 2).setValue(body.username);
        if (body.password) sheet.getRange(i + 1, 3).setValue(body.password);
        if (body.name) sheet.getRange(i + 1, 4).setValue(body.name);
        if (body.role) sheet.getRange(i + 1, 5).setValue(body.role);
        if (body.position) sheet.getRange(i + 1, 6).setValue(body.position);
        if (body.isActive !== undefined) sheet.getRange(i + 1, 9).setValue(body.isActive ? "TRUE" : "FALSE");
        if (body.preferences) sheet.getRange(i + 1, 8).setValue(JSON.stringify(body.preferences));
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("User not found");
  }
};`;

const CODE_CORE_OPS = `
// 3. CORE OPERATIONS (Data, Systems, Subscription)
const DataHandlers = {
  handleDataSubmission: function(ss, body) {
    const sheetName = body.sheet;
    const rowData = body.row;
    let sheet = ss.getSheetByName(sheetName);

    // CRITICAL: Prevent auto-sheet creation
    if (!sheet) {
      return ResponseBuilder.error("Target Registry Found: No sheet named '" + sheetName + "' exists. Please create it manually in your spreadsheet.");
    }

    const safeRow = rowData.map(r => (r === null || r === undefined) ? "" : String(r));
    sheet.appendRow(safeRow);

    // Update Request status if applicable
    if (body.requestId) {
        const reqSheet = ss.getSheetByName('Inspection_Requests');
        if (reqSheet) {
            const reqData = reqSheet.getDataRange().getValues();
            for (let i = 1; i < reqData.length; i++) {
                if (String(reqData[i][0]) === String(body.requestId)) {
                    reqSheet.getRange(i + 1, 10).setValue('Completed');
                    break;
                }
            }
        }
    }

    if (body.reportData) {
      EmailDispatcher.sendInspectionReport(body.reportData);
    }

    return ResponseBuilder.success({ sheet: sheetName });
  },

  handleGetRequest: function(ss) {
    const sheets = ss.getSheets();
    const data = {};
    sheets.forEach(sheet => {
      const name = sheet.getName();
      if (name === 'Users' || name === 'System_Logs') return;
      const lastRow = sheet.getLastRow();
      if (lastRow === 0) { data[name] = []; return; }

      if (name === 'Validation_Data') {
         if (lastRow > 1) {
            const range = sheet.getRange(2, 1, lastRow - 1, sheet.getLastColumn());
            const values = range.getValues();
            const columns = {};
            const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
            headers.forEach((h, colIndex) => {
               columns[h] = [...new Set(values.map(row => row[colIndex]).filter(c => c !== ""))]; 
            });
            data[name] = columns;
         } else { data[name] = {}; }
      } else if (name === 'Subscription_Data') {
          const values = sheet.getDataRange().getValues();
          if (values.length > 1) {
            const history = [];
            for (let i = 1; i < values.length; i++) {
                const row = values[i];
                let expiry = row[2];
                if (expiry instanceof Date) expiry = Utilities.formatDate(expiry, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
                history.push({ status: row[0], plan: row[1], expiryDate: expiry, processedBy: row[3], timestamp: row[4] });
            }
            data[name] = { current: history[history.length - 1], history: history };
          } else { data[name] = { current: { status: "Expired", plan: "None", expiryDate: "" }, history: [] }; }
      } else {
         const startRow = Math.max(1, lastRow - 150);
         const values = sheet.getRange(startRow, 1, lastRow - startRow + 1, sheet.getLastColumn()).getValues();
         if (startRow > 1) values.unshift(sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0]);
         data[name] = values;
      }
    });
    return ResponseBuilder.build(data);
  }
};

const PaymentHandlers = {
  handleMobileMoney: function(ss, body) {
    const settingsSheet = ss.getSheetByName('System_Settings');
    if (!settingsSheet) return ResponseBuilder.error("System_Settings sheet not found.");
    const secretKey = settingsSheet.getRange(2, 10).getValue(); 

    if (!secretKey) return ResponseBuilder.error("Payment system not configured. Secret Key missing in System_Settings.");

    const tx_ref = "TXN-" + Date.now();
    const payload = {
      "amount": body.amount, "currency": "ZMW", "phone_number": body.phoneNumber,
      "network": body.network, "email": body.email, "tx_ref": tx_ref,
      "order_id": "SUB-" + Date.now(), "description": body.description, "country": "ZM"
    };

    const options = {
      "method": "post", "contentType": "application/json",
      "headers": { "Authorization": "Bearer " + secretKey },
      "payload": JSON.stringify(payload), "muteHttpExceptions": true
    };

    try {
      const response = UrlFetchApp.fetch("https://api.flutterwave.com/v3/charges?type=mobile_money_zambia", options);
      const resData = JSON.parse(response.getContentText());
      if (resData.status === "success") {
        return ResponseBuilder.success({ message: "PIN Prompt dispatched.", tx_ref: tx_ref });
      } else {
        return ResponseBuilder.error(resData.message || "Gateway rejection.");
      }
    } catch (e) {
      return ResponseBuilder.error("Payment link timeout.");
    }
  }
};

const SubscriptionHandlers = {
  handleCheckSubscription: function(ss) {
    let subSheet = ss.getSheetByName('Subscription_Data');
    if (!subSheet) return ResponseBuilder.success({ subscription: { status: 'Expired', daysRemaining: 0 } });
    const lastRow = subSheet.getLastRow();
    if (lastRow < 2) return ResponseBuilder.success({ subscription: { status: 'Expired', daysRemaining: 0 } });
    const data = subSheet.getRange(lastRow, 1, 1, 4).getValues()[0];
    let status = data[0];
    const expiry = new Date(data[2]);
    const now = new Date();
    if (status === 'Active' && !isNaN(expiry.getTime()) && now > expiry) {
        status = 'Expired';
        subSheet.getRange(lastRow, 1).setValue('Expired');
    }
    return ResponseBuilder.success({ 
        subscription: {
            status: status, plan: data[1], expiryDate: data[2],
            daysRemaining: Math.ceil((expiry.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))
        }
    });
  },
  handleExtendSubscription: function(ss, body) {
    let subSheet = ss.getSheetByName('Subscription_Data');
    if (!subSheet) return ResponseBuilder.error("Subscription_Data sheet missing.");
    subSheet.appendRow(["Active", body.plan || "Enterprise", body.expiryDate, body.processedBy || "System", new Date().toISOString()]);
    return ResponseBuilder.success();
  }
};

const SystemHandlers = {
  handleUpdateSettings: function(ss, body) {
    let settingsSheet = ss.getSheetByName('System_Settings');
    if (!settingsSheet) return ResponseBuilder.error("System_Settings sheet missing.");

    const updateRow = [
      body.companyName || '', body.managerEmail || '', new Date(), body.updatedBy || "Admin", 
      body.companyLogo || '', "", "", body.maintenanceMode ? "TRUE" : "FALSE", 
      body.maintenanceMessage || '', body.flutterwaveSecretKey || ''
    ];
    if (settingsSheet.getLastRow() < 2) settingsSheet.appendRow(updateRow);
    else settingsSheet.getRange(2, 1, 1, updateRow.length).setValues([updateRow]);
    return ResponseBuilder.success();
  },
  handleManageFleet: function(ss, body) {
    const sheet = ss.getSheetByName('Validation_Data');
    if (!sheet) return ResponseBuilder.error("Validation_Data sheet missing.");
    const col = body.type === 'truck' ? 1 : 2;
    sheet.getRange(sheet.getLastRow() + 1, col).setValue(body.value);
    return ResponseBuilder.success();
  },
  handleBulkManageFleet: function(ss, body) {
    const sheet = ss.getSheetByName('Validation_Data');
    if (!sheet) return ResponseBuilder.error("Validation_Data sheet missing.");
    if (body.trucks) body.trucks.forEach(t => sheet.getRange(sheet.getLastRow() + 1, 1).setValue(t));
    if (body.trailers) body.trailers.forEach(t => sheet.getRange(sheet.getLastRow() + 1, 2).setValue(t));
    return ResponseBuilder.success();
  },
  handleRequestInspection: function(ss, body) {
    const sheet = ss.getSheetByName('Inspection_Requests');
    if (!sheet) return ResponseBuilder.error("Inspection_Requests sheet missing.");
    const requestId = "REQ-" + Date.now();
    sheet.appendRow([requestId, body.requester, body.role, body.truckNo, body.trailerNo, body.type, body.reason, body.priority, body.assignedInspector || "Unassigned", "Pending", new Date().toISOString()]);
    return ResponseBuilder.success();
  },
  handleBroadcast: function(ss, body) {
    const sheet = ss.getSheetByName('SystemNotification');
    if (!sheet) return ResponseBuilder.error("SystemNotification sheet missing.");
    const id = "BC-" + Date.now();
    sheet.appendRow([id, "all", body.type, body.message, new Date().toISOString(), "FALSE", "overview"]);
    return ResponseBuilder.success();
  },
  cleanupOldNotifications: function(ss) {}
};

const SupportHandlers = {
  handleSubmitSupport: function(ss, body) {
    const sheet = ss.getSheetByName('Support_Tickets');
    if (!sheet) return ResponseBuilder.error("Support_Tickets sheet missing.");
    const id = "TKT-" + Math.floor(Math.random()*90000 + 10000);
    sheet.appendRow([id, body.type, body.subject, body.description, body.priority, body.user, body.email, body.role, new Date().toISOString(), "Open", "[]"]);
    return ResponseBuilder.success();
  },
  handleGetTickets: function(ss, body) {
    const sheet = ss.getSheetByName('Support_Tickets');
    if (!sheet) return ResponseBuilder.success({ tickets: [] });
    const data = sheet.getDataRange().getValues();
    const tickets = [];
    for(let i=1; i<data.length; i++) {
      const r = data[i];
      if (body.role === 'Admin' || body.role === 'SuperAdmin' || r[6] === body.email) {
        tickets.push({
          ticketId: r[0], type: r[1], subject: r[2], description: r[3],
          priority: r[4], user: r[5], email: r[6], role: r[7],
          timestamp: r[8], status: r[9], comments: JSON.parse(r[10] || "[]")
        });
      }
    }
    return ResponseBuilder.success({ tickets: tickets.reverse() });
  },
  handleUpdateTicket: function(ss, body) {
    const sheet = ss.getSheetByName('Support_Tickets');
    if (!sheet) return ResponseBuilder.error("Sheet missing.");
    const data = sheet.getDataRange().getValues();
    for(let i=1; i<data.length; i++) {
      if (String(data[i][0]) === String(body.ticketId)) {
        const comments = JSON.parse(data[i][10] || "[]");
        comments.push(body.comment);
        sheet.getRange(i+1, 11).setValue(JSON.stringify(comments));
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("Ticket not found.");
  }
};

const EmailDispatcher = {
  sendInspectionReport: function(data) {
    try {
      const settingsSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName('System_Settings');
      let adminEmail = "";
      if (settingsSheet && settingsSheet.getLastRow() > 1) adminEmail = settingsSheet.getRange(2, 2).getValue();
      if (!adminEmail) return;
      MailApp.sendEmail({
        to: adminEmail,
        subject: "SAFETY REPORT: " + data.truckNo + " - " + data.title,
        htmlBody: "A new inspection report has been filed for unit " + data.truckNo + ".<br>Overall Rating: " + data.rate + "/5<br>Safe to Load: " + data.safeToLoad
      });
    } catch (e) {}
  }
};
`;

const CODE_LIB = `const ResponseBuilder = {
  success: function(data = {}) { return this.build({ status: "success", ...data }); },
  error: function(message) { return this.build({ status: "error", message: message }); },
  build: function(data) { return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON); }
};`;

