import { useState, useEffect, useCallback, useRef } from 'react';
import { User } from '../types';

// Professional Session Constraints - Extended to 30 days to ensure persistence on refresh
const IDLE_TIMEOUT_MS = 30 * 24 * 60 * 60 * 1000; // 30 Days
const MAX_SESSION_MS = 30 * 24 * 60 * 60 * 1000; // 30 Days

export const useAuth = () => {
    // 1. Synchronous Initialization from LocalStorage to prevent logout on refresh
    const [currentUser, setCurrentUser] = useState<User | null>(() => {
        const savedUser = localStorage.getItem('safetyCheck_user');
        if (savedUser) {
            try {
                const u = JSON.parse(savedUser);
                // Normalize role case for consistency
                const rawRole = u.role ? String(u.role).trim().toLowerCase() : '';
                if (rawRole === 'admin') u.role = 'Admin';
                else if (rawRole === 'operations') u.role = 'Operations';
                else if (rawRole === 'maintenance') u.role = 'Maintenance';
                else if (rawRole === 'secretary') u.role = 'Secretary';
                else if (rawRole === 'other') u.role = 'Other';
                else if (rawRole === 'superadmin') u.role = 'SuperAdmin';
                else u.role = 'Inspector';

                // CRITICAL: Strict Onboarding Check
                u.needsSetup = !u.name || u.needsSetup === true;
                return u;
            } catch (e) {
                return null;
            }
        }
        return null;
    });

    const [sessionExpired, setSessionExpired] = useState<'idle' | 'max_duration' | null>(null);

    // Refs to track timers without re-renders, initialized from storage if available
    const lastActivityRef = useRef<number>(
        (() => {
            const saved = localStorage.getItem('safetyCheck_last_activity');
            return saved ? parseInt(saved, 10) : Date.now();
        })()
    );

    const sessionStartRef = useRef<number>(
        (() => {
            const saved = localStorage.getItem('safetyCheck_session_start');
            return saved ? parseInt(saved, 10) : Date.now();
        })()
    );

    const timerRef = useRef<number | null>(null);

    // 2. Lifecycle management for session listeners
    useEffect(() => {
        if (currentUser) {
            const savedSessionStart = localStorage.getItem('safetyCheck_session_start');

            // Check Absolute Session Expiry immediately on mount
            if (savedSessionStart) {
                const start = parseInt(savedSessionStart, 10);
                const elapsed = Date.now() - start;
                if (elapsed > MAX_SESSION_MS) {
                    handleLogout('max_duration');
                    return;
                }
                sessionStartRef.current = start;
            } else {
                localStorage.setItem('safetyCheck_session_start', Date.now().toString());
            }

            startActivityListeners();
        }

        return () => {
            stopActivityListeners();
        };
    }, [currentUser]);

    const updateActivity = useCallback(() => {
        if (!currentUser) return;
        const now = Date.now();
        // Throttled storage update (max once per second)
        if (now - lastActivityRef.current > 1000) {
            lastActivityRef.current = now;
            localStorage.setItem('safetyCheck_last_activity', now.toString());
        }
    }, [currentUser]);

    const startActivityListeners = () => {
        window.addEventListener('mousemove', updateActivity);
        window.addEventListener('keydown', updateActivity);
        window.addEventListener('touchstart', updateActivity);
        window.addEventListener('click', updateActivity);

        if (timerRef.current) window.clearInterval(timerRef.current);
        timerRef.current = window.setInterval(checkSessionStatus, 60000); // Check status every minute
    };

    const stopActivityListeners = () => {
        window.removeEventListener('mousemove', updateActivity);
        window.removeEventListener('keydown', updateActivity);
        window.removeEventListener('touchstart', updateActivity);
        window.removeEventListener('click', updateActivity);

        if (timerRef.current) {
            window.clearInterval(timerRef.current);
            timerRef.current = null;
        }
    };

    const checkSessionStatus = () => {
        const now = Date.now();

        // Restore from storage to sync across tabs if necessary
        const lastSaved = localStorage.getItem('safetyCheck_last_activity');
        const effectiveLastActivity = lastSaved ? parseInt(lastSaved, 10) : lastActivityRef.current;

        if (now - effectiveLastActivity > IDLE_TIMEOUT_MS) {
            handleLogout('idle');
            return;
        }
        if (now - sessionStartRef.current > MAX_SESSION_MS) {
            handleLogout('max_duration');
            return;
        }
    };

    const handleLogin = (user: User) => {
        const now = Date.now();
        // Recalculate needsSetup upon login
        const userToStore = {
            ...user,
            needsSetup: !user.name || user.needsSetup === true
        };

        setCurrentUser(userToStore);
        localStorage.setItem('safetyCheck_user', JSON.stringify(userToStore));
        localStorage.setItem('safetyCheck_session_start', now.toString());
        localStorage.setItem('safetyCheck_last_activity', now.toString());
        sessionStartRef.current = now;
        lastActivityRef.current = now;
        setSessionExpired(null);
        startActivityListeners();
    };

    const handleLogout = (reason?: 'idle' | 'max_duration') => {
        stopActivityListeners();
        setCurrentUser(null);
        if (reason) setSessionExpired(reason);

        const keysToRemove = [
            'safetyCheck_user',
            'safetyCheck_session_start',
            'safetyCheck_last_activity',
            'sc_validation_lists',
            'sc_remembered_creds'
        ];
        keysToRemove.forEach(k => localStorage.removeItem(k));
    };

    return { 
        currentUser, 
        setCurrentUser, 
        handleLogin, 
        handleLogout,
        sessionExpired,
        setSessionExpired
    };
};

import React from 'react';
import { SubscriptionDetails, User } from '../../types';

interface SubscriptionAlertProps {
    subscription: SubscriptionDetails | null;
    user: User | null;
    onManage: () => void;
}

const SubscriptionAlert: React.FC<SubscriptionAlertProps> = ({ subscription, user, onManage }) => {
    // If no user is logged in, don't show anything
    if (!user) return null;

    const isSuperAdmin = user.role === 'SuperAdmin';

    // --- BACKGROUND VALIDATION ---
    // Make verification run in the background (return null instead of a visible bar)
    if (subscription === null) return null;

    // --- DETERMINING STATUS AFTER FETCH ---
    const isExpired = subscription.status === 'Expired' || !subscription.expiryDate || subscription.daysRemaining <= 0;
    const isNearExpiry = !isExpired && subscription.status === 'Active' && subscription.daysRemaining > 0 && subscription.daysRemaining <= 7;

    // If active and not near expiry, hide the bar completely
    if (!isExpired && !isNearExpiry) return null;

    return (
        <div className={`w-full px-4 py-3 flex items-center justify-between shadow-md relative z-[100] animate-fadeIn
            ${isExpired ? 'bg-red-600 text-white' : 'bg-amber-500 text-white'}
        `}>
            <div className="flex items-center gap-3">
                <div className="p-1.5 bg-white/20 rounded-full">
                    {isExpired ? (
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                    ) : (
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
                    )}
                </div>
                <div>
                    <p className="text-sm font-bold uppercase tracking-wide">
                        {isExpired ? 'SYSTEM LICENSE EXPIRED' : 'LICENSE EXPIRING SOON'}
                    </p>
                    <p className="text-xs font-medium opacity-90">
                        {isExpired 
                            ? 'Access to core features is restricted. Renew to restore modification access.'
                            : `${subscription?.daysRemaining} days remaining. Please renew soon.`
                        }
                    </p>
                </div>
            </div>

            {isSuperAdmin && (
                <button 
                    onClick={onManage}
                    className="px-4 py-2 bg-white text-gray-900 rounded-lg text-xs font-bold uppercase tracking-wider hover:bg-gray-100 transition-colors shadow-sm"
                >
                    Manage License
                </button>
            )}
        </div>
    );
};

export default SubscriptionAlert;

