    const [messages, setMessages] = useState<ChatMessage[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_messages');
        return cached ? JSON.parse(cached) : [];
    });

    const [staff, setStaff] = useState<User[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_staff');
        return cached ? JSON.parse(cached) : [];
    });

    const [searchTerm, setSearchTerm] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [isLoading, setIsLoading] = useState(false);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const lastFetchRef = useRef<number>(0);
    const heartbeatRef = useRef<number | null>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    // Role check for permissions
    const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';

    // Online presence check
    const isUserOnline = (member: User) => {
        if (!member.lastSeen) return false;
        const diff = Date.now() - new Date(member.lastSeen).getTime();
        return diff < 45000;
    };

    // Helper to normalize IDs for comparison
    const normalize = (id: string) => (id || '').toLowerCase().trim();

    // Filtered messages for current view (excluding heartbeats/status messages)
    const chatOnlyMessages = useMemo(() => {
        return messages.filter(m => m.status !== 'Presence' && m.status !== 'Typing' && m.status !== 'HB');
    }, [messages]);

    // Calculate total unique senders with unread personal messages for the main icon
    const totalUnreadCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        const unreadFromSenders = new Set(
            chatOnlyMessages
                .filter(m => normalize(m.receiverId) === myUid && m.status === 'Sent')
                .map(m => normalize(m.senderId))
        );
        return unreadFromSenders.size;
    }, [chatOnlyMessages, currentUser]);

    const filteredMessagesForView = useMemo(() => {
        if (!currentUser) return [];

        return chatOnlyMessages.filter(m => {
            const isBroadcast = (m.message || '').startsWith('[BROADCAST]:') || normalize(m.receiverId) === 'all';

            if (!selectedStaff) {
                return isBroadcast;
            } else {
                const myUid = normalize(currentUser.username);
                const partnerUid = normalize(selectedStaff.username);
                const senderUid = normalize(m.senderId);
                const receiverUid = normalize(m.receiverId);

                const isFromMeToThem = senderUid === myUid && receiverUid === partnerUid;
                const isFromThemToMe = senderUid === partnerUid && receiverUid === myUid;
                return isFromMeToThem || isFromThemToMe;
            }
        });
    }, [chatOnlyMessages, selectedStaff, currentUser]);

    const activeChatPartner = useMemo(() => {
        if (!selectedStaff) return null;
        return staff.find(s => normalize(s.username) === normalize(selectedStaff.username)) || selectedStaff;
    }, [selectedStaff, staff]);

    const markAsRead = async (sender: User) => {
        if (!appScriptUrl || !currentUser) return;
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'text/plain' },
                body: JSON.stringify({
                    action: 'mark_read',
                    username: currentUser.username,
                    senderId: sender.username
                }),
                mode: 'no-cors'
            });
            // Update local state immediately to remove badges
            setMessages(prev => prev.map(m => {
                if (normalize(m.senderId) === normalize(sender.username) && 
                    normalize(m.receiverId) === normalize(currentUser.username)) {
                    return { ...m, status: 'Read' };
                }
                return m;
            }));
        } catch (e) {}
    };

    const sendHeartbeat = async () => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'text/plain' },
                body: JSON.stringify({
                    action: 'heartbeat',
                    username: currentUser.username,
                    name: currentUser.name,
                    isTyping: input.trim().length > 0 && view === 'chat' && !!selectedStaff
                }),
                mode: 'no-cors'
            });
        } catch (e) {}
    };

    useEffect(() => {
        if (currentUser) {
            sendHeartbeat();
            heartbeatRef.current = window.setInterval(sendHeartbeat, 15000);
        }
        return () => {
            if (heartbeatRef.current) window.clearInterval(heartbeatRef.current);
        };
    }, [currentUser, input, view, selectedStaff]);

    useEffect(() => {
        if (isOpen && view === 'chat' && selectedStaff) {
            markAsRead(selectedStaff);
        }
    }, [isOpen, view, selectedStaff]);

    const fetchData = async (showLoading = false) => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;

        const now = Date.now();
        if (now - lastFetchRef.current < 3000) return; 
        lastFetchRef.current = now;

        if (showLoading && staff.length === 0) setIsLoading(true);

        try {
            const userResponse = await fetch(appScriptUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'text/plain' },
                body: JSON.stringify({ action: 'get_users' })
            });

            if (userResponse.ok) {
                const userData = await userResponse.json();
                if (userData.status === 'success' && Array.isArray(userData.users)) {
                    const filteredStaff = userData.users.filter((u: User) => normalize(u.username) !== normalize(currentUser.username));
                    setStaff(filteredStaff);
                    localStorage.setItem('sc_chat_cache_staff', JSON.stringify(filteredStaff));
                }
            }

            const msgResponse = await fetch(`${appScriptUrl}?t=${now}`);
            if (msgResponse.ok) {
                const json = await msgResponse.json();
                const chatData = json['Messages'];
                if (chatData && Array.isArray(chatData) && chatData.length > 1) {
                    const mappedMessages: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                        id: String(row[0]),
                        senderId: row[1],
                        senderName: row[2],
                        receiverId: row[3],
                        message: row[4] || '',
                        timestamp: row[5],
                        status: row[6] || 'Sent'
                    }));

                    setMessages(prev => {
                        const serverIds = new Set(mappedMessages.map(m => m.id));
                        const localOnly = prev.filter(p => normalize(p.senderId) === normalize(currentUser?.username) && !serverIds.has(p.id));
                        const combined = [...mappedMessages, ...localOnly];
                        const sorted = combined.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
                        localStorage.setItem('sc_chat_cache_messages', JSON.stringify(sorted));
                        return sorted;
                    });
                }
            }
        } catch (error) {
            console.warn("Chat sync skipped:", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchData(true);
        const interval = window.setInterval(() => fetchData(false), 8000);
        return () => window.clearInterval(interval);
    }, [appScriptUrl, currentUser?.username]);

    useEffect(() => {
        if (isOpen && view === 'chat') scrollToBottom();
    }, [filteredMessagesForView, isOpen, view]);

    const handleSendMessage = async (isGlobalAnnouncement = false) => {
        if (!input.trim() || isSending || !currentUser) return;

        // Final permission check for broadcast
        if (isGlobalAnnouncement && !isAdmin) return;

        const receiver = isGlobalAnnouncement ? 'ALL' : selectedStaff ? selectedStaff.username : 'ALL';
        const msgPrefix = isGlobalAnnouncement ? '[BROADCAST]: ' : '';
        const msgId = "M-" + Date.now();

        const optimisticMsg: ChatMessage = {
            id: msgId,
            senderId: currentUser.username,
            senderName: currentUser.name,
            receiverId: receiver,
            message: `${msgPrefix}${input.trim()}`,
            timestamp: new Date().toISOString(),
            status: 'Sent'
        };

        setInput('');
        setIsSending(true);

        setMessages(prev => [...prev, optimisticMsg]);

        const payload = {
            action: 'create',
            sheet: 'Messages',
            headers: ['ID', 'SenderID', 'SenderName', 'ReceiverID', 'Message', 'Timestamp', 'Status'],
            row: [optimisticMsg.id, optimisticMsg.senderId, optimisticMsg.senderName, optimisticMsg.receiverId, optimisticMsg.message, optimisticMsg.timestamp, optimisticMsg.status]
        };

        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'text/plain' },
                body: JSON.stringify(payload),
                mode: 'no-cors'
            });
            if (view === 'list') setView('chat');
        } catch (error) {
            console.error("Message delivery failed", error);
        } finally {
            setIsSending(false);
        }
    };

    const cleanMessage = (text: string) => {
        if (!text || typeof text !== 'string') return '';
        return text.replace(/^\[BROADCAST\]:\s*/, '');
    };

    const sortedStaffList = useMemo(() => {
        if (!currentUser) return [];
        const myId = normalize(currentUser.username);

        const baseFiltered = staff.filter(s => 
            s.name?.toLowerCase().includes(searchTerm.toLowerCase()) || 
            s.username?.toLowerCase().includes(searchTerm.toLowerCase())
        );

        return baseFiltered.sort((a, b) => {
            const partnerA = normalize(a.username);
            const partnerB = normalize(b.username);

            // 1. Calculate unread counts for sorting priority
            const unreadA = chatOnlyMessages.filter(m => normalize(m.senderId) === partnerA && normalize(m.receiverId) === myId && m.status === 'Sent').length;
            const unreadB = chatOnlyMessages.filter(m => normalize(m.senderId) === partnerB && normalize(m.receiverId) === myId && m.status === 'Sent').length;

            if (unreadA > 0 && unreadB === 0) return -1;
            if (unreadB > 0 && unreadA === 0) return 1;

            // 2. Tie-breaker: latest message timestamp
            const latestA = chatOnlyMessages.filter(m => (normalize(m.senderId) === partnerA && normalize(m.receiverId) === myId) || (normalize(m.senderId) === myId && normalize(m.receiverId) === partnerA)).pop();
            const latestB = chatOnlyMessages.filter(m => (normalize(m.senderId) === partnerB && normalize(m.receiverId) === myId) || (normalize(m.senderId) === myId && normalize(m.receiverId) === partnerB)).pop();

            const timeA = latestA ? new Date(latestA.timestamp).getTime() : 0;
            const timeB = latestB ? new Date(latestB.timestamp).getTime() : 0;

            return timeB - timeA;
        });
    }, [staff, searchTerm, chatOnlyMessages, currentUser]);

    const typingUsers = useMemo(() => {
        return staff.filter(s => s.isTyping && isUserOnline(s)).map(s => s.name);
    }, [staff]);

    const MessageStatusIndicator = ({ status, isMe }: { status: string, isMe: boolean }) => {
        if (!isMe) return null;
        const isRead = status === 'Read';
        return (
            <div className="flex items-center ml-1 shrink-0">
                {isRead ? (
                    <svg className="w-3.5 h-3.5 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M0.41 13.41L6 19L7.41 17.58L1.83 12M22.24 5.58L11.66 16.17L7.5 12L6.07 13.41L11.66 19L23.66 7M18 7L16.59 5.58L10.24 11.93L11.66 13.34L18 7Z"/></svg>
                ) : (
                    <svg className="w-3.5 h-3.5 text-slate-300" fill="currentColor" viewBox="0 0 24 24"><path d="M21,7L9,19L3.5,13.5L4.91,12.09L9,16.17L19.59,5.59L21,7Z"/></svg>
                )}
            </div>
        );
    };

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end font-sans">
            {isOpen && (
                <div className="mb-4 w-[330px] sm:w-[350px] h-[440px] bg-white rounded-[2rem] shadow-[0_20px_60px_-15px_rgba(0,0,0,0.3)] border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">

                    {/* Main Header */}
                    <div className="bg-[#0f172a] p-4 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-9 h-9 bg-[#4f46e5] rounded-xl flex items-center justify-center text-white shadow-lg">
                                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg>
                            </div>
                            <h3 className="text-[11px] font-bold text-white tracking-tight leading-none uppercase">Staff Chat</h3>
                        </div>
                        <div className="flex items-center gap-2">
                            {isAdmin && (
                                <button onClick={() => { setSelectedStaff(null); setView('chat'); setInput(''); fetchData(true); }} className="bg-[#4f46e5] hover:bg-[#4338ca] text-white px-2.5 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all">
                                    <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M11 5.882V19.24a1.76 1.76 0 01-3.417.592l-2.147-6.15M18 13a3 3 0 100-6M5.436 13.683A4.001 4.001 0 017 6h1.832c4.1 0 7.625-1.234 9.168-3v14c-1.543-1.766-5.067-3-9.168-3H7a3.988 3.988 0 01-1.564-.317z" /></svg>
                                    Announcements
                                </button>
                            )}
                            <button onClick={() => setIsOpen(false)} className="p-1 text-slate-400 hover:text-white transition-colors">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg>
                            </button>
                        </div>
                    </div>

                    {view === 'list' ? (
                        <>
                            {/* Current User Status Banner with Inspector Indicator */}
                            {currentUser && (
                                <div className="px-4 py-3 bg-indigo-50/50 border-b border-indigo-100/50 flex items-center justify-between shrink-0">
                                    <div className="flex items-center gap-2">
                                        <div className="relative">
                                            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white text-[10px] font-bold">
                                                {currentUser.name.substring(0, 2).toUpperCase()}
                                            </div>
                                            <span className="absolute -bottom-0.5 -right-0.5 w-2.5 h-2.5 bg-emerald-500 border-2 border-white rounded-full"></span>
                                        </div>
                                        <div>
                                            <p className="text-[9px] font-black text-indigo-900 uppercase tracking-tight leading-none">{currentUser.name} (Me)</p>
                                            <p className={`text-[7px] font-bold uppercase tracking-widest flex items-center gap-1 mt-1 ${normalize(currentUser.role) === 'inspector' ? 'text-emerald-600' : 'text-emerald-600'}`}>
                                                <span className={`w-1 h-1 rounded-full animate-pulse ${normalize(currentUser.role) === 'inspector' ? 'bg-emerald-500' : 'bg-emerald-500'}`}></span>
                                                {normalize(currentUser.role) === 'inspector' ? 'Live on Inspection' : 'Active & Visible'}
                                            </p>
                                        </div>
                                    </div>
                                    <div className={`px-2 py-1 border rounded-md shadow-sm transition-colors ${normalize(currentUser.role) === 'inspector' ? 'bg-emerald-50 border-emerald-100' : 'bg-white border-indigo-100'}`}>
                                        <span className={`text-[7px] font-black uppercase tracking-widest ${normalize(currentUser.role) === 'inspector' ? 'text-emerald-600' : 'text-indigo-400'}`}>
                                            {currentUser.role || 'Inspector'}
                                        </span>
                                    </div>
                                </div>
                            )}

                            <div className="px-4 py-2.5 bg-white border-b border-slate-50 shrink-0">
                                <div className="relative">
                                    <svg className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" strokeWidth="2.5" /></svg>
                                    <input 
                                        type="text" 
                                        placeholder="Search people..." 
                                        className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-100 rounded-xl text-[10px] font-medium outline-none focus:ring-2 focus:ring-indigo-50/50 transition-all"
                                        value={searchTerm}
                                        onChange={(e) => setSearchTerm(e.target.value)}
                                    />
                                </div>
                            </div>

                            <div className="flex-1 overflow-y-auto scrollbar-hide">
                                <div className="divide-y divide-slate-50">
                                    {isLoading && staff.length === 0 ? (
                                        <div className="py-16 text-center">
                                            <div className="w-6 h-6 border-2 border-slate-200 border-t-indigo-500 rounded-full animate-spin mx-auto mb-2"></div>
                                            <p className="text-[9px] font-bold text-slate-300 uppercase tracking-widest">Syncing Personnel...</p>
                                        </div>
                                    ) : sortedStaffList.length === 0 ? (
                                        <div className="py-16 text-center text-slate-300 italic text-[9px] uppercase tracking-widest font-bold">No results</div>
                                    ) : (
                                        sortedStaffList.map((member, i) => {
                                            const myId = normalize(currentUser?.username || '');
                                            const partnerId = normalize(member.username);

                                            const relevantMsgs = chatOnlyMessages.filter(m => {
                                                const senderId = normalize(m.senderId);
                                                const receiverId = normalize(m.receiverId);
                                                return (senderId === myId && receiverId === partnerId) || 
                                                       (senderId === partnerId && receiverId === myId);
                                            });

                                            const unreadMemberCount = chatOnlyMessages.filter(m => 
                                                normalize(m.senderId) === partnerId && normalize(m.receiverId) === myId && m.status === 'Sent'
                                            ).length;

                                            const lastMsg = relevantMsgs.length > 0 ? relevantMsgs[relevantMsgs.length - 1] : null;
                                            const online = isUserOnline(member);
                                            const isInspector = normalize(member.role) === 'inspector';

                                            return (
                                                <button key={i} onClick={() => { setSelectedStaff(member); setView('chat'); }} className={`w-full px-4 py-3 hover:bg-slate-50 transition-all flex items-center gap-3 group relative ${unreadMemberCount > 0 ? 'bg-indigo-50/20' : ''}`}>
                                                    <div className="relative shrink-0">
                                                        <div className={`w-9 h-9 rounded-xl border flex items-center justify-center transition-colors ${unreadMemberCount > 0 ? 'bg-indigo-100 border-indigo-200 text-indigo-700' : 'bg-slate-100 border-slate-200 text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-600'}`}>
                                                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2" /></svg>
                                                        </div>
                                                        <span className={`absolute -bottom-0.5 -right-0.5 w-2.5 h-2.5 border-2 border-white rounded-full ${online ? 'bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]' : 'bg-slate-300'}`}></span>
                                                    </div>
                                                    <div className="flex-1 text-left min-w-0">
                                                        <div className="flex justify-between items-center mb-0.5">
                                                            <div className="flex items-center gap-2 min-w-0">
                                                                <h4 className={`text-[10px] uppercase tracking-tight truncate ${unreadMemberCount > 0 ? 'font-black text-indigo-900' : 'font-bold text-slate-800'}`}>{member.name}</h4>
                                                                {isInspector && online && (
                                                                    <span className="bg-emerald-50 text-emerald-600 text-[6px] font-black px-1.5 py-0.5 rounded border border-emerald-100 uppercase tracking-widest shrink-0">Field Ops</span>
                                                                )}
                                                            </div>
                                                            {lastMsg && <span className="text-[7px] text-slate-300 font-bold shrink-0 ml-2">{new Date(lastMsg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>}
                                                        </div>
                                                        <p className={`text-[9px] truncate leading-tight flex items-center gap-1 ${unreadMemberCount > 0 ? 'text-indigo-600 font-bold' : 'text-slate-400 font-medium'}`}>
                                                            {member.isTyping && online ? <span className="text-indigo-500 font-bold animate-pulse italic">Typing...</span> : lastMsg ? cleanMessage(lastMsg.message) : <span className="italic opacity-50">No conversation history</span>}
                                                        </p>
                                                    </div>
                                                    {unreadMemberCount > 0 && (
                                                        <div className="shrink-0 flex items-center justify-center h-5 min-w-[20px] bg-indigo-600 text-white text-[8px] font-black rounded-full px-1.5 shadow-sm border border-white">
                                                            {unreadMemberCount}
                                                        </div>
                                                    )}
                                                </button>
                                            );
                                        })
                                    )}
                                </div>
                            </div>
                        </>
                    ) : (
                        <>
                            {/* Chat Header */}
                            <div className="p-3 bg-slate-50 border-b border-slate-100 flex items-center justify-between shrink-0">
                                <div className="flex items-center gap-2">
                                    <button onClick={() => { setView('list'); setSelectedStaff(null); }} className="p-1.5 hover:bg-white rounded-lg text-slate-400 transition-all">
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M15 19l-7-7 7-7" /></svg>
                                    </button>
                                    <div>
                                        <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest leading-none">
                                            {activeChatPartner ? activeChatPartner.name : 'Announcements'}
                                        </h4>
                                        <p className={`text-[7px] font-bold uppercase tracking-widest mt-1 flex items-center gap-1 ${
                                            activeChatPartner 
                                            ? (isUserOnline(activeChatPartner) ? 'text-emerald-500' : 'text-slate-400')
                                            : 'text-emerald-500'
                                        }`}>
                                            {activeChatPartner ? (
                                                <>
                                                    <span className={`w-1 h-1 rounded-full ${isUserOnline(activeChatPartner) ? 'bg-emerald-500 shadow-[0_0_3px_rgba(16,185,129,0.5)]' : 'bg-slate-300'}`}></span>
                                                    {isUserOnline(activeChatPartner) 
                                                        ? (activeChatPartner.isTyping ? 'Is typing...' : (normalize(activeChatPartner.role) === 'inspector' ? 'Field On-Duty' : 'Online')) 
                                                        : activeChatPartner.lastSeen 
                                                            ? `Last seen ${new Date(activeChatPartner.lastSeen).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}` 
                                                            : 'Offline'}
                                                </>
                                            ) : (
                                                <>
                                                    <span className="w-1 h-1 bg-emerald-500 rounded-full animate-pulse"></span> 
                                                    {typingUsers.length > 0 ? `${typingUsers.join(', ')} typing...` : 'System Broadcast Channel'}
                                                </>
                                            )}
                                        </p>
                                    </div>
                                </div>
                            </div>

                            {/* Chat Content */}
                            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/30 scrollbar-hide">
                                {filteredMessagesForView.length === 0 ? (
                                    <div className="h-full flex items-center justify-center flex-col opacity-30 select-none">
                                        <svg className="w-12 h-12 mb-2 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" strokeWidth="1.5" /></svg>
                                        <p className="text-[9px] font-black uppercase tracking-[0.2em]">Secure connection established</p>
                                    </div>
                                ) : filteredMessagesForView.map((msg, idx) => {
                                    const isMe = normalize(msg.senderId) === normalize(currentUser?.username);
                                    const isBroadcast = (msg.message || '').startsWith('[BROADCAST]:') || normalize(msg.receiverId) === 'all';

                                    return (
                                        <div key={msg.id || idx} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                                            {!isMe && (
                                                <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1 flex items-center gap-1.5">
                                                    {msg.senderName}
                                                    {isBroadcast && <span className="bg-indigo-50 text-indigo-500 px-1 rounded-[4px] text-[6px]">GLOBAL</span>}
                                                </span>
                                            )}
                                            <div className="flex items-end gap-1 group">
                                                {isMe && <MessageStatusIndicator status={msg.status} isMe={true} />}
                                                <div className={`max-w-[210px] p-3 text-[10.5px] leading-relaxed shadow-sm border ${
                                                    isMe 
                                                    ? 'bg-[#0f172a] text-white rounded-2xl rounded-tr-none border-[#0f172a]' 
                                                    : isBroadcast
                                                        ? 'bg-indigo-50 text-indigo-900 border-indigo-100 rounded-2xl rounded-tl-none'
                                                        : 'bg-white text-slate-700 border-slate-200 rounded-2xl rounded-tl-none'
                                                }`}>
                                                    {cleanMessage(msg.message)}
                                                </div>
                                            </div>
                                            <span className="text-[6px] text-slate-300 font-bold uppercase mt-1 px-1">
                                                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                            </span>
                                        </div>
                                    );
                                })}
                                <div ref={messagesEndRef} />
                            </div>

                            {/* Chat Input */}
                            <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(view === 'chat' && !selectedStaff); }} className="p-3 bg-white border-t border-slate-100 flex gap-2 shrink-0">
                                <input 
                                    type="text"
                                    value={input}
                                    onChange={(e) => setInput(e.target.value)}
                                    placeholder="Type a message..."
                                    className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 text-[11px] outline-none focus:ring-2 focus:ring-indigo-50/50 focus:bg-white transition-all font-medium"
                                />
                                <button type="submit" disabled={!input.trim() || isSending} className="w-10 h-10 bg-[#0f172a] text-white rounded-xl flex items-center justify-center hover:bg-black transition-all active:scale-90 disabled:bg-slate-200">
                                    {isSending ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>}
                                </button>
                            </form>
                        </>
                    )}
                </div>
            )}

            {/* Float Toggle */}
            <button 
                onClick={() => setIsOpen(!isOpen)}
                className={`group h-16 w-16 rounded-[1.8rem] shadow-[0_15px_40px_-10px_rgba(0,0,0,0.4)] flex items-center justify-center transition-all duration-500 relative border-t border-white/10
                    ${isOpen ? 'bg-[#4f46e5] rotate-180 rounded-full' : 'bg-[#0f172a] hover:bg-black hover:scale-110 active:scale-95'}
                `}
            >
                {isOpen ? (
                    <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg>
                ) : (
                    <div className="relative">
                        <svg className="w-8 h-8 text-white transition-transform group-hover:rotate-12 group-hover:scale-110" fill="currentColor" viewBox="0 0 24 24">
                            <path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" />
                        </svg>
                        {totalUnreadCount > 0 && (
                            <div className="absolute -top-3 -right-3 h-6 min-w-[24px] bg-[#ef4444] text-white text-[9px] font-black flex items-center justify-center rounded-full border-[3px] border-[#0f172a] px-1.5 shadow-xl animate-pulse">
                                {totalUnreadCount > 99 ? '99+' : totalUnreadCount}
                            </div>
                        )}
                    </div>
                )}
            </button>
        </div>
    );
};

