import { useState, useEffect, useCallback, useRef } from 'react';
import { User } from '../types';

// Professional Session Constraints - Extended for long-term persistence
const IDLE_TIMEOUT_MS = 30 * 24 * 60 * 60 * 1000; // 30 Days
const MAX_SESSION_MS = 30 * 24 * 60 * 60 * 1000; // 30 Days absolute max

export const useAuth = () => {
    // 1. Synchronous Initialization from LocalStorage to prevent logout on refresh
    const [currentUser, setCurrentUser] = useState<User | null>(() => {
        const savedUser = localStorage.getItem('safetyCheck_user');
        if (savedUser) {
            try {
                const u = JSON.parse(savedUser);
                // Normalize role case for consistency
                const rawRole = u.role ? String(u.role).trim().toLowerCase() : '';
                if (rawRole === 'admin') u.role = 'Admin';
                else if (rawRole === 'operations') u.role = 'Operations';
                else if (rawRole === 'maintenance') u.role = 'Maintenance';
                else if (rawRole === 'secretary') u.role = 'Secretary';
                else if (rawRole === 'other') u.role = 'Other';
                else if (rawRole === 'superadmin') u.role = 'SuperAdmin';
                else u.role = 'Inspector';

                // CRITICAL: Strict Onboarding Check
                u.needsSetup = !u.name || u.needsSetup === true;
                return u;
            } catch (e) {
                return null;
            }
        }
        return null;
    });

    const [sessionExpired, setSessionExpired] = useState<'idle' | 'max_duration' | null>(null);

    // Refs to track timers without re-renders, initialized from storage if available
    const lastActivityRef = useRef<number>(
        (() => {
            const saved = localStorage.getItem('safetyCheck_last_activity');
            return saved ? parseInt(saved, 10) : Date.now();
        })()
    );

    const sessionStartRef = useRef<number>(
        (() => {
            const saved = localStorage.getItem('safetyCheck_session_start');
            return saved ? parseInt(saved, 10) : Date.now();
        })()
    );

    const timerRef = useRef<number | null>(null);

    // 2. Lifecycle management for session listeners
    useEffect(() => {
        if (currentUser) {
            const savedSessionStart = localStorage.getItem('safetyCheck_session_start');

            // Check Absolute Session Expiry immediately on mount
            if (savedSessionStart) {
                const start = parseInt(savedSessionStart, 10);
                const elapsed = Date.now() - start;
                if (elapsed > MAX_SESSION_MS) {
                    handleLogout('max_duration');
                    return;
                }
                sessionStartRef.current = start;
            } else {
                localStorage.setItem('safetyCheck_session_start', Date.now().toString());
            }

            startActivityListeners();
        }

        return () => {
            stopActivityListeners();
        };
    }, [currentUser]);

    const updateActivity = useCallback(() => {
        if (!currentUser) return;
        const now = Date.now();
        // Throttled storage update (max once per second)
        if (now - lastActivityRef.current > 1000) {
            lastActivityRef.current = now;
            localStorage.setItem('safetyCheck_last_activity', now.toString());
        }
    }, [currentUser]);

    const startActivityListeners = () => {
        window.addEventListener('mousemove', updateActivity);
        window.addEventListener('keydown', updateActivity);
        window.addEventListener('touchstart', updateActivity);
        window.addEventListener('click', updateActivity);

        if (timerRef.current) window.clearInterval(timerRef.current);
        timerRef.current = window.setInterval(checkSessionStatus, 60000); // Check status every minute
    };

    const stopActivityListeners = () => {
        window.removeEventListener('mousemove', updateActivity);
        window.removeEventListener('keydown', updateActivity);
        window.removeEventListener('touchstart', updateActivity);
        window.removeEventListener('click', updateActivity);

        if (timerRef.current) {
            window.clearInterval(timerRef.current);
            timerRef.current = null;
        }
    };

    const checkSessionStatus = () => {
        const now = Date.now();

        // Restore from storage to sync across tabs if necessary
        const lastSaved = localStorage.getItem('safetyCheck_last_activity');
        const effectiveLastActivity = lastSaved ? parseInt(lastSaved, 10) : lastActivityRef.current;

        if (now - effectiveLastActivity > IDLE_TIMEOUT_MS) {
            handleLogout('idle');
            return;
        }
        if (now - sessionStartRef.current > MAX_SESSION_MS) {
            handleLogout('max_duration');
            return;
        }
    };

    const handleLogin = (user: User) => {
        const now = Date.now();
        // Recalculate needsSetup upon login
        const userToStore = {
            ...user,
            needsSetup: !user.name || user.needsSetup === true
        };

        setCurrentUser(userToStore);
        localStorage.setItem('safetyCheck_user', JSON.stringify(userToStore));
        localStorage.setItem('safetyCheck_session_start', now.toString());
        localStorage.setItem('safetyCheck_last_activity', now.toString());
        sessionStartRef.current = now;
        lastActivityRef.current = now;
        setSessionExpired(null);
        startActivityListeners();
    };

    const handleLogout = (reason?: 'idle' | 'max_duration') => {
        stopActivityListeners();
        setCurrentUser(null);
        if (reason) setSessionExpired(reason);

        const keysToRemove = [
            'safetyCheck_user',
            'safetyCheck_session_start',
            'safetyCheck_last_activity',
            'sc_validation_lists',
            'sc_remembered_creds'
        ];
        keysToRemove.forEach(k => localStorage.removeItem(k));
    };

    return { 
        currentUser, 
        setCurrentUser, 
        handleLogin, 
        handleLogout,
        sessionExpired,
        setSessionExpired
    };
};

import React from 'react';
import { SubscriptionDetails, User } from '../../types';

interface SubscriptionAlertProps {
    subscription: SubscriptionDetails | null;
    user: User | null;
    onManage: () => void;
}

const SubscriptionAlert: React.FC<SubscriptionAlertProps> = ({ subscription, user, onManage }) => {
    // If no user is logged in, don't show anything
    if (!user) return null;

    const isSuperAdmin = user.role === 'SuperAdmin';

    // --- BACKGROUND VALIDATION ---
    // If subscription is null, we are still fetching from the server.
    // Silent background validation - do not show a verifying bar.
    if (subscription === null) return null;

    // --- DETERMINING STATUS AFTER FETCH ---
    const isExpired = subscription.status === 'Expired' || !subscription.expiryDate || subscription.daysRemaining <= 0;
    const isNearExpiry = !isExpired && subscription.status === 'Active' && subscription.daysRemaining > 0 && subscription.daysRemaining <= 7;

    // If active and not near expiry, hide the bar completely
    if (!isExpired && !isNearExpiry) return null;

    return (
        <div className={`w-full px-4 py-3 flex items-center justify-between shadow-md relative z-[100] animate-fadeIn
            ${isExpired ? 'bg-red-600 text-white' : 'bg-amber-500 text-white'}
        `}>
            <div className="flex items-center gap-3">
                <div className="p-1.5 bg-white/20 rounded-full">
                    {isExpired ? (
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                    ) : (
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
                    )}
                </div>
                <div>
                    <p className="text-sm font-bold uppercase tracking-wide">
                        {isExpired ? 'SYSTEM LICENSE EXPIRED' : 'LICENSE EXPIRING SOON'}
                    </p>
                    <p className="text-xs font-medium opacity-90">
                        {isExpired 
                            ? 'Access to core features is restricted. Renew to restore modification access.'
                            : `${subscription?.daysRemaining} days remaining. Please renew soon.`
                        }
                    </p>
                </div>
            </div>

            {isSuperAdmin && (
                <button 
                    onClick={onManage}
                    className="px-4 py-2 bg-white text-gray-900 rounded-lg text-xs font-bold uppercase tracking-wider hover:bg-gray-100 transition-colors shadow-sm"
                >
                    Manage License
                </button>
            )}
        </div>
    );
};

export default SubscriptionAlert;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { User, ChatMessage } from '../../types';

interface ChatAssistantProps {
    currentUser: User | null;
    appScriptUrl: string;
}

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentUser, appScriptUrl }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [view, setView] = useState<'list' | 'chat'>('list');
    const [selectedStaff, setSelectedStaff] = useState<User | null>(null);
    const [input, setInput] = useState('');

    const [messages, setMessages] = useState<ChatMessage[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_messages');
        return cached ? JSON.parse(cached) : [];
    });

    const [staff, setStaff] = useState<User[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_staff');
        return cached ? JSON.parse(cached) : [];
    });

    const [searchTerm, setSearchTerm] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [isLoading, setIsLoading] = useState(false);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const lastFetchRef = useRef<number>(0);
    const heartbeatRef = useRef<number | null>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    // Online presence check
    const isUserOnline = (member: User) => {
        if (!member.lastSeen) return false;
        const diff = Date.now() - new Date(member.lastSeen).getTime();
        return diff < 45000;
    };

    // Role check for permissions
    const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';

    // Helper to normalize IDs for comparison
    const normalize = (id: string) => (id || '').toLowerCase().trim();

    // Filtered messages for current view (excluding heartbeats/status messages)
    // FIX: Optimized filter to check for "HB" message content
    const chatOnlyMessages = useMemo(() => {
        return messages.filter(m => 
            m.status !== 'Presence' && 
            m.status !== 'Typing' && 
            m.status !== 'HB' && 
            m.message !== 'HB'
        );
    }, [messages]);

    // Calculate total unique senders with unread personal messages for the main icon
    const totalUnreadCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        const unreadFromSenders = new Set(
            chatOnlyMessages
                .filter(m => normalize(m.receiverId) === myUid && m.status === 'Sent')
                .map(m => normalize(m.senderId))
        );
        return unreadFromSenders.size;
    }, [chatOnlyMessages, currentUser]);

    const filteredMessagesForView = useMemo(() => {
        if (!currentUser) return [];

        return chatOnlyMessages.filter(m => {
            const isBroadcast = (m.message || '').startsWith('[BROADCAST]:') || normalize(m.receiverId) === 'all';

            if (!selectedStaff) {
                return isBroadcast;
            } else {
                const myUid = normalize(currentUser.username);
                const partnerUid = normalize(selectedStaff.username);
                const senderUid = normalize(m.senderId);
                const receiverUid = normalize(m.receiverId);

                const isFromMeToThem = senderUid === myUid && receiverUid === partnerUid;
                const isFromThemToMe = senderUid === partnerUid && receiverUid === myUid;
                return isFromMeToThem || isFromThemToMe;
            }
        });
    }, [chatOnlyMessages, selectedStaff, currentUser]);

    const activeChatPartner = useMemo(() => {
        if (!selectedStaff) return null;
        return staff.find(s => normalize(s.username) === normalize(selectedStaff.username)) || selectedStaff;
    }, [selectedStaff, staff]);

    const markAsRead = async (sender: User) => {
        if (!appScriptUrl || !currentUser) return;
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'text/plain' },
                body: JSON.stringify({
                    action: 'mark_read',
                    username: currentUser.username,
                    senderId: sender.username
                }),
                mode: 'no-cors'
            });
            // Update local state immediately to remove badges
            setMessages(prev => prev.map(m => {
                if (normalize(m.senderId) === normalize(sender.username) && 
                    normalize(m.receiverId) === normalize(currentUser.username)) {
                    return { ...m, status: 'Read' };
                }
                return m;
            }));
        } catch (e) {}
    };

    const sendHeartbeat = async () => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'text/plain' },
                body: JSON.stringify({
                    action: 'heartbeat',
                    username: currentUser.username,
                    name: currentUser.name,
                    isTyping: input.trim().length > 0 && view === 'chat' && !!selectedStaff
                }),
                mode: 'no-cors'
            });
        } catch (e) {}
    };

    // Heartbeat Lifecycle
    // FIX: Reduced dependencies to prevent excessive server requests on every keystroke
    useEffect(() => {
        if (currentUser) {
            sendHeartbeat();
            heartbeatRef.current = window.setInterval(sendHeartbeat, 20000); // 20s interval
        }
        return () => {
            if (heartbeatRef.current) window.clearInterval(heartbeatRef.current);
        };
    }, [currentUser?.username]);

    useEffect(() => {
        if (isOpen && view === 'chat' && selectedStaff) {
            markAsRead(selectedStaff);
        }
    }, [isOpen, view, selectedStaff]);

    const fetchData = async (showLoading = false) => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;

        const now = Date.now();
        if (now - lastFetchRef.current < 3000) return; 
        lastFetchRef.current = now;

        if (showLoading && staff.length === 0) setIsLoading(true);

        try {
            const userResponse = await fetch(appScriptUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'text/plain' },
                body: JSON.stringify({ action: 'get_users' })
            });

            if (userResponse.ok) {
                const userData = await userResponse.json();
                if (userData.status === 'success' && Array.isArray(userData.users)) {
                    const filteredStaff = userData.users.filter((u: User) => normalize(u.username) !== normalize(currentUser.username));
                    setStaff(filteredStaff);
                    localStorage.setItem('sc_chat_cache_staff', JSON.stringify(filteredStaff));
                }
            }

            const msgResponse = await fetch(`${appScriptUrl}?t=${now}`);
            if (msgResponse.ok) {
                const json = await msgResponse.json();
                const chatData = json['Messages'];
                if (chatData && Array.isArray(chatData) && chatData.length > 1) {
                    const mappedMessages: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                        id: String(row[0]),
                        senderId: row[1],
                        senderName: row[2],
                        receiverId: row[3],
                        message: row[4] || '',
                        timestamp: row[5],
                        status: row[6] || 'Sent'
                    }));

                    setMessages(prev => {
                        const serverIds = new Set(mappedMessages.map(m => m.id));
                        const localOnly = prev.filter(p => normalize(p.senderId) === normalize(currentUser?.username) && !serverIds.has(p.id));
                        const combined = [...mappedMessages, ...localOnly];
                        const sorted = combined.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
                        localStorage.setItem('sc_chat_cache_messages', JSON.stringify(sorted));
                        return sorted;
                    });
                }
            }
        } catch (error) {
            console.warn("Chat sync skipped:", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchData(true);
        const interval = window.setInterval(() => fetchData(false), 8000);
        return () => window.clearInterval(interval);
    }, [appScriptUrl, currentUser?.username]);

    useEffect(() => {
        if (isOpen && view === 'chat') scrollToBottom();
    }, [filteredMessagesForView, isOpen, view]);

    const handleSendMessage = async (isGlobalAnnouncement = false) => {
        if (!input.trim() || isSending || !currentUser) return;

        // Final permission check for broadcast
        if (isGlobalAnnouncement && !isAdmin) return;

        const receiver = isGlobalAnnouncement ? 'ALL' : selectedStaff ? selectedStaff.username : 'ALL';
        const msgPrefix = isGlobalAnnouncement ? '[BROADCAST]: ' : '';
        const msgId = "M-" + Date.now();

        const optimisticMsg: ChatMessage = {
            id: msgId,
            senderId: currentUser.username,
            senderName: currentUser.name,
            receiverId: receiver,
            message: `${msgPrefix}${input.trim()}`,
            timestamp: new Date().toISOString(),
            status: 'Sent'
        };

        setInput('');
        setIsSending(true);

        setMessages(prev => [...prev, optimisticMsg]);

        const payload = {
            action: 'create',
            sheet: 'Messages',
            headers: ['ID', 'SenderID', 'SenderName', 'ReceiverID', 'Message', 'Timestamp', 'Status'],
            row: [optimisticMsg.id, optimisticMsg.senderId, optimisticMsg.senderName, optimisticMsg.receiverId, optimisticMsg.message, optimisticMsg.timestamp, optimisticMsg.status]
        };

        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'text/plain' },
                body: JSON.stringify(payload),
                mode: 'no-cors'
            });
            if (view === 'list') setView('chat');
        } catch (error) {
            console.error("Message delivery failed", error);
        } finally {
            setIsSending(false);
        }
    };

    const cleanMessage = (text: string) => {
        if (!text || typeof text !== 'string') return '';
        return text.replace(/^\[BROADCAST\]:\s*/, '');
    };

    const sortedStaffList = useMemo(() => {
        if (!currentUser) return [];
        const myId = normalize(currentUser.username);

        const baseFiltered = staff.filter(s => 
            s.name?.toLowerCase().includes(searchTerm.toLowerCase()) || 
            s.username?.toLowerCase().includes(searchTerm.toLowerCase())
        );

        return baseFiltered.sort((a, b) => {
            const partnerA = normalize(a.username);
            const partnerB = normalize(b.username);

            // 1. Calculate unread counts for sorting priority
            const unreadA = chatOnlyMessages.filter(m => normalize(m.senderId) === partnerA && normalize(m.receiverId) === myId && m.status === 'Sent').length;
            const unreadB = chatOnlyMessages.filter(m => normalize(m.senderId) === partnerB && normalize(m.receiverId) === myId && m.status === 'Sent').length;

            if (unreadA > 0 && unreadB === 0) return -1;
            if (unreadB > 0 && unreadA === 0) return 1;

            // 2. Tie-breaker: latest message timestamp
            const latestA = chatOnlyMessages.filter(m => (normalize(m.senderId) === partnerA && normalize(m.receiverId) === myId) || (normalize(m.senderId) === myId && normalize(m.receiverId) === partnerA)).pop();
            const latestB = chatOnlyMessages.filter(m => (normalize(m.senderId) === partnerB && normalize(m.receiverId) === myId) || (normalize(m.senderId) === myId && normalize(m.receiverId) === partnerB)).pop();

            const timeA = latestA ? new Date(latestA.timestamp).getTime() : 0;
            const timeB = latestB ? new Date(latestB.timestamp).getTime() : 0;

            return timeB - timeA;
        });
    }, [staff, searchTerm, chatOnlyMessages, currentUser]);

    const typingUsers = useMemo(() => {
        return staff.filter(s => s.isTyping && isUserOnline(s)).map(s => s.name);
    }, [staff]);

    const MessageStatusIndicator = ({ status, isMe }: { status: string, isMe: boolean }) => {
        if (!isMe) return null;
        const isRead = status === 'Read';
        return (
            <div className="flex items-center ml-1 shrink-0">
                {isRead ? (
                    <svg className="w-3.5 h-3.5 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M0.41 13.41L6 19L7.41 17.58L1.83 12M22.24 5.58L11.66 16.17L7.5 12L6.07 13.41L11.66 19L23.66 7M18 7L16.59 5.58L10.24 11.93L11.66 13.34L18 7Z"/></svg>
                ) : (
                    <svg className="w-3.5 h-3.5 text-slate-300" fill="currentColor" viewBox="0 0 24 24"><path d="M21,7L9,19L3.5,13.5L4.91,12.09L9,16.17L19.59,5.59L21,7Z"/></svg>
                )}
            </div>
        );
    };

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end font-sans">
            {isOpen && (
                <div className="mb-4 w-[330px] sm:w-[350px] h-[440px] bg-white rounded-[2rem] shadow-[0_20px_60px_-15px_rgba(0,0,0,0.3)] border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">

                    {/* Main Header */}
                    <div className="bg-[#0f172a] p-4 flex justify-between items-center shrink-0">
