            const isBroadcast = (m.message || '').startsWith('[BROADCAST]:') || normalize(m.receiverId) === 'all';
            if (!selectedStaff) return isBroadcast;
            const senderUid = normalize(m.senderId);
            const receiverUid = normalize(m.receiverId);
            return (senderUid === myUid && receiverUid === partnerUid) || 
                   (senderUid === partnerUid && receiverUid === myUid);
        });

        // Capping view to latest 50 messages for DOM performance
        return relevant.slice(-MAX_MESSAGES_PER_CONVERSATION);
    }, [chatOnlyMessages, selectedStaff, currentUser]);

    const isUserOnline = (member: User) => {
        if (!member.lastSeen) return false;
        return Date.now() - new Date(member.lastSeen).getTime() < 45000;
    };

    // 2. High-Traffic Adaptive Polling
    const fetchData = async (showLoading = false) => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        const now = Date.now();
        if (now - lastFetchRef.current < 4000) return; // Hard throttle
        lastFetchRef.current = now;

        if (showLoading && staff.length === 0) setIsLoading(true);
        try {
            const [uResp, mResp] = await Promise.all([
                fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) }),
                fetch(`${appScriptUrl}?t=${now}`)
            ]);

            if (uResp.ok) {
                const uData = await uResp.json();
                if (uData.status === 'success') {
                    const filtered = uData.users.filter((u: User) => normalize(u.username) !== normalize(currentUser.username));
                    setStaff(filtered);
                    localStorage.setItem('sc_chat_cache_staff', JSON.stringify(filtered));
                }
            }

            if (mResp.ok) {
                const json = await mResp.json();
                const chatData = json['Messages'];
                if (Array.isArray(chatData) && chatData.length > 1) {
                    const mapped: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                        id: String(row[0]), senderId: row[1], senderName: row[2],
                        receiverId: row[3], message: row[4] || '', timestamp: row[5], status: row[6] || 'Sent'
                    }));
                    setMessages(mapped.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()));
                }
            }
        } catch (e) {} finally { setIsLoading(false); }
    };

    useEffect(() => {
        fetchData(true);
        if (pollTimerRef.current) window.clearInterval(pollTimerRef.current);
        const interval = isOpen ? ACTIVE_POLLING_MS : IDLE_POLLING_MS;
        pollTimerRef.current = window.setInterval(() => fetchData(false), interval);
        return () => { if (pollTimerRef.current) window.clearInterval(pollTimerRef.current); };
    }, [isOpen, appScriptUrl, currentUser?.username]);

    const handleSendMessage = async (isGlobalAnnouncement = false) => {
        if (!input.trim() || isSending || !currentUser) return;
        if (isGlobalAnnouncement && !isAdmin) return;

        setIsSending(true);
        const receiver = isGlobalAnnouncement ? 'ALL' : selectedStaff ? selectedStaff.username : 'ALL';
        const msgPrefix = isGlobalAnnouncement ? '[BROADCAST]: ' : '';
        const msgId = "M-" + Date.now();

        const payload = {
            action: 'create', sheet: 'Messages',
            headers: ['ID', 'SenderID', 'SenderName', 'ReceiverID', 'Message', 'Timestamp', 'Status'],
            row: [msgId, currentUser.username, currentUser.name, receiver, `${msgPrefix}${input.trim()}`, new Date().toISOString(), 'Sent']
        };

        try {
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload), mode: 'no-cors' });
            setInput('');
            fetchData(false);
        } finally { setIsSending(false); }
    };

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end font-sans">
            {isOpen && (
                <div className="mb-4 w-[330px] sm:w-[350px] h-[440px] bg-white rounded-[2rem] shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">
                    <div className="bg-[#0f172a] p-4 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 bg-[#4f46e5] rounded-xl flex items-center justify-center text-white shadow-lg"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg></div>
                            <h3 className="text-[10px] font-bold text-white tracking-widest uppercase">Safety Ops Chat</h3>
                        </div>
                        <div className="flex items-center gap-2">
                            {isAdmin && (
                                <button onClick={() => { setSelectedStaff(null); setView('chat'); setInput(''); }} className="bg-[#4f46e5] hover:bg-[#4338ca] text-white px-2 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all">Broadcast</button>
                            )}
                            <button onClick={() => setIsOpen(false)} className="p-1 text-slate-400 hover:text-white"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
                        </div>
                    </div>

                    {view === 'list' ? (
                        <>
                            {currentUser && (
                                <div className="px-4 py-3 bg-indigo-50/50 border-b border-indigo-100/50 flex items-center justify-between shrink-0">
                                    <div className="flex items-center gap-2">
                                        <div className="relative">
                                            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white text-[10px] font-black">{currentUser.name.substring(0, 2).toUpperCase()}</div>
                                            <span className="absolute -bottom-0.5 -right-0.5 w-2 h-2 bg-emerald-500 border-2 border-white rounded-full"></span>
                                        </div>
                                        <div>
                                            <p className="text-[9px] font-black text-indigo-900 uppercase tracking-tight leading-none">{currentUser.name} (Me)</p>
                                            <p className="text-[7px] font-bold text-emerald-600 uppercase tracking-widest flex items-center gap-1 mt-1">
                                                <span className="w-1 h-1 bg-emerald-500 rounded-full animate-pulse"></span>
                                                {isInspector ? 'Live on Inspection' : 'Online & Active'}
                                            </p>
                                        </div>
                                    </div>
                                    <div className={`px-2 py-1 border rounded shadow-sm ${isInspector ? 'bg-emerald-50 border-emerald-100' : 'bg-white border-slate-100'}`}>
                                        <span className={`text-[7px] font-black uppercase tracking-widest ${isInspector ? 'text-emerald-600' : 'text-slate-400'}`}>{currentUser.role}</span>
                                    </div>
                                </div>
                            )}

                            <div className="flex-1 overflow-y-auto scrollbar-hide bg-white">
                                <div className="divide-y divide-slate-50">
                                    {staff.map((member, i) => {
                                        const unread = chatOnlyMessages.filter(m => normalize(m.senderId) === normalize(member.username) && normalize(m.receiverId) === normalize(currentUser?.username || '') && m.status === 'Sent').length;
                                        const online = isUserOnline(member);
                                        const isStaffInspector = normalize(member.role) === 'inspector';
                                        return (
                                            <button key={i} onClick={() => { setSelectedStaff(member); setView('chat'); }} className={`w-full px-4 py-3 hover:bg-slate-50 transition-all flex items-center gap-3 relative ${unread > 0 ? 'bg-indigo-50/20' : ''}`}>
                                                <div className="relative shrink-0">
                                                    <div className={`w-9 h-9 rounded-xl border flex items-center justify-center ${unread > 0 ? 'bg-indigo-100 border-indigo-200 text-indigo-700' : 'bg-slate-50 border-slate-200 text-slate-400'}`}>
                                                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2" /></svg>
                                                    </div>
                                                    <span className={`absolute -bottom-0.5 -right-0.5 w-2 h-2 border-2 border-white rounded-full ${online ? 'bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]' : 'bg-slate-300'}`}></span>
