import React, { useState, useEffect, useMemo } from 'react';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// Services
import { analyzeInspection } from './services/geminiService';

// UI Components
import Toast from './components/ui/Toast';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import SystemTour from './components/ui/SystemTour'; 
import InstallPwaPrompt from './components/ui/InstallPwaPrompt';
import OnboardingWizard from './components/ui/OnboardingWizard'; 
import ChatAssistant from './components/ui/ChatAssistant';

// Layout Components
import AppHeader from './components/layout/AppHeader';
import AppContent from './components/layout/AppContent';
import AppModals from './components/layout/AppModals';
import AppFooter from './components/layout/AppFooter';

// Views
import LoginView from './views/LoginView';

// Main Application Logic
const App = () => {
  // Core Business Hooks
  const { currentUser, setCurrentUser, handleLogin, handleLogout, sessionExpired, setSessionExpired } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings, fetchSystemSettings } = useSettings();
  const { subscription, history: subHistory, refreshSubscription } = useSubscription(appScriptUrl, currentUser);

  // View Routing State
  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');

  // UI Interaction State
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [isSolutionsOpen, setIsSolutionsOpen] = useState(false);
  const [isRequestModalOpen, setIsRequestModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isStartModalOpen, setIsStartModalOpen] = useState(false);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info' | 'warning'} | null>(null);
  const [showTour, setShowTour] = useState(false);
  const [isCheckingMaint, setIsCheckingMaint] = useState(false);

  // Data Handlers State
  const [lastSubmittedData, setLastSubmittedData] = useState<InspectionData | null>(null);
  const [aiAnalysisResult, setAiAnalysisResult] = useState<string | null>(null);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);
  const [supportPrefill, setSupportPrefill] = useState<{subject: string, description: string} | null>(null);
  const [pendingModule, setPendingModule] = useState<string | null>(null);
  const [hasExistingDraft, setHasExistingDraft] = useState(false);

  // Core Data Fetching Hook
  const { historyList, isLoadingHistory, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule, currentUser);

  // Handlers
  const showToast = (message: string, type: 'success' | 'error' | 'info' | 'warning') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  const { submissionStatus, setSubmissionStatus, isSyncing, addToQueue } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));

  const lockInfo = useMemo(() => {
      const isSuperAdmin = currentUser?.role === 'SuperAdmin';
      const isSubExpired = subscription ? (subscription.status === 'Expired' || subscription.daysRemaining <= 0) : false;
      const isMaintActive = settings.maintenanceMode === true;
      if (isSuperAdmin) return { isLocked: false, reason: null as any };
      if (isMaintActive) return { isLocked: true, reason: 'maintenance' as const };
      if (isSubExpired) return { isLocked: true, reason: 'license' as const };
      return { isLocked: false, reason: null as any };
  }, [subscription, settings.maintenanceMode, currentUser?.role]);

  const isSystemLocked = lockInfo.isLocked;

  useEffect(() => {
    (window as any).isSubscriptionLocked = isSystemLocked;
  }, [isSystemLocked]);

  useEffect(() => {
    if (currentUser && !currentUser.needsSetup) {
        setActiveModule('overview');
        setViewMode('dashboard');
    }
  }, [currentUser?.username, currentUser?.needsSetup]);

  useEffect(() => {
      if (sessionExpired === 'idle') showToast("Session expired due to inactivity.", 'warning');
      else if (sessionExpired === 'max_duration') showToast("Session limit reached. Log in again.", 'info');
      if (sessionExpired) setSessionExpired(null);
  }, [sessionExpired]);

  const handleNavigate = async (module: string) => {
    if (module.startsWith('support:info:')) {
        const solutionName = module.replace('support:info:', '');
        setSupportPrefill({
            subject: `Inquiry: ${solutionName}`,
            description: `Automated Request: User is interested in learning more about integrating the "${solutionName}" module into the current fleet workflow.`
        });
        setActiveModule('support');
        setViewMode('dashboard');
        setIsSolutionsOpen(false);
        return;
    }

    if (module.startsWith('request:start_inspection')) {
        if (isSystemLocked) { showToast("System is in View-Only mode.", "error"); return; }
        const parts = module.split('|');
        const type = parts[1]?.toLowerCase();
        const truck = parts[2];
        const trailer = parts[3];
        const requester = parts[4];
        const reason = parts[5];
        let moduleKey = 'general';
        if (type === 'petroleum') moduleKey = 'petroleum';
        else if (type === 'petroleum_v2') moduleKey = 'petroleum_v2';
        else if (type === 'acid') moduleKey = 'acid';

        setActiveModule(moduleKey);
        startFreshInspection(moduleKey, {
            truckNo: truck,
            trailerNo: trailer,
            remarks: `Requested by ${requester}: ${reason}`,
            requestId: parts[0].split('-')[1]
        });
        return;
    }

    if (module !== 'support') setSupportPrefill(null);
    setActiveModule(module);
    setViewMode('dashboard');
  };

  const handleOpenInspectionFlow = (module: string) => {
    if (isSystemLocked) { showToast("System is currently in view-only mode.", "error"); return; }
    const draftKey = `sc_draft_${module}`;
    const draft = localStorage.getItem(draftKey);
    if (draft) {
        setPendingModule(module);
        setHasExistingDraft(true);
        setIsStartModalOpen(true);
    } else {
        startFreshInspection(module);
    }
  };

  const { notifications, handleMarkNotificationRead, handleDismissNotification, handleClearAllNotifications, handleGlobalAcknowledge } = useNotifications(appScriptUrl, currentUser, showToast);

  const startFreshInspection = (module: string, prefill?: Partial<InspectionData>) => {
      if (isSystemLocked) { showToast("Access Restricted: View-Only mode active.", "error"); return; }
      setLastSubmittedData(null);
      setAiAnalysisResult(null);
      setFormInitialData({ ...INITIAL_DATA, timestamp: new Date().toISOString(), inspectedBy: currentUser?.name || '', ...prefill });
      setViewMode('form');
  };

  const handleResumeDraft = () => {
    if (!pendingModule) return;
    const draftKey = `sc_draft_${pendingModule}`;
    const draftData = localStorage.getItem(draftKey);
    if (draftData) {
        setFormInitialData(JSON.parse(draftData));
        setActiveModule(pendingModule);
        setViewMode('form');
    }
    setIsStartModalOpen(false);
  };

  const handleDiscardAndStartNew = () => {
    if (!pendingModule) return;
    localStorage.removeItem(`sc_draft_${pendingModule}`);
    setActiveModule(pendingModule);
    startFreshInspection(pendingModule);
    setIsStartModalOpen(false);
  };

  const handleSaveDraft = (data: InspectionData) => {
    localStorage.setItem(`sc_draft_${activeModule}`, JSON.stringify(data));
    setViewMode('dashboard');
  };

  const handleExitForm = () => setViewMode('dashboard');

  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    if (isSystemLocked) { showToast("System is in View-Only mode. Submission blocked.", "error"); return; }
    if (!appScriptUrl) { showToast("Application URL not configured", "error"); return; }

    setSubmissionStatus('submitting');
    setLastSubmittedData(formData);
    setAiAnalysisResult(null);

    let sheetName = 'General', headers = SHEET_HEADERS, moduleTitle = "General Vehicle Inspection", activeItems = INSPECTION_ITEMS;
    if (activeModule === 'petroleum') { 
        sheetName = 'Petroleum'; headers = PETROLEUM_HEADERS; moduleTitle = "Petroleum Tanker Inspection"; activeItems = PETROLEUM_INSPECTION_ITEMS;
    } else if (activeModule === 'petroleum_v2') { 
        sheetName = 'Petroleum_V2'; headers = PETROLEUM_V2_HEADERS; moduleTitle = "Petroleum Tanker Inspection V2"; activeItems = PETROLEUM_V2_ITEMS;
    } else if (activeModule === 'acid') { 
        sheetName = 'Acid'; headers = ACID_HEADERS; moduleTitle = "Acid Tanker Inspection"; activeItems = ACID_INSPECTION_ITEMS;
    }

    const row = headers.map(h => formData[h] !== undefined ? formData[h] : "");
    const reportData = {
        title: moduleTitle, timestamp: formData.timestamp, truckNo: formData.truckNo, trailerNo: formData.trailerNo, jobCard: formData.jobCard,
        location: formData.location, odometer: formData.odometer, inspectedBy: formData.inspectedBy, driverName: formData.driverName,
        remarks: formData.remarks, rate: formData.rate, safeToLoad: formData.safeToLoad, signatures: { inspector: formData.inspectorSignature, driver: formData.driverSignature },
        photos: { front: formData.photoFront, ls: formData.photoLS, rs: formData.photoRS, back: formData.photoBack, damage: formData.photoDamage },
        items: activeItems.map(item => ({ label: item.label, category: item.category, status: formData[item.id] || 'N/A' })),
        companyName: settings.companyName, companyLogo: settings.companyLogo
    };

    const payload = { action: 'create', sheet: sheetName, headers: headers, row: row, requestId: formData.requestId || null, reportData: reportData };
    if (!navigator.onLine) {
        addToQueue(payload); localStorage.removeItem(`sc_draft_${activeModule}`);
        setSubmissionStatus('offline_saved'); setTimeout(() => { setSubmissionStatus('idle'); setViewMode('dashboard'); }, 3500); return;
    }

    try {
        await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload), mode: 'no-cors' });
        setSubmissionStatus('success'); localStorage.removeItem(`sc_draft_${activeModule}`);
        try { const analysis = await analyzeInspection(formData); setAiAnalysisResult(analysis); } catch (aiErr) { setAiAnalysisResult("AI analysis currently unavailable."); }
        fetchHistory(true); 
    } catch (error) {
        addToQueue(payload); localStorage.removeItem(`sc_draft_${activeModule}`);
        setSubmissionStatus('offline_saved'); setTimeout(() => { setSubmissionStatus('idle'); setViewMode('dashboard'); }, 3500);
    }
  };

  const handleRequestSubmit = async (data: any) => {
      if (isSystemLocked) { showToast("Requests are disabled in View-Only mode.", "error"); return; }
      if (!appScriptUrl) return;
      try { await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'request_inspection', requester: currentUser?.name, role: currentUser?.role, ...data }), mode: 'no-cors' }); showToast("Inspection request submitted successfully", "success"); } catch (e) { showToast("Failed to submit request", "error"); }
  };

  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  const handleOnboardingComplete = (updatedUser: User) => {
      const userWithSetup = { ...updatedUser, needsSetup: false };
      setCurrentUser(userWithSetup);
      localStorage.setItem('safetyCheck_user', JSON.stringify(userWithSetup));
      setActiveModule('overview'); setViewMode('dashboard');
      showToast("Profile verified successfully.", "success"); setShowTour(true);
  };

  const handleCheckMaintStatus = async () => {
    setIsCheckingMaint(true);
    try { await fetchSystemSettings(appScriptUrl, true); showToast("Status updated.", "info"); } finally { setIsCheckingMaint(false); }
  };

  if (!currentUser) {
      return (
          <>
            <InstallPwaPrompt />
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
            <LoginView onLogin={handleLogin} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} settings={settings} />
          </>
      );
  }

  if (currentUser && currentUser.needsSetup) {
      return <OnboardingWizard user={currentUser} appScriptUrl={appScriptUrl} onComplete={handleOnboardingComplete} onLogout={handleLogout} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 relative">
      <SubmissionOverlay 
        status={submissionStatus} 
        onClose={() => { setSubmissionStatus('idle'); setViewMode('dashboard'); }}
        onViewReport={() => lastSubmittedData && handleViewReport(lastSubmittedData)}
        aiAnalysis={aiAnalysisResult}
      />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
      {showTour && <SystemTour onComplete={() => setShowTour(false)} />}

      <AppModals
        isProfileModalOpen={isProfileModalOpen} isSolutionsOpen={isSolutionsOpen} isRequestModalOpen={isRequestModalOpen}
        isStartModalOpen={isStartModalOpen} isReportModalOpen={isReportModalOpen} currentUser={currentUser}
        settings={settings} appScriptUrl={appScriptUrl} validationLists={validationLists} hasExistingDraft={hasExistingDraft}
        pendingModule={pendingModule} activeModule={activeModule} selectedReportData={selectedReportData}
        setIsProfileModalOpen={setIsProfileModalOpen} setIsSolutionsOpen={setIsSolutionsOpen}
        setIsRequestModalOpen={setIsRequestModalOpen} setIsStartModalOpen={setIsStartModalOpen}
        setIsReportModalOpen={setIsReportModalOpen} showToast={showToast} setCurrentUser={setCurrentUser}
        handleLogout={handleLogout} handleNavigate={handleNavigate} handleRequestSubmit={handleRequestSubmit}
        handleDiscardAndStartNew={handleDiscardAndStartNew} handleResumeDraft={handleResumeDraft}
      />

      <div className="relative z-10 min-h-screen flex flex-col">
          <AppHeader 
            settings={settings} currentUser={currentUser} activeModule={activeModule} isAdmin={currentUser.role === 'Admin' || currentUser.role === 'SuperAdmin'}
            isAtRoot={activeModule === 'overview'} isSystemLocked={isSystemLocked} lockReason={lockInfo.reason}
            subscription={subscription} notifications={notifications} isCheckingMaint={isCheckingMaint}
            onNavigateHome={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
            handleMarkNotificationRead={handleMarkNotificationRead} handleDismissNotification={handleDismissNotification}
            handleClearAllNotifications={handleClearAllNotifications} handleGlobalAcknowledge={handleGlobalAcknowledge}
            handleNavigate={handleNavigate} setIsProfileModalOpen={setIsProfileModalOpen}
            handleCheckMaintStatus={handleCheckMaintStatus} setActiveModule={setActiveModule}
          />

          <main className="flex-1 p-4 md:p-6 w-full max-w-7xl mx-auto no-print">
              <AppContent 
                viewMode={viewMode} activeModule={activeModule} currentUser={currentUser} settings={settings}
                appScriptUrl={appScriptUrl} historyList={historyList} isLoadingHistory={isLoadingHistory}
                validationLists={validationLists} stats={stats} notifications={notifications}
                isSystemLocked={isSystemLocked} lockReason={lockInfo.reason} formInitialData={formInitialData}
                submissionStatus={submissionStatus} supportPrefill={supportPrefill}
                subscription={subscription} subHistory={subHistory}
                handleOpenInspectionFlow={handleOpenInspectionFlow} handleSaveDraft={handleSaveDraft}
                handleExitForm={handleExitForm} handleGoogleSheetSubmit={handleGoogleSheetSubmit}
                handleViewReport={handleViewReport} handleNavigate={handleNavigate}
                handleSaveSettings={handleSaveSettings} isSavingSettings={isSavingSettings}
                setSettings={setSettings} setAppScriptUrl={setAppScriptUrl} showToast={showToast}
                refreshSubscription={refreshSubscription} fetchHistory={fetchHistory}
                setIsRequestModalOpen={setIsRequestModalOpen} setSupportPrefill={setSupportPrefill}
              />
          </main>

          {!isSystemLocked && viewMode === 'dashboard' && (
              <>
                  <ChatAssistant currentUser={currentUser} appScriptUrl={appScriptUrl} onNavigate={handleNavigate} />
                  <div className="fixed bottom-8 right-28 z-[100] no-print">
                      <button onClick={() => setIsSolutionsOpen(true)} className="w-14 h-14 bg-slate-900 text-white rounded-2xl shadow-xl flex items-center justify-center hover:bg-black hover:scale-110 transition-all group border-t border-white/5 relative">
                          <svg className="w-7 h-7 group-hover:rotate-12 transition-transform opacity-80" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                              <rect x="2" y="7" width="20" height="14" rx="2" ry="2" />
                              <path d="M16 21V5a2 2 0 00-2-2h-4a2 2 0 00-2 2v16" />
                          </svg>
                          <div className="absolute -top-1 -right-1 bg-indigo-600 text-white text-[7px] font-semibold px-1.5 py-0.5 rounded shadow-sm border border-indigo-500 uppercase tracking-widest">PRO</div>
                      </button>
                  </div>
              </>
          )}

          <AppFooter />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { User, ChatMessage } from '../../types';

interface ChatAssistantProps {
    currentUser: User | null;
    appScriptUrl: string;
    onNavigate?: (module: string) => void;
}

// Optimization Constants
const ACTIVE_POLLING_MS = 10000; // 10s when open
const IDLE_POLLING_MS = 60000;   // 1m when closed
const MAX_MESSAGES_PER_CONVERSATION = 50; 
const DAILY_LIMIT_PER_CONVERSATION = 30;

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentUser, appScriptUrl, onNavigate }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [view, setView] = useState<'list' | 'chat'>('list');
    const [selectedStaff, setSelectedStaff] = useState<User | null>(null);
    const [input, setInput] = useState('');

    const [messages, setMessages] = useState<ChatMessage[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_messages');
        return cached ? JSON.parse(cached) : [];
    });

    const [staff, setStaff] = useState<User[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_staff');
        return cached ? JSON.parse(cached) : [];
    });

    const [searchTerm, setSearchTerm] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [limitReached, setLimitReached] = useState(false);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const lastFetchRef = useRef<number>(0);
    const pollTimerRef = useRef<number | null>(null);

    const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
    const isInspector = currentUser?.role === 'Inspector';

    const normalize = (id: string) => (id || '').toLowerCase().trim();

    // 1. Professional Message Capping & Filtering
    const chatOnlyMessages = useMemo(() => {
        const filtered = messages.filter(m => 
            m.status !== 'Presence' && m.status !== 'Typing' && m.status !== 'HB' && m.message !== 'HB'
        );
        // Truncate for overall cache
        return filtered.slice(-200);
    }, [messages]);

    const filteredMessagesForView = useMemo(() => {
        if (!currentUser) return [];
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : null;

        const relevant = chatOnlyMessages.filter(m => {
            const isBroadcast = (m.message || '').startsWith('[BROADCAST]:') || normalize(m.receiverId) === 'all';
            if (!selectedStaff) return isBroadcast;
            const senderUid = normalize(m.senderId);
            const receiverUid = normalize(m.receiverId);
            return (senderUid === myUid && receiverUid === partnerUid) || 
                   (senderUid === partnerUid && receiverUid === myUid);
        });

        // Capping view to latest 50 messages for DOM performance
        return relevant.slice(-MAX_MESSAGES_PER_CONVERSATION);
    }, [chatOnlyMessages, selectedStaff, currentUser]);

    // Daily Limit Checker
    const sentTodayCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : 'ALL';
        const today = new Date().toISOString().split('T')[0];

        return chatOnlyMessages.filter(m => {
            const isToday = m.timestamp.startsWith(today);
            const isFromMe = normalize(m.senderId) === myUid;
            const isToPartner = normalize(m.receiverId) === partnerUid;
            return isToday && isFromMe && isToPartner;
        }).length;
    }, [chatOnlyMessages, currentUser, selectedStaff]);

    useEffect(() => {
        setLimitReached(sentTodayCount >= DAILY_LIMIT_PER_CONVERSATION);
    }, [sentTodayCount]);

    const totalUnreadCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        return new Set(
            chatOnlyMessages
                .filter(m => normalize(m.receiverId) === myUid && m.status === 'Sent')
                .map(m => normalize(m.senderId))
        ).size;
    }, [chatOnlyMessages, currentUser]);

    const isUserOnline = (member: User) => {
        if (!member.lastSeen) return false;
        return Date.now() - new Date(member.lastSeen).getTime() < 45000;
    };

    // 2. High-Traffic Adaptive Polling
    const fetchData = async (showLoading = false) => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        const now = Date.now();
        if (now - lastFetchRef.current < 4000) return; 
        lastFetchRef.current = now;

        if (showLoading && staff.length === 0) setIsLoading(true);
        try {
            const [uResp, mResp] = await Promise.all([
                fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) }),
                fetch(`${appScriptUrl}?t=${now}`)
            ]);

            if (uResp.ok) {
                const uData = await uResp.json();
                if (uData.status === 'success') {
                    const filtered = uData.users.filter((u: User) => normalize(u.username) !== normalize(currentUser.username));
                    setStaff(filtered);
                    localStorage.setItem('sc_chat_cache_staff', JSON.stringify(filtered));
                }
            }

            if (mResp.ok) {
                const json = await mResp.json();
                const chatData = json['Messages'];
                if (Array.isArray(chatData) && chatData.length > 1) {
                    const mapped: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                        id: String(row[0]), senderId: row[1], senderName: row[2],
                        receiverId: row[3], message: row[4] || '', timestamp: row[5], status: row[6] || 'Sent'
                    }));
                    setMessages(mapped.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()));
                    localStorage.setItem('sc_chat_cache_messages', JSON.stringify(mapped));
                }
            }
        } catch (e) {} finally { setIsLoading(false); }
    };

    useEffect(() => {
        fetchData(true);
        if (pollTimerRef.current) window.clearInterval(pollTimerRef.current);
        const interval = isOpen ? ACTIVE_POLLING_MS : IDLE_POLLING_MS;
        pollTimerRef.current = window.setInterval(() => fetchData(false), interval);
        return () => { if (pollTimerRef.current) window.clearInterval(pollTimerRef.current); };
    }, [isOpen, appScriptUrl, currentUser?.username]);

    const handleSendMessage = async (isGlobalAnnouncement = false) => {
        if (!input.trim() || isSending || !currentUser || limitReached) return;
        if (isGlobalAnnouncement && !isAdmin) return;

        setIsSending(true);
        const receiver = isGlobalAnnouncement ? 'ALL' : selectedStaff ? selectedStaff.username : 'ALL';
        const msgPrefix = isGlobalAnnouncement ? '[BROADCAST]: ' : '';
        const msgId = "M-" + Date.now();

        const payload = {
            action: 'create', sheet: 'Messages',
            headers: ['ID', 'SenderID', 'SenderName', 'ReceiverID', 'Message', 'Timestamp', 'Status'],
            row: [msgId, currentUser.username, currentUser.name, receiver, `${msgPrefix}${input.trim()}`, new Date().toISOString(), 'Sent']
        };

        try {
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload), mode: 'no-cors' });
            setInput('');
            fetchData(false);
        } finally { setIsSending(false); }
    };

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end font-sans">
            {isOpen && (
                <div className="mb-4 w-[330px] sm:w-[350px] h-[460px] bg-white rounded-[2rem] shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">
                    <div className="bg-[#0f172a] p-4 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 bg-[#4f46e5] rounded-xl flex items-center justify-center text-white shadow-lg"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg></div>
                            <h3 className="text-[10px] font-bold text-white tracking-widest uppercase">Operations Chat</h3>
                        </div>
                        <div className="flex items-center gap-1">
                            <button onClick={() => { setIsOpen(false); onNavigate?.('support'); }} className="bg-slate-800 hover:bg-slate-700 text-white px-2 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all border border-white/10">Support</button>
                            {isAdmin && (
                                <button onClick={() => { setSelectedStaff(null); setView('chat'); setInput(''); }} className="bg-[#4f46e5] hover:bg-[#4338ca] text-white px-2 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all">Broadcast</button>
                            )}
                            <button onClick={() => setIsOpen(false)} className="p-1 text-slate-400 hover:text-white"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
                        </div>
                    </div>

                    {view === 'list' ? (
                        <>
                            {currentUser && (
                                <div className="px-4 py-3 bg-indigo-50/50 border-b border-indigo-100/50 flex items-center justify-between shrink-0">
                                    <div className="flex items-center gap-2">
                                        <div className="relative">
                                            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white text-[10px] font-black">{currentUser.name.substring(0, 2).toUpperCase()}</div>
                                            <span className="absolute -bottom-0.5 -right-0.5 w-2 h-2 bg-emerald-500 border-2 border-white rounded-full"></span>
                                        </div>
                                        <div>
                                            <p className="text-[9px] font-black text-indigo-900 uppercase tracking-tight leading-none">{currentUser.name} (Me)</p>
                                            <p className="text-[7px] font-bold text-emerald-600 uppercase tracking-widest flex items-center gap-1 mt-1">
                                                <span className="w-1 h-1 bg-emerald-500 rounded-full animate-pulse"></span>
                                                {isInspector ? 'Live on Inspection' : 'Online & Active'}
                                            </p>
                                        </div>
                                    </div>
                                    <div className={`px-2 py-1 border rounded shadow-sm ${isInspector ? 'bg-emerald-50 border-emerald-100' : 'bg-white border-slate-100'}`}>
                                        <span className={`text-[7px] font-black uppercase tracking-widest ${isInspector ? 'text-emerald-600' : 'text-slate-400'}`}>{currentUser.role}</span>
                                    </div>
                                </div>
                            )}

                            <div className="flex-1 overflow-y-auto scrollbar-hide bg-white">
                                <div className="divide-y divide-slate-50">
                                    {staff.map((member, i) => {
                                        const unread = chatOnlyMessages.filter(m => normalize(m.senderId) === normalize(member.username) && normalize(m.receiverId) === normalize(currentUser?.username || '') && m.status === 'Sent').length;
                                        const online = isUserOnline(member);
                                        const isStaffInspector = normalize(member.role) === 'inspector';
                                        return (
                                            <button key={i} onClick={() => { setSelectedStaff(member); setView('chat'); }} className={`w-full px-4 py-3 hover:bg-slate-50 transition-all flex items-center gap-3 relative ${unread > 0 ? 'bg-indigo-50/20' : ''}`}>
                                                <div className="relative shrink-0">
                                                    <div className={`w-9 h-9 rounded-xl border flex items-center justify-center ${unread > 0 ? 'bg-indigo-100 border-indigo-200 text-indigo-700' : 'bg-slate-50 border-slate-200 text-slate-400'}`}>
                                                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2" /></svg>
                                                    </div>
                                                    <span className={`absolute -bottom-0.5 -right-0.5 w-2 h-2 border-2 border-white rounded-full ${online ? 'bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]' : 'bg-slate-300'}`}></span>
                                                </div>
                                                <div className="flex-1 text-left min-w-0">
                                                    <div className="flex items-center gap-2">
                                                        <h4 className={`text-[10px] uppercase tracking-tight truncate ${unread > 0 ? 'font-black text-indigo-900' : 'font-bold text-slate-800'}`}>{member.name}</h4>
                                                        {isStaffInspector && online && <span className="bg-emerald-50 text-emerald-600 text-[6px] font-black px-1.5 py-0.5 rounded border border-emerald-100 uppercase tracking-widest shrink-0">Field Ops</span>}
                                                    </div>
                                                    <p className="text-[9px] text-slate-400 font-medium truncate mt-0.5">{member.role} • {online ? 'Online' : 'Last seen ' + (member.lastSeen ? new Date(member.lastSeen).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : 'never')}</p>
                                                </div>
                                                {unread > 0 && <div className="h-5 min-w-[20px] bg-indigo-600 text-white text-[8px] font-black rounded-full px-1.5 flex items-center justify-center border border-white shadow-sm">{unread}</div>}
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>
                        </>
                    ) : (
                        <>
                            <div className="p-3 bg-slate-50 border-b border-slate-100 flex items-center justify-between shrink-0">
                                <div className="flex items-center gap-2 overflow-hidden">
                                    <button onClick={() => setView('list')} className="p-1 text-slate-400 hover:text-indigo-600 transition-colors shrink-0"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M15 19l-7-7 7-7" /></svg></button>
                                    <div className="min-w-0">
                                        <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest leading-none truncate">{selectedStaff ? selectedStaff.name : 'Announcements'}</h4>
                                        <p className="text-[7px] text-slate-400 font-bold uppercase tracking-widest mt-1">Daily Cap: {sentTodayCount}/{DAILY_LIMIT_PER_CONVERSATION}</p>
                                    </div>
                                </div>
                                <button onClick={() => { setIsOpen(false); onNavigate?.('support'); }} className="text-[7px] font-bold text-indigo-600 bg-indigo-50 px-2 py-1 rounded-md uppercase tracking-widest border border-indigo-100">Raise Ticket</button>
                            </div>

                            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/30 scrollbar-hide">
                                {filteredMessagesForView.map((msg, idx) => {
                                    const isMe = normalize(msg.senderId) === normalize(currentUser?.username);
                                    const isB = (msg.message || '').startsWith('[BROADCAST]:');
                                    return (
                                        <div key={idx} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                                            {!isMe && <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1">{msg.senderName}</span>}
                                            <div className={`max-w-[220px] p-3 text-[10px] font-medium leading-relaxed shadow-sm border ${isMe ? 'bg-[#0f172a] text-white rounded-2xl rounded-tr-none border-[#0f172a]' : isB ? 'bg-indigo-50 text-indigo-900 border-indigo-100 rounded-2xl rounded-tl-none' : 'bg-white text-slate-700 border-slate-200 rounded-2xl rounded-tl-none'}`}>
                                                {msg.message.replace('[BROADCAST]: ', '')}
                                            </div>
                                            <span className="text-[6px] text-slate-300 font-bold mt-1 px-1">{new Date(msg.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                        </div>
                                    );
                                })}
                                <div ref={messagesEndRef} />
                            </div>

                            <div className="px-3">
                                {limitReached && (
                                    <div className="bg-amber-50 border border-amber-100 rounded-lg p-2 mb-2">
                                        <p className="text-[9px] text-amber-700 font-bold uppercase tracking-tight leading-tight text-center">Daily limit of {DAILY_LIMIT_PER_CONVERSATION} messages reached for this thread.</p>
                                    </div>
                                )}
                                <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(view === 'chat' && !selectedStaff); }} className={`p-3 bg-white border-t border-slate-100 flex gap-2 shrink-0 ${limitReached ? 'opacity-50 pointer-events-none' : ''}`}>
                                    <input type="text" value={input} onChange={(e) => setInput(e.target.value)} disabled={limitReached} placeholder={limitReached ? "Daily limit reached" : "Type a message..."} className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2 text-[11px] outline-none focus:ring-2 focus:ring-indigo-100 transition-all font-medium" />
                                    <button type="submit" disabled={!input.trim() || isSending || limitReached} className="w-10 h-10 bg-[#0f172a] text-white rounded-xl flex items-center justify-center hover:bg-black transition-all active:scale-95 disabled:bg-slate-200">
                                        {isSending ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>}
                                    </button>
                                </form>
                            </div>
                        </>
                    )}
                </div>
            )}

            <button onClick={() => setIsOpen(!isOpen)} className={`h-14 w-14 rounded-2xl shadow-2xl flex items-center justify-center transition-all duration-500 relative border-t border-white/10 ${isOpen ? 'bg-[#4f46e5] rotate-180' : 'bg-[#0f172a] hover:scale-110 active:scale-95'}`}>
                {isOpen ? <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg> : (
                    <div className="relative"><svg className="w-7 h-7 text-white" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg>
                        {totalUnreadCount > 0 && <div className="absolute -top-3 -right-3 h-5 min-w-[20px] bg-[#ef4444] text-white text-[9px] font-black flex items-center justify-center rounded-full border-2 border-[#0f172a] px-1">{totalUnreadCount}</div>}
                    </div>
                )}
            </button>
        </div>
    );
};

export default ChatAssistant;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { User, ChatMessage } from '../../types';

interface ChatAssistantProps {
    currentUser: User | null;
    appScriptUrl: string;
    onNavigate?: (module: string) => void;
}

// Optimization Constants
const ACTIVE_POLLING_MS = 10000; 
const IDLE_POLLING_MS = 60000;   
const MAX_MESSAGES_PER_CONVERSATION = 50; 
const DAILY_LIMIT_PER_CONVERSATION = 30; // Strictly 30 messages per day

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentUser, appScriptUrl, onNavigate }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [view, setView] = useState<'list' | 'chat'>('list');
    const [selectedStaff, setSelectedStaff] = useState<User | null>(null);
    const [input, setInput] = useState('');

    const [messages, setMessages] = useState<ChatMessage[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_messages');
        return cached ? JSON.parse(cached) : [];
    });

    const [staff, setStaff] = useState<User[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_staff');
        return cached ? JSON.parse(cached) : [];
    });

    const [searchTerm, setSearchTerm] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [limitReached, setLimitReached] = useState(false);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const lastFetchRef = useRef<number>(0);
    const pollTimerRef = useRef<number | null>(null);

    const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
    const isInspector = currentUser?.role === 'Inspector';

    const normalize = (id: string) => (id || '').toLowerCase().trim();

    const chatOnlyMessages = useMemo(() => {
        return messages.filter(m => 
            m.status !== 'Presence' && m.status !== 'Typing' && m.status !== 'HB' && m.message !== 'HB'
        ).slice(-200);
    }, [messages]);

    // Intelligent Daily Limit Calculation
    const sentTodayCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : 'ALL';
        const today = new Date().toISOString().split('T')[0];

        return chatOnlyMessages.filter(m => {
            const isToday = m.timestamp.startsWith(today);
            const isFromMe = normalize(m.senderId) === myUid;
            const isToPartner = normalize(m.receiverId) === partnerUid;
            return isToday && isFromMe && isToPartner;
        }).length;
    }, [chatOnlyMessages, currentUser, selectedStaff]);

    useEffect(() => {
        setLimitReached(sentTodayCount >= DAILY_LIMIT_PER_CONVERSATION);
    }, [sentTodayCount]);

    const filteredMessagesForView = useMemo(() => {
        if (!currentUser) return [];
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : null;

        const relevant = chatOnlyMessages.filter(m => {
            const isBroadcast = (m.message || '').startsWith('[BROADCAST]:') || normalize(m.receiverId) === 'all';
            if (!selectedStaff) return isBroadcast;
            const senderUid = normalize(m.senderId);
            const receiverUid = normalize(m.receiverId);
            return (senderUid === myUid && receiverUid === partnerUid) || 
                   (senderUid === partnerUid && receiverUid === myUid);
        });

        return relevant.slice(-MAX_MESSAGES_PER_CONVERSATION);
    }, [chatOnlyMessages, selectedStaff, currentUser]);

    const totalUnreadCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        return new Set(
            chatOnlyMessages
                .filter(m => normalize(m.receiverId) === myUid && m.status === 'Sent')
                .map(m => normalize(m.senderId))
        ).size;
    }, [chatOnlyMessages, currentUser]);

    const isUserOnline = (member: User) => {
        if (!member.lastSeen) return false;
        return Date.now() - new Date(member.lastSeen).getTime() < 45000;
    };

    const fetchData = async (showLoading = false) => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        const now = Date.now();
        if (now - lastFetchRef.current < 4000) return; 
        lastFetchRef.current = now;

        if (showLoading && staff.length === 0) setIsLoading(true);
        try {
            const [uResp, mResp] = await Promise.all([
                fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) }),
                fetch(`${appScriptUrl}?t=${now}`)
            ]);

            if (uResp.ok) {
                const uData = await uResp.json();
                if (uData.status === 'success') {
                    const filtered = uData.users.filter((u: User) => normalize(u.username) !== normalize(currentUser.username));
                    setStaff(filtered);
                    localStorage.setItem('sc_chat_cache_staff', JSON.stringify(filtered));
                }
            }

            if (mResp.ok) {
                const json = await mResp.json();
                const chatData = json['Messages'];
                if (Array.isArray(chatData) && chatData.length > 1) {
                    const mapped: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                        id: String(row[0]), senderId: row[1], senderName: row[2],
                        receiverId: row[3], message: row[4] || '', timestamp: row[5], status: row[6] || 'Sent'
                    }));
                    const sorted = mapped.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
                    setMessages(sorted);
                    localStorage.setItem('sc_chat_cache_messages', JSON.stringify(sorted));
                }
            }
        } catch (e) {} finally { setIsLoading(false); }
    };

    useEffect(() => {
        fetchData(true);
        if (pollTimerRef.current) window.clearInterval(pollTimerRef.current);
        const interval = isOpen ? ACTIVE_POLLING_MS : IDLE_POLLING_MS;
        pollTimerRef.current = window.setInterval(() => fetchData(false), interval);
        return () => { if (pollTimerRef.current) window.clearInterval(pollTimerRef.current); };
    }, [isOpen, appScriptUrl, currentUser?.username]);

    const handleSendMessage = async (isGlobalAnnouncement = false) => {
        if (!input.trim() || isSending || !currentUser || limitReached) return;
        if (isGlobalAnnouncement && !isAdmin) return;

        setIsSending(true);
        const receiver = isGlobalAnnouncement ? 'ALL' : selectedStaff ? selectedStaff.username : 'ALL';
        const msgPrefix = isGlobalAnnouncement ? '[BROADCAST]: ' : '';
        const msgId = "M-" + Date.now();

        const payload = {
            action: 'create', sheet: 'Messages',
            headers: ['ID', 'SenderID', 'SenderName', 'ReceiverID', 'Message', 'Timestamp', 'Status'],
            row: [msgId, currentUser.username, currentUser.name, receiver, `${msgPrefix}${input.trim()}`, new Date().toISOString(), 'Sent']
        };

        try {
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload), mode: 'no-cors' });
            setInput('');
            fetchData(false);
        } finally { setIsSending(false); }
    };

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end font-sans">
            {isOpen && (
                <div className="mb-4 w-[330px] sm:w-[350px] h-[480px] bg-white rounded-[2rem] shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">
                    <div className="bg-[#0f172a] p-4 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 bg-[#4f46e5] rounded-xl flex items-center justify-center text-white shadow-lg"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg></div>
                            <h3 className="text-[10px] font-bold text-white tracking-widest uppercase">System Chat</h3>
                        </div>
                        <div className="flex items-center gap-1">
                            <button onClick={() => { setIsOpen(false); onNavigate?.('support'); }} className="bg-slate-800 hover:bg-slate-700 text-white px-2 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all border border-white/10">Support</button>
                            {isAdmin && (
                                <button onClick={() => { setSelectedStaff(null); setView('chat'); setInput(''); }} className="bg-[#4f46e5] hover:bg-[#4338ca] text-white px-2 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all">Broadcast</button>
                            )}
                            <button onClick={() => setIsOpen(false)} className="p-1 text-slate-400 hover:text-white"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
                        </div>
                    </div>

                    {view === 'list' ? (
                        <>
                            {currentUser && (
                                <div className="px-4 py-3 bg-indigo-50/50 border-b border-indigo-100/50 flex items-center justify-between shrink-0">
                                    <div className="flex items-center gap-2">
                                        <div className="relative">
                                            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white text-[10px] font-black">{currentUser.name.substring(0, 2).toUpperCase()}</div>
                                            <span className="absolute -bottom-0.5 -right-0.5 w-2 h-2 bg-emerald-500 border-2 border-white rounded-full"></span>
                                        </div>
                                        <div>
                                            <p className="text-[9px] font-black text-indigo-900 uppercase tracking-tight leading-none">{currentUser.name} (Me)</p>
                                            <p className="text-[7px] font-bold text-emerald-600 uppercase tracking-widest flex items-center gap-1 mt-1">
                                                <span className="w-1 h-1 bg-emerald-500 rounded-full animate-pulse"></span>
                                                {isInspector ? 'Live on Inspection' : 'Online & Active'}
                                            </p>
                                        </div>
                                    </div>
                                    <div className={`px-2 py-1 border rounded shadow-sm ${isInspector ? 'bg-emerald-50 border-emerald-100' : 'bg-white border-slate-100'}`}>
                                        <span className={`text-[7px] font-black uppercase tracking-widest ${isInspector ? 'text-emerald-600' : 'text-slate-400'}`}>{currentUser.role}</span>
                                    </div>
                                </div>
                            )}

                            <div className="flex-1 overflow-y-auto scrollbar-hide bg-white">
                                <div className="divide-y divide-slate-50">
                                    {staff.map((member, i) => {
                                        const unread = chatOnlyMessages.filter(m => normalize(m.senderId) === normalize(member.username) && normalize(m.receiverId) === normalize(currentUser?.username || '') && m.status === 'Sent').length;
                                        const online = isUserOnline(member);
                                        const isStaffInspector = normalize(member.role) === 'inspector';
                                        return (
                                            <button key={i} onClick={() => { setSelectedStaff(member); setView('chat'); }} className={`w-full px-4 py-3 hover:bg-slate-50 transition-all flex items-center gap-3 relative ${unread > 0 ? 'bg-indigo-50/20' : ''}`}>
                                                <div className="relative shrink-0">
                                                    <div className={`w-9 h-9 rounded-xl border flex items-center justify-center ${unread > 0 ? 'bg-indigo-100 border-indigo-200 text-indigo-700' : 'bg-slate-50 border-slate-200 text-slate-400'}`}>
                                                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2" /></svg>
                                                    </div>
                                                    <span className={`absolute -bottom-0.5 -right-0.5 w-2 h-2 border-2 border-white rounded-full ${online ? 'bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]' : 'bg-slate-300'}`}></span>
                                                </div>
                                                <div className="flex-1 text-left min-w-0">
                                                    <div className="flex items-center gap-2">
                                                        <h4 className={`text-[10px] uppercase tracking-tight truncate ${unread > 0 ? 'font-black text-indigo-900' : 'font-bold text-slate-800'}`}>{member.name}</h4>
                                                        {isStaffInspector && online && <span className="bg-emerald-50 text-emerald-600 text-[6px] font-black px-1.5 py-0.5 rounded border border-emerald-100 uppercase tracking-widest shrink-0">Field Ops</span>}
                                                    </div>
                                                    <p className="text-[9px] text-slate-400 font-medium truncate mt-0.5">{member.role} • {online ? 'Online' : 'Last seen ' + (member.lastSeen ? new Date(member.lastSeen).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : 'never')}</p>
                                                </div>
                                                {unread > 0 && <div className="h-5 min-w-[20px] bg-indigo-600 text-white text-[8px] font-black rounded-full px-1.5 flex items-center justify-center border border-white shadow-sm">{unread}</div>}
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>
                        </>
                    ) : (
                        <>
                            <div className="p-3 bg-slate-50 border-b border-slate-100 flex items-center justify-between shrink-0">
                                <div className="flex items-center gap-2 overflow-hidden">
                                    <button onClick={() => setView('list')} className="p-1 text-slate-400 hover:text-indigo-600 transition-colors shrink-0"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M15 19l-7-7 7-7" /></svg></button>
                                    <div className="min-w-0">
                                        <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest leading-none truncate">{selectedStaff ? selectedStaff.name : 'Announcements'}</h4>
                                        <p className="text-[7px] text-slate-400 font-bold uppercase tracking-widest mt-1">Daily Cap: {sentTodayCount}/{DAILY_LIMIT_PER_CONVERSATION}</p>
                                    </div>
                                </div>
                                <button onClick={() => { setIsOpen(false); onNavigate?.('support'); }} className="text-[7px] font-bold text-indigo-600 bg-indigo-50 px-2 py-1 rounded-md uppercase tracking-widest border border-indigo-100">Raise Ticket</button>
                            </div>

                            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/30 scrollbar-hide">
                                {filteredMessagesForView.map((msg, idx) => {
                                    const isMe = normalize(msg.senderId) === normalize(currentUser?.username);
                                    const isB = (msg.message || '').startsWith('[BROADCAST]:');
                                    return (
                                        <div key={idx} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                                            {!isMe && <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1">{msg.senderName}</span>}
                                            <div className={`max-w-[220px] p-3 text-[10px] font-medium leading-relaxed shadow-sm border ${isMe ? 'bg-[#0f172a] text-white rounded-2xl rounded-tr-none border-[#0f172a]' : isB ? 'bg-indigo-50 text-indigo-900 border-indigo-100 rounded-2xl rounded-tl-none' : 'bg-white text-slate-700 border-slate-200 rounded-2xl rounded-tl-none'}`}>
                                                {msg.message.replace('[BROADCAST]: ', '')}
                                            </div>
                                            <span className="text-[6px] text-slate-300 font-bold mt-1 px-1">{new Date(msg.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                        </div>
                                    );
                                })}
                                <div ref={messagesEndRef} />
                            </div>

                            <div className="px-3 bg-white border-t border-slate-100">
                                {limitReached && (
                                    <div className="bg-amber-50 border border-amber-100 rounded-xl p-3 my-2 animate-fadeIn">
                                        <div className="flex gap-2 items-center">
                                            <svg className="w-3 h-3 text-amber-600 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="3"/></svg>
                                            <p className="text-[9px] text-amber-700 font-black uppercase tracking-tight leading-tight">Daily transmission limit of {DAILY_LIMIT_PER_CONVERSATION} messages reached.</p>
                                        </div>
                                    </div>
                                )}
                                <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(view === 'chat' && !selectedStaff); }} className={`py-3 flex gap-2 shrink-0 ${limitReached ? 'opacity-40 grayscale pointer-events-none' : ''}`}>
                                    <input 
                                        type="text" 
                                        value={input} 
                                        onChange={(e) => setInput(e.target.value)} 
                                        disabled={limitReached}
                                        placeholder={limitReached ? "Daily limit reached" : "Type a message..."} 
                                        className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 text-[11px] outline-none focus:ring-2 focus:ring-indigo-100 transition-all font-medium" 
                                    />
                                    <button 
                                        type="submit" 
                                        disabled={!input.trim() || isSending || limitReached} 
                                        className="w-10 h-10 bg-[#0f172a] text-white rounded-xl flex items-center justify-center hover:bg-black transition-all active:scale-95 disabled:bg-slate-200"
                                    >
                                        {isSending ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>}
                                    </button>
                                </form>
                            </div>
                        </>
                    )}
                </div>
            )}

            <button onClick={() => setIsOpen(!isOpen)} className={`h-14 w-14 rounded-2xl shadow-2xl flex items-center justify-center transition-all duration-500 relative border-t border-white/10 ${isOpen ? 'bg-[#4f46e5] rotate-180' : 'bg-[#0f172a] hover:scale-110 active:scale-95'}`}>
                {isOpen ? <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg> : (
                    <div className="relative"><svg className="w-7 h-7 text-white" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg>
                        {totalUnreadCount > 0 && <div className="absolute -top-3 -right-3 h-5 min-w-[20px] bg-[#ef4444] text-white text-[9px] font-black flex items-center justify-center rounded-full border-2 border-[#0f172a] px-1">{totalUnreadCount}</div>}
                    </div>
                )}
            </button>
        </div>
    );
};

export default ChatAssistant;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { User, ChatMessage } from '../../types';

interface ChatAssistantProps {
    currentUser: User | null;
    appScriptUrl: string;
    onNavigate?: (module: string) => void;
}

// Optimization Constants
const ACTIVE_POLLING_MS = 10000; 
const IDLE_POLLING_MS = 60000;   
const MAX_MESSAGES_PER_CONVERSATION = 50; 
const DAILY_LIMIT_PER_CONVERSATION = 30; // Strictly 30 messages per day

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentUser, appScriptUrl, onNavigate }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [view, setView] = useState<'list' | 'chat'>('list');
    const [selectedStaff, setSelectedStaff] = useState<User | null>(null);
    const [input, setInput] = useState('');

    const [messages, setMessages] = useState<ChatMessage[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_messages');
        return cached ? JSON.parse(cached) : [];
    });

    const [staff, setStaff] = useState<User[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_staff');
        return cached ? JSON.parse(cached) : [];
    });

    const [isSending, setIsSending] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [limitReached, setLimitReached] = useState(false);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const lastFetchRef = useRef<number>(0);
    const pollTimerRef = useRef<number | null>(null);

    const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
    const isInspector = currentUser?.role === 'Inspector';

    const normalize = (id: string) => (id || '').toLowerCase().trim();

    const chatOnlyMessages = useMemo(() => {
        return messages.filter(m => 
            m.status !== 'Presence' && m.status !== 'Typing' && m.status !== 'HB' && m.message !== 'HB'
        ).slice(-200);
    }, [messages]);

    // Intelligent Daily Limit Calculation
    const sentTodayCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : 'ALL';
        const today = new Date().toISOString().split('T')[0];

        return chatOnlyMessages.filter(m => {
            const isToday = m.timestamp.startsWith(today);
            const isFromMe = normalize(m.senderId) === myUid;
            const isToPartner = normalize(m.receiverId) === partnerUid;
            return isToday && isFromMe && isToPartner;
        }).length;
    }, [chatOnlyMessages, currentUser, selectedStaff]);

    useEffect(() => {
        setLimitReached(sentTodayCount >= DAILY_LIMIT_PER_CONVERSATION);
    }, [sentTodayCount]);

    // UI Logic: When opening a chat, mark messages as read LOCALLY to clear notification badges immediately
    useEffect(() => {
        if (selectedStaff && view === 'chat' && currentUser) {
            const myUid = normalize(currentUser.username);
            const partnerUid = normalize(selectedStaff.username);

            const hasUnread = messages.some(m => 
                normalize(m.senderId) === partnerUid && 
                normalize(m.receiverId) === myUid && 
                m.status === 'Sent'
            );

            if (hasUnread) {
                const updated = messages.map(m => {
                    if (normalize(m.senderId) === partnerUid && normalize(m.receiverId) === myUid && m.status === 'Sent') {
                        return { ...m, status: 'Read' };
                    }
                    return m;
                });
                setMessages(updated);

                // Trigger server update in background
                fetch(appScriptUrl, { 
                    method: 'POST', 
                    body: JSON.stringify({ action: 'mark_read', username: myUid, senderId: partnerUid }),
                    mode: 'no-cors'
                }).catch(() => {});
            }
        }
    }, [selectedStaff, view]);

    const filteredMessagesForView = useMemo(() => {
        if (!currentUser) return [];
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : null;

        const relevant = chatOnlyMessages.filter(m => {
            const isBroadcast = (m.message || '').startsWith('[BROADCAST]:') || normalize(m.receiverId) === 'all';
            if (!selectedStaff) return isBroadcast;
            const senderUid = normalize(m.senderId);
            const receiverUid = normalize(m.receiverId);
            return (senderUid === myUid && receiverUid === partnerUid) || 
                   (senderUid === partnerUid && receiverUid === myUid);
        });

        return relevant.slice(-MAX_MESSAGES_PER_CONVERSATION);
    }, [chatOnlyMessages, selectedStaff, currentUser]);

    const totalUnreadCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        return new Set(
            chatOnlyMessages
                .filter(m => normalize(m.receiverId) === myUid && m.status === 'Sent')
                .map(m => normalize(m.senderId))
        ).size;
    }, [chatOnlyMessages, currentUser]);

    const isUserOnline = (member: User) => {
        if (!member.lastSeen) return false;
        return Date.now() - new Date(member.lastSeen).getTime() < 45000;
    };

    const fetchData = async (showLoading = false) => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        const now = Date.now();
        if (now - lastFetchRef.current < 4000) return; 
        lastFetchRef.current = now;

        if (showLoading && staff.length === 0) setIsLoading(true);
        try {
            const [uResp, mResp] = await Promise.all([
                fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) }),
                fetch(`${appScriptUrl}?t=${now}`)
            ]);

            if (uResp.ok) {
                const uData = await uResp.json();
                if (uData.status === 'success') {
                    const filtered = uData.users.filter((u: User) => normalize(u.username) !== normalize(currentUser.username));
                    setStaff(filtered);
                    localStorage.setItem('sc_chat_cache_staff', JSON.stringify(filtered));
                }
            }

            if (mResp.ok) {
                const json = await mResp.json();
                const chatData = json['Messages'];
                if (Array.isArray(chatData) && chatData.length > 1) {
                    const mapped: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                        id: String(row[0]), senderId: row[1], senderName: row[2],
                        receiverId: row[3], message: row[4] || '', timestamp: row[5], status: row[6] || 'Sent'
                    }));
                    const sorted = mapped.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
                    setMessages(sorted);
                    localStorage.setItem('sc_chat_cache_messages', JSON.stringify(sorted));
                }
            }
        } catch (e) {} finally { setIsLoading(false); }
    };

    useEffect(() => {
        fetchData(true);
        if (pollTimerRef.current) window.clearInterval(pollTimerRef.current);
        const interval = isOpen ? ACTIVE_POLLING_MS : IDLE_POLLING_MS;
        pollTimerRef.current = window.setInterval(() => fetchData(false), interval);
        return () => { if (pollTimerRef.current) window.clearInterval(pollTimerRef.current); };
    }, [isOpen, appScriptUrl, currentUser?.username]);

    const handleSendMessage = async (isGlobalAnnouncement = false) => {
        if (!input.trim() || isSending || !currentUser || limitReached) return;
        if (isGlobalAnnouncement && !isAdmin) return;

        setIsSending(true);
        const receiver = isGlobalAnnouncement ? 'ALL' : selectedStaff ? selectedStaff.username : 'ALL';
        const msgPrefix = isGlobalAnnouncement ? '[BROADCAST]: ' : '';
        const msgId = "M-" + Date.now();
        const msgText = `${msgPrefix}${input.trim()}`;
        const msgTs = new Date().toISOString();

        // Optimistic UI update: add message locally so it doesn't "disappear"
        const optimisticMsg: ChatMessage = {
            id: msgId,
            senderId: currentUser.username,
            senderName: currentUser.name,
            receiverId: receiver,
            message: msgText,
            timestamp: msgTs,
            status: 'Sending...'
        };

        setMessages(prev => [...prev, optimisticMsg]);
        const currentInput = input;
        setInput('');

        const payload = {
            action: 'create', sheet: 'Messages',
            headers: ['ID', 'SenderID', 'SenderName', 'ReceiverID', 'Message', 'Timestamp', 'Status'],
            row: [msgId, currentUser.username, currentUser.name, receiver, msgText, msgTs, 'Sent']
        };

        try {
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload), mode: 'no-cors' });
            // Update the status of our optimistic message
            setMessages(prev => prev.map(m => m.id === msgId ? { ...m, status: 'Sent' } : m));
            fetchData(false);
        } catch (e) {
            // Revert on failure
            setInput(currentInput);
            setMessages(prev => prev.filter(m => m.id !== msgId));
        } finally { setIsSending(false); }
    };

    useEffect(() => {
        if (messagesEndRef.current) {
            messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
        }
    }, [filteredMessagesForView]);

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end font-sans">
            {isOpen && (
                <div className="mb-4 w-[330px] sm:w-[350px] h-[480px] bg-white rounded-[2rem] shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">
                    <div className="bg-[#0f172a] p-4 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 bg-[#4f46e5] rounded-xl flex items-center justify-center text-white shadow-lg"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg></div>
                            <h3 className="text-[10px] font-bold text-white tracking-widest uppercase">System Chat</h3>
                        </div>
                        <div className="flex items-center gap-1">
                            <button onClick={() => { setIsOpen(false); onNavigate?.('support'); }} className="bg-slate-800 hover:bg-slate-700 text-white px-2 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all border border-white/10">Support</button>
                            {isAdmin && (
                                <button onClick={() => { setSelectedStaff(null); setView('chat'); setInput(''); }} className="bg-[#4f46e5] hover:bg-[#4338ca] text-white px-2 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all">Broadcast</button>
                            )}
                            <button onClick={() => setIsOpen(false)} className="p-1 text-slate-400 hover:text-white"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
                        </div>
                    </div>

                    {view === 'list' ? (
                        <>
                            {currentUser && (
                                <div className="px-4 py-3 bg-indigo-50/50 border-b border-indigo-100/50 flex items-center justify-between shrink-0">
                                    <div className="flex items-center gap-2">
                                        <div className="relative">
                                            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white text-[10px] font-black">{currentUser.name.substring(0, 2).toUpperCase()}</div>
                                            <span className="absolute -bottom-0.5 -right-0.5 w-2 h-2 bg-emerald-500 border-2 border-white rounded-full"></span>
                                        </div>
                                        <div>
                                            <p className="text-[9px] font-black text-indigo-900 uppercase tracking-tight leading-none">{currentUser.name} (Me)</p>
                                            <p className="text-[7px] font-bold text-emerald-600 uppercase tracking-widest flex items-center gap-1 mt-1">
                                                <span className="w-1 h-1 bg-emerald-500 rounded-full animate-pulse"></span>
                                                {isInspector ? 'Live on Inspection' : 'Online & Active'}
                                            </p>
                                        </div>
                                    </div>
                                    <div className={`px-2 py-1 border rounded shadow-sm ${isInspector ? 'bg-emerald-50 border-emerald-100' : 'bg-white border-slate-100'}`}>
                                        <span className={`text-[7px] font-black uppercase tracking-widest ${isInspector ? 'text-emerald-600' : 'text-slate-400'}`}>{currentUser.role}</span>
                                    </div>
                                </div>
                            )}

                            <div className="flex-1 overflow-y-auto scrollbar-hide bg-white">
                                <div className="divide-y divide-slate-50">
                                    {staff.map((member, i) => {
                                        const unread = chatOnlyMessages.filter(m => normalize(m.senderId) === normalize(member.username) && normalize(m.receiverId) === normalize(currentUser?.username || '') && m.status === 'Sent').length;
                                        const online = isUserOnline(member);
                                        const isStaffInspector = normalize(member.role) === 'inspector';
                                        return (
                                            <button key={i} onClick={() => { setSelectedStaff(member); setView('chat'); }} className={`w-full px-4 py-3 hover:bg-slate-50 transition-all flex items-center gap-3 relative ${unread > 0 ? 'bg-indigo-50/20' : ''}`}>
                                                <div className="relative shrink-0">
                                                    <div className={`w-9 h-9 rounded-xl border flex items-center justify-center ${unread > 0 ? 'bg-indigo-100 border-indigo-200 text-indigo-700' : 'bg-slate-50 border-slate-200 text-slate-400'}`}>
                                                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2" /></svg>
                                                    </div>
                                                    <span className={`absolute -bottom-0.5 -right-0.5 w-2 h-2 border-2 border-white rounded-full ${online ? 'bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]' : 'bg-slate-300'}`}></span>
                                                </div>
                                                <div className="flex-1 text-left min-w-0">
                                                    <div className="flex items-center gap-2">
                                                        <h4 className={`text-[10px] uppercase tracking-tight truncate ${unread > 0 ? 'font-black text-indigo-900' : 'font-bold text-slate-800'}`}>{member.name}</h4>
                                                        {isStaffInspector && online && <span className="bg-emerald-50 text-emerald-600 text-[6px] font-black px-1.5 py-0.5 rounded border border-emerald-100 uppercase tracking-widest shrink-0">Field Ops</span>}
                                                    </div>
                                                    <p className="text-[9px] text-slate-400 font-medium truncate mt-0.5">
                                                        {member.role} • {online ? (member.isTyping ? 'Typing...' : 'Online') : 'Last seen ' + (member.lastSeen ? new Date(member.lastSeen).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : 'never')}
                                                    </p>
                                                </div>
                                                {unread > 0 && <div className="h-5 min-w-[20px] bg-indigo-600 text-white text-[8px] font-black rounded-full px-1.5 flex items-center justify-center border border-white shadow-sm">{unread}</div>}
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>
                        </>
                    ) : (
                        <>
                            <div className="p-3 bg-slate-50 border-b border-slate-100 flex items-center justify-between shrink-0">
                                <div className="flex items-center gap-2 overflow-hidden">
                                    <button onClick={() => setView('list')} className="p-1 text-slate-400 hover:text-indigo-600 transition-colors shrink-0"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M15 19l-7-7 7-7" /></svg></button>
                                    <div className="min-w-0">
                                        <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest leading-none truncate">{selectedStaff ? selectedStaff.name : 'Announcements'}</h4>
                                        {selectedStaff && (
                                            <p className="text-[7px] text-slate-400 font-bold uppercase tracking-widest mt-1">
                                                {isUserOnline(selectedStaff) ? (selectedStaff.isTyping ? 'Typing...' : 'Online') : 'Offline'}
                                            </p>
                                        )}
                                    </div>
                                </div>
                                <div className="flex items-center gap-2">
                                    <div className="px-2 py-1 bg-white border border-slate-100 rounded-lg shadow-sm shrink-0">
                                        <p className="text-[7px] text-slate-400 font-bold uppercase tracking-widest">Cap: {sentTodayCount}/{DAILY_LIMIT_PER_CONVERSATION}</p>
                                    </div>
                                </div>
                            </div>

                            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/30 scrollbar-hide">
                                {filteredMessagesForView.map((msg, idx) => {
                                    const isMe = normalize(msg.senderId) === normalize(currentUser?.username);
                                    const isB = (msg.message || '').startsWith('[BROADCAST]:');
                                    return (
                                        <div key={idx} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                                            {!isMe && <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1">{msg.senderName}</span>}
                                            <div className={`max-w-[220px] p-3 text-[10px] font-medium leading-relaxed shadow-sm border ${isMe ? 'bg-[#0f172a] text-white rounded-2xl rounded-tr-none border-[#0f172a]' : isB ? 'bg-indigo-50 text-indigo-900 border-indigo-100 rounded-2xl rounded-tl-none' : 'bg-white text-slate-700 border-slate-200 rounded-2xl rounded-tl-none'}`}>
                                                {msg.message.replace('[BROADCAST]: ', '')}
                                            </div>
                                            <div className="flex items-center gap-1.5 mt-1 px-1">
                                                <span className="text-[6px] text-slate-300 font-bold">{new Date(msg.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                                {isMe && (
                                                    <span className={`text-[6px] font-black uppercase ${msg.status === 'Read' ? 'text-indigo-400' : 'text-slate-300'}`}>
                                                        {msg.status === 'Read' ? 'Seen' : 'Sent'}
                                                    </span>
                                                )}
                                            </div>
                                        </div>
                                    );
                                })}
                                <div ref={messagesEndRef} />
                            </div>

                            <div className="px-3 bg-white border-t border-slate-100">
                                {limitReached && (
                                    <div className="bg-amber-50 border border-amber-100 rounded-xl p-3 my-2 animate-fadeIn">
                                        <div className="flex gap-2 items-center">
                                            <svg className="w-3 h-3 text-amber-600 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="3"/></svg>
                                            <p className="text-[9px] text-amber-700 font-black uppercase tracking-tight leading-tight">Daily transmission limit of {DAILY_LIMIT_PER_CONVERSATION} messages reached.</p>
                                        </div>
                                    </div>
                                )}
                                <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(view === 'chat' && !selectedStaff); }} className={`py-3 flex gap-2 shrink-0 ${limitReached ? 'opacity-40 grayscale pointer-events-none' : ''}`}>
                                    <input 
                                        type="text" 
                                        value={input} 
                                        onChange={(e) => setInput(e.target.value)} 
                                        disabled={limitReached}
                                        placeholder={limitReached ? "Daily limit reached" : "Type a message..."} 
                                        className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 text-[11px] outline-none focus:ring-2 focus:ring-indigo-100 transition-all font-medium" 
                                    />
                                    <button 
                                        type="submit" 
                                        disabled={!input.trim() || isSending || limitReached} 
                                        className="w-10 h-10 bg-[#0f172a] text-white rounded-xl flex items-center justify-center hover:bg-black transition-all active:scale-95 disabled:bg-slate-200"
                                    >
                                        {isSending ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>}
                                    </button>
                                </form>
                            </div>
                        </>
                    )}
                </div>
            )}

            <button onClick={() => setIsOpen(!isOpen)} className={`h-14 w-14 rounded-2xl shadow-2xl flex items-center justify-center transition-all duration-500 relative border-t border-white/10 ${isOpen ? 'bg-[#4f46e5] rotate-180' : 'bg-[#0f172a] hover:scale-110 active:scale-95'}`}>
                {isOpen ? <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg> : (
                    <div className="relative"><svg className="w-7 h-7 text-white" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg>
                        {totalUnreadCount > 0 && <div className="absolute -top-3 -right-3 h-5 min-w-[20px] bg-[#ef4444] text-white text-[9px] font-black flex items-center justify-center rounded-full border-2 border-[#0f172a] px-1">{totalUnreadCount}</div>}
                    </div>
                )}
            </button>
        </div>
    );
};

export default ChatAssistant;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { User, ChatMessage } from '../../types';

interface ChatAssistantProps {
    currentUser: User | null;
    appScriptUrl: string;
    onNavigate?: (module: string) => void;
}

// Optimization Constants
const ACTIVE_POLLING_MS = 10000; 
const IDLE_POLLING_MS = 60000;   
const MAX_MESSAGES_PER_CONVERSATION = 50; 
const DAILY_LIMIT_PER_CONVERSATION = 30; // Strictly 30 messages per day

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentUser, appScriptUrl, onNavigate }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [view, setView] = useState<'list' | 'chat'>('list');
    const [selectedStaff, setSelectedStaff] = useState<User | null>(null);
    const [input, setInput] = useState('');

    const [messages, setMessages] = useState<ChatMessage[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_messages');
        return cached ? JSON.parse(cached) : [];
    });

    const [staff, setStaff] = useState<User[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_staff');
        return cached ? JSON.parse(cached) : [];
    });

    const [isSending, setIsSending] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [limitReached, setLimitReached] = useState(false);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const lastFetchRef = useRef<number>(0);
    const pollTimerRef = useRef<number | null>(null);

    const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
    const isInspector = currentUser?.role === 'Inspector';

    const normalize = (id: string) => (id || '').toLowerCase().trim();

    const chatOnlyMessages = useMemo(() => {
        return messages.filter(m => 
            m.status !== 'Presence' && m.status !== 'Typing' && m.status !== 'HB' && m.message !== 'HB'
        ).slice(-200);
    }, [messages]);

    // Sorted Staff based on conversation recency
    const sortedStaff = useMemo(() => {
        if (!currentUser) return staff;
        const myUid = normalize(currentUser.username);

        return [...staff].sort((a, b) => {
            const uidA = normalize(a.username);
            const uidB = normalize(b.username);

            const lastMsgA = [...chatOnlyMessages].reverse().find(m => 
                (normalize(m.senderId) === uidA && normalize(m.receiverId) === myUid) ||
                (normalize(m.senderId) === myUid && normalize(m.receiverId) === uidA)
            );

            const lastMsgB = [...chatOnlyMessages].reverse().find(m => 
                (normalize(m.senderId) === uidB && normalize(m.receiverId) === myUid) ||
                (normalize(m.senderId) === myUid && normalize(m.receiverId) === uidB)
            );

            const timeA = lastMsgA ? new Date(lastMsgA.timestamp).getTime() : 0;
            const timeB = lastMsgB ? new Date(lastMsgB.timestamp).getTime() : 0;

            return timeB - timeA;
        });
    }, [staff, chatOnlyMessages, currentUser]);

    // Intelligent Daily Limit Calculation
    const sentTodayCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : 'ALL';
        const today = new Date().toISOString().split('T')[0];

        return chatOnlyMessages.filter(m => {
            const isToday = m.timestamp.startsWith(today);
            const isFromMe = normalize(m.senderId) === myUid;
            const isToPartner = normalize(m.receiverId) === partnerUid;
            return isToday && isFromMe && isToPartner;
        }).length;
    }, [chatOnlyMessages, currentUser, selectedStaff]);

    useEffect(() => {
        setLimitReached(sentTodayCount >= DAILY_LIMIT_PER_CONVERSATION);
    }, [sentTodayCount]);

    // UI Logic: When opening a chat, mark messages as read LOCALLY to clear notification badges immediately
    useEffect(() => {
        if (selectedStaff && view === 'chat' && currentUser) {
            const myUid = normalize(currentUser.username);
            const partnerUid = normalize(selectedStaff.username);

            const hasUnread = messages.some(m => 
                normalize(m.senderId) === partnerUid && 
                normalize(m.receiverId) === myUid && 
                m.status === 'Sent'
            );

            if (hasUnread) {
                const updated = messages.map(m => {
                    if (normalize(m.senderId) === partnerUid && normalize(m.receiverId) === myUid && m.status === 'Sent') {
                        return { ...m, status: 'Read' };
                    }
                    return m;
                });
                setMessages(updated);

                // Trigger server update in background
                fetch(appScriptUrl, { 
                    method: 'POST', 
                    body: JSON.stringify({ action: 'mark_read', username: myUid, senderId: partnerUid }),
                    mode: 'no-cors'
                }).catch(() => {});
            }
        }
    }, [selectedStaff, view]);

    const filteredMessagesForView = useMemo(() => {
        if (!currentUser) return [];
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : null;

        const relevant = chatOnlyMessages.filter(m => {
            const isBroadcast = (m.message || '').startsWith('[BROADCAST]:') || normalize(m.receiverId) === 'all';
            if (!selectedStaff) return isBroadcast;
            const senderUid = normalize(m.senderId);
            const receiverUid = normalize(m.receiverId);
            return (senderUid === myUid && receiverUid === partnerUid) || 
                   (senderUid === partnerUid && receiverUid === myUid);
        });

        return relevant.slice(-MAX_MESSAGES_PER_CONVERSATION);
    }, [chatOnlyMessages, selectedStaff, currentUser]);

    const totalUnreadCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        return new Set(
            chatOnlyMessages
                .filter(m => normalize(m.receiverId) === myUid && m.status === 'Sent')
                .map(m => normalize(m.senderId))
        ).size;
    }, [chatOnlyMessages, currentUser]);

    const isUserOnline = (member: User) => {
        if (!member.lastSeen) return false;
        return Date.now() - new Date(member.lastSeen).getTime() < 45000;
    };

    const fetchData = async (showLoading = false) => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        const now = Date.now();
        if (now - lastFetchRef.current < 4000) return; 
        lastFetchRef.current = now;

        if (showLoading && staff.length === 0) setIsLoading(true);
        try {
            const [uResp, mResp] = await Promise.all([
                fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) }),
                fetch(`${appScriptUrl}?t=${now}`)
            ]);

            if (uResp.ok) {
                const uData = await uResp.json();
                if (uData.status === 'success') {
                    const filtered = uData.users.filter((u: User) => normalize(u.username) !== normalize(currentUser.username));
                    setStaff(filtered);
                    localStorage.setItem('sc_chat_cache_staff', JSON.stringify(filtered));
                }
            }

            if (mResp.ok) {
                const json = await mResp.json();
                const chatData = json['Messages'];
                if (Array.isArray(chatData) && chatData.length > 1) {
                    const mapped: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                        id: String(row[0]), senderId: row[1], senderName: row[2],
                        receiverId: row[3], message: row[4] || '', timestamp: row[5], status: row[6] || 'Sent'
                    }));
                    const sorted = mapped.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
                    setMessages(sorted);
                    localStorage.setItem('sc_chat_cache_messages', JSON.stringify(sorted));
                }
            }
        } catch (e) {} finally { setIsLoading(false); }
    };

    useEffect(() => {
        fetchData(true);
        if (pollTimerRef.current) window.clearInterval(pollTimerRef.current);
        const interval = isOpen ? ACTIVE_POLLING_MS : IDLE_POLLING_MS;
        pollTimerRef.current = window.setInterval(() => fetchData(false), interval);
        return () => { if (pollTimerRef.current) window.clearInterval(pollTimerRef.current); };
    }, [isOpen, appScriptUrl, currentUser?.username]);

    const handleSendMessage = async (isGlobalAnnouncement = false) => {
        if (!input.trim() || isSending || !currentUser || limitReached) return;
        if (isGlobalAnnouncement && !isAdmin) return;

        setIsSending(true);
        const receiver = isGlobalAnnouncement ? 'ALL' : selectedStaff ? selectedStaff.username : 'ALL';
        const msgPrefix = isGlobalAnnouncement ? '[BROADCAST]: ' : '';
        const msgId = "M-" + Date.now();
        const msgText = `${msgPrefix}${input.trim()}`;
        const msgTs = new Date().toISOString();

        // Optimistic UI update: add message locally so it doesn't "disappear"
        const optimisticMsg: ChatMessage = {
            id: msgId,
            senderId: currentUser.username,
            senderName: currentUser.name,
            receiverId: receiver,
            message: msgText,
            timestamp: msgTs,
            status: 'Sending...'
        };

        setMessages(prev => [...prev, optimisticMsg]);
        const currentInput = input;
        setInput('');

        const payload = {
            action: 'create', sheet: 'Messages',
            headers: ['ID', 'SenderID', 'SenderName', 'ReceiverID', 'Message', 'Timestamp', 'Status'],
            row: [msgId, currentUser.username, currentUser.name, receiver, msgText, msgTs, 'Sent']
        };

        try {
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload), mode: 'no-cors' });
            // Update the status of our optimistic message
            setMessages(prev => prev.map(m => m.id === msgId ? { ...m, status: 'Sent' } : m));
            fetchData(false);
        } catch (e) {
            // Revert on failure
            setInput(currentInput);
            setMessages(prev => prev.filter(m => m.id !== msgId));
        } finally { setIsSending(false); }
    };

    useEffect(() => {
        if (messagesEndRef.current) {
            messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
        }
    }, [filteredMessagesForView]);

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end font-sans">
            {isOpen && (
                <div className="mb-4 w-[330px] sm:w-[350px] h-[480px] bg-white rounded-[2rem] shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">
                    <div className="bg-[#0f172a] p-4 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 bg-[#4f46e5] rounded-xl flex items-center justify-center text-white shadow-lg"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg></div>
                            <h3 className="text-[10px] font-bold text-white tracking-widest uppercase">System Chat</h3>
                        </div>
                        <div className="flex items-center gap-1">
                            <button onClick={() => { setIsOpen(false); onNavigate?.('support'); }} className="bg-slate-800 hover:bg-slate-700 text-white px-2 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all border border-white/10">Support</button>
                            {isAdmin && (
                                <button onClick={() => { setSelectedStaff(null); setView('chat'); setInput(''); }} className="bg-[#4f46e5] hover:bg-[#4338ca] text-white px-2 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all">Broadcast</button>
                            )}
                            <button onClick={() => setIsOpen(false)} className="p-1 text-slate-400 hover:text-white"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
                        </div>
                    </div>

                    {view === 'list' ? (
                        <>
                            {currentUser && (
                                <div className="px-4 py-3 bg-indigo-50/50 border-b border-indigo-100/50 flex items-center justify-between shrink-0">
                                    <div className="flex items-center gap-2">
                                        <div className="relative">
                                            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white text-[10px] font-black">{currentUser.name.substring(0, 2).toUpperCase()}</div>
                                            <span className="absolute -bottom-0.5 -right-0.5 w-2 h-2 bg-emerald-500 border-2 border-white rounded-full"></span>
                                        </div>
                                        <div>
                                            <p className="text-[9px] font-black text-indigo-900 uppercase tracking-tight leading-none">{currentUser.name} (Me)</p>
                                            <p className="text-[7px] font-bold text-emerald-600 uppercase tracking-widest flex items-center gap-1 mt-1">
                                                <span className="w-1 h-1 bg-emerald-500 rounded-full animate-pulse"></span>
                                                {isInspector ? 'Live on Inspection' : 'Online & Active'}
                                            </p>
                                        </div>
                                    </div>
                                    <div className={`px-2 py-1 border rounded shadow-sm ${isInspector ? 'bg-emerald-50 border-emerald-100' : 'bg-white border-slate-100'}`}>
                                        <span className={`text-[7px] font-black uppercase tracking-widest ${isInspector ? 'text-emerald-600' : 'text-slate-400'}`}>{currentUser.role}</span>
                                    </div>
                                </div>
                            )}

                            <div className="flex-1 overflow-y-auto scrollbar-hide bg-white">
                                <div className="divide-y divide-slate-50">
                                    {sortedStaff.map((member, i) => {
                                        const unread = chatOnlyMessages.filter(m => normalize(m.senderId) === normalize(member.username) && normalize(m.receiverId) === normalize(currentUser?.username || '') && m.status === 'Sent').length;
                                        const online = isUserOnline(member);
                                        const isStaffInspector = normalize(member.role) === 'inspector';

                                        // Status string logic: hide "last seen" if user has never logged activity
                                        const lastSeenTime = member.lastSeen ? new Date(member.lastSeen).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : null;
                                        const statusText = online 
                                            ? (member.isTyping ? 'Typing...' : 'Online') 
                                            : (lastSeenTime ? 'Last seen ' + lastSeenTime : 'Offline');

                                        return (
                                            <button key={i} onClick={() => { setSelectedStaff(member); setView('chat'); }} className={`w-full px-4 py-3 hover:bg-slate-50 transition-all flex items-center gap-3 relative ${unread > 0 ? 'bg-indigo-50/20' : ''}`}>
                                                <div className="relative shrink-0">
                                                    <div className={`w-9 h-9 rounded-xl border flex items-center justify-center ${unread > 0 ? 'bg-indigo-100 border-indigo-200 text-indigo-700' : 'bg-slate-50 border-slate-200 text-slate-400'}`}>
                                                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2" /></svg>
                                                    </div>
                                                    <span className={`absolute -bottom-0.5 -right-0.5 w-2 h-2 border-2 border-white rounded-full ${online ? 'bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]' : 'bg-slate-300'}`}></span>
                                                </div>
                                                <div className="flex-1 text-left min-w-0">
                                                    <div className="flex items-center gap-2">
                                                        <h4 className={`text-[10px] uppercase tracking-tight truncate ${unread > 0 ? 'font-black text-indigo-900' : 'font-bold text-slate-800'}`}>{member.name}</h4>
                                                        {isStaffInspector && online && <span className="bg-emerald-50 text-emerald-600 text-[6px] font-black px-1.5 py-0.5 rounded border border-emerald-100 uppercase tracking-widest shrink-0">Field Ops</span>}
                                                    </div>
                                                    <p className="text-[9px] text-slate-400 font-medium truncate mt-0.5">
                                                        {member.role} • {statusText}
                                                    </p>
                                                </div>
                                                {unread > 0 && <div className="h-5 min-w-[20px] bg-indigo-600 text-white text-[8px] font-black rounded-full px-1.5 flex items-center justify-center border border-white shadow-sm">{unread}</div>}
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>
                        </>
                    ) : (
                        <>
                            <div className="p-3 bg-slate-50 border-b border-slate-100 flex items-center justify-between shrink-0">
                                <div className="flex items-center gap-2 overflow-hidden">
                                    <button onClick={() => setView('list')} className="p-1 text-slate-400 hover:text-indigo-600 transition-colors shrink-0"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M15 19l-7-7 7-7" /></svg></button>
                                    <div className="min-w-0">
                                        <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest leading-none truncate">{selectedStaff ? selectedStaff.name : 'Announcements'}</h4>
                                        {selectedStaff && (
                                            <p className="text-[7px] text-slate-400 font-bold uppercase tracking-widest mt-1">
                                                {isUserOnline(selectedStaff) ? (selectedStaff.isTyping ? 'Typing...' : 'Online') : 'Offline'}
                                            </p>
                                        )}
                                    </div>
                                </div>
                                <div className="flex items-center gap-2">
                                    <div className="px-2 py-1 bg-white border border-slate-100 rounded-lg shadow-sm shrink-0">
                                        <p className="text-[7px] text-slate-400 font-bold uppercase tracking-widest">Cap: {sentTodayCount}/{DAILY_LIMIT_PER_CONVERSATION}</p>
                                    </div>
                                </div>
                            </div>

                            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/30 scrollbar-hide">
                                {filteredMessagesForView.map((msg, idx) => {
                                    const isMe = normalize(msg.senderId) === normalize(currentUser?.username);
                                    const isB = (msg.message || '').startsWith('[BROADCAST]:');
                                    return (
                                        <div key={idx} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                                            {!isMe && <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1">{msg.senderName}</span>}
                                            <div className={`max-w-[220px] p-3 text-[10px] font-medium leading-relaxed shadow-sm border ${isMe ? 'bg-[#0f172a] text-white rounded-2xl rounded-tr-none border-[#0f172a]' : isB ? 'bg-indigo-50 text-indigo-900 border-indigo-100 rounded-2xl rounded-tl-none' : 'bg-white text-slate-700 border-slate-200 rounded-2xl rounded-tl-none'}`}>
                                                {msg.message.replace('[BROADCAST]: ', '')}
                                            </div>
                                            <div className="flex items-center gap-1.5 mt-1 px-1">
                                                <span className="text-[6px] text-slate-300 font-bold">{new Date(msg.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                                {isMe && (
                                                    <span className={`text-[6px] font-black uppercase ${msg.status === 'Read' ? 'text-indigo-400' : 'text-slate-300'}`}>
                                                        {msg.status === 'Read' ? 'Seen' : 'Sent'}
                                                    </span>
                                                )}
                                            </div>
                                        </div>
                                    );
                                })}
                                <div ref={messagesEndRef} />
                            </div>

                            <div className="px-3 bg-white border-t border-slate-100">
                                {limitReached && (
                                    <div className="bg-amber-50 border border-amber-100 rounded-xl p-3 my-2 animate-fadeIn">
                                        <div className="flex gap-2 items-center">
                                            <svg className="w-3 h-3 text-amber-600 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="3"/></svg>
                                            <p className="text-[9px] text-amber-700 font-black uppercase tracking-tight leading-tight">Daily transmission limit of {DAILY_LIMIT_PER_CONVERSATION} messages reached.</p>
                                        </div>
                                    </div>
                                )}
                                <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(view === 'chat' && !selectedStaff); }} className={`py-3 flex gap-2 shrink-0 ${limitReached ? 'opacity-40 grayscale pointer-events-none' : ''}`}>
                                    <input 
                                        type="text" 
                                        value={input} 
                                        onChange={(e) => setInput(e.target.value)} 
                                        disabled={limitReached}
                                        placeholder={limitReached ? "Daily limit reached" : "Type a message..."} 
                                        className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 text-[11px] outline-none focus:ring-2 focus:ring-indigo-100 transition-all font-medium" 
                                    />
                                    <button 
                                        type="submit" 
                                        disabled={!input.trim() || isSending || limitReached} 
                                        className="w-10 h-10 bg-[#0f172a] text-white rounded-xl flex items-center justify-center hover:bg-black transition-all active:scale-95 disabled:bg-slate-200"
                                    >
                                        {isSending ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>}
                                    </button>
                                </form>
                            </div>
                        </>
                    )}
                </div>
            )}

            <button onClick={() => setIsOpen(!isOpen)} className={`h-14 w-14 rounded-2xl shadow-2xl flex items-center justify-center transition-all duration-500 relative border-t border-white/10 ${isOpen ? 'bg-[#4f46e5] rotate-180' : 'bg-[#0f172a] hover:scale-110 active:scale-95'}`}>
                {isOpen ? <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg> : (
                    <div className="relative"><svg className="w-7 h-7 text-white" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg>
                        {totalUnreadCount > 0 && <div className="absolute -top-3 -right-3 h-5 min-w-[20px] bg-[#ef4444] text-white text-[9px] font-black flex items-center justify-center rounded-full border-2 border-[#0f172a] px-1">{totalUnreadCount}</div>}
                    </div>
                )}
            </button>
        </div>
    );
};

export default ChatAssistant;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { User, ChatMessage } from '../../types';

interface ChatAssistantProps {
    currentUser: User | null;
    appScriptUrl: string;
    onNavigate?: (module: string) => void;
}

// Optimization Constants
const ACTIVE_POLLING_MS = 6000;  // More frequent when open for "real-time" feel
const HEARTBEAT_INTERVAL_MS = 15000; 
const IDLE_POLLING_MS = 60000;   
const MAX_MESSAGES_PER_CONVERSATION = 50; 
const DAILY_LIMIT_PER_CONVERSATION = 30;

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentUser, appScriptUrl, onNavigate }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [view, setView] = useState<'list' | 'chat'>('list');
    const [selectedStaff, setSelectedStaff] = useState<User | null>(null);
    const [input, setInput] = useState('');

    // Core Data State
    const [messages, setMessages] = useState<ChatMessage[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_messages');
        return cached ? JSON.parse(cached) : [];
    });

    const [staff, setStaff] = useState<User[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_staff');
        return cached ? JSON.parse(cached) : [];
    });

    const [isSending, setIsSending] = useState(false);
    const [limitReached, setLimitReached] = useState(false);
    const [isTyping, setIsTyping] = useState(false);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const lastFetchRef = useRef<number>(0);
    const pollTimerRef = useRef<number | null>(null);
    const typingTimeoutRef = useRef<number | null>(null);

    const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
    const isInspector = currentUser?.role === 'Inspector';

    const normalize = (id: string) => (id || '').toLowerCase().trim();

    // 1. Message Aggregation logic
    const chatOnlyMessages = useMemo(() => {
        return messages.filter(m => 
            m.status !== 'Presence' && m.status !== 'Typing' && m.status !== 'HB' && m.message !== 'HB'
        );
    }, [messages]);

    // 2. Real-time Status Sorting
    const sortedStaff = useMemo(() => {
        if (!currentUser) return staff;
        const myUid = normalize(currentUser.username);

        return [...staff].sort((a, b) => {
            const uidA = normalize(a.username);
            const uidB = normalize(b.username);

            const lastMsgA = [...chatOnlyMessages].reverse().find(m => 
                (normalize(m.senderId) === uidA && normalize(m.receiverId) === myUid) ||
                (normalize(m.senderId) === myUid && normalize(m.receiverId) === uidA)
            );

            const lastMsgB = [...chatOnlyMessages].reverse().find(m => 
                (normalize(m.senderId) === uidB && normalize(m.receiverId) === myUid) ||
                (normalize(m.senderId) === myUid && normalize(m.receiverId) === uidB)
            );

            const timeA = lastMsgA ? new Date(lastMsgA.timestamp).getTime() : 0;
            const timeB = lastMsgB ? new Date(lastMsgB.timestamp).getTime() : 0;

            return timeB - timeA;
        });
    }, [staff, chatOnlyMessages, currentUser]);

    const sentTodayCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : 'ALL';
        const today = new Date().toISOString().split('T')[0];

        return chatOnlyMessages.filter(m => {
            const isToday = m.timestamp.startsWith(today);
            return isToday && normalize(m.senderId) === myUid && normalize(m.receiverId) === partnerUid;
        }).length;
    }, [chatOnlyMessages, currentUser, selectedStaff]);

    useEffect(() => {
        setLimitReached(sentTodayCount >= DAILY_LIMIT_PER_CONVERSATION);
    }, [sentTodayCount]);

    const filteredMessagesForView = useMemo(() => {
        if (!currentUser) return [];
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : null;

        const relevant = chatOnlyMessages.filter(m => {
            const isBroadcast = (m.message || '').startsWith('[BROADCAST]:') || normalize(m.receiverId) === 'all';
            if (!selectedStaff) return isBroadcast;
            const senderUid = normalize(m.senderId);
            const receiverUid = normalize(m.receiverId);
            return (senderUid === myUid && receiverUid === partnerUid) || 
                   (senderUid === partnerUid && receiverUid === myUid);
        });

        return relevant.slice(-MAX_MESSAGES_PER_CONVERSATION);
    }, [chatOnlyMessages, selectedStaff, currentUser]);

    const totalUnreadCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        return new Set(
            chatOnlyMessages
                .filter(m => normalize(m.receiverId) === myUid && m.status === 'Sent')
                .map(m => normalize(m.senderId))
        ).size;
    }, [chatOnlyMessages, currentUser]);

    const isUserOnline = (member: User) => {
        if (!member.lastSeen) return false;
        return Date.now() - new Date(member.lastSeen).getTime() < 45000;
    };

    // Heartbeat Function for Live Presence
    const sendHeartbeat = async () => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ 
                    action: 'heartbeat', 
                    username: currentUser.username, 
                    name: currentUser.name,
                    isTyping: isTyping 
                }),
                mode: 'no-cors'
            });
        } catch (e) {}
    };

    const fetchData = async () => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        const now = Date.now();
        if (now - lastFetchRef.current < 4000) return; 
        lastFetchRef.current = now;

        try {
            const [uResp, mResp] = await Promise.all([
                fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) }),
                fetch(`${appScriptUrl}?t=${now}`)
            ]);

            if (uResp.ok) {
                const uData = await uResp.json();
                if (uData.status === 'success') {
                    const filtered = uData.users.filter((u: User) => normalize(u.username) !== normalize(currentUser.username));
                    setStaff(filtered);
                    localStorage.setItem('sc_chat_cache_staff', JSON.stringify(filtered));
                }
            }

            if (mResp.ok) {
                const json = await mResp.json();
                const chatData = json['Messages'];
                if (Array.isArray(chatData) && chatData.length > 1) {
                    const serverMsgs: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                        id: String(row[0]), senderId: row[1], senderName: row[2],
                        receiverId: row[3], message: row[4] || '', timestamp: row[5], status: row[6] || 'Sent'
                    }));

                    setMessages(prev => {
                        // Merge server messages with local optimistic ones that haven't reached server yet
                        const serverIds = new Set(serverMsgs.map(m => m.id));
                        const localOnly = prev.filter(m => m.status === 'Sending' && !serverIds.has(m.id));
                        const combined = [...serverMsgs, ...localOnly].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
                        localStorage.setItem('sc_chat_cache_messages', JSON.stringify(combined));
                        return combined;
                    });
                }
            }
        } catch (e) {}
    };

    useEffect(() => {
        fetchData();
        if (pollTimerRef.current) window.clearInterval(pollTimerRef.current);
        const interval = isOpen ? ACTIVE_POLLING_MS : IDLE_POLLING_MS;
        pollTimerRef.current = window.setInterval(fetchData, interval);

        const hbTimer = window.setInterval(sendHeartbeat, HEARTBEAT_INTERVAL_MS);

        return () => { 
            if (pollTimerRef.current) window.clearInterval(pollTimerRef.current);
            window.clearInterval(hbTimer);
        };
    }, [isOpen, appScriptUrl, currentUser?.username]);

    const handleInputChange = (val: string) => {
        setInput(val);
        setIsTyping(true);
        if (typingTimeoutRef.current) window.clearTimeout(typingTimeoutRef.current);
        typingTimeoutRef.current = window.setTimeout(() => setIsTyping(false), 3000);
    };

    const handleSendMessage = async (isGlobalAnnouncement = false) => {
        if (!input.trim() || isSending || !currentUser || limitReached) return;
        if (isGlobalAnnouncement && !isAdmin) return;

        const msgText = input.trim();
        const receiver = isGlobalAnnouncement ? 'ALL' : selectedStaff ? selectedStaff.username : 'ALL';
        const msgPrefix = isGlobalAnnouncement ? '[BROADCAST]: ' : '';
        const msgId = "OPT-" + Date.now();
        const timestamp = new Date().toISOString();

        // 1. Optimistic UI Update (Instant appearance)
        const optimisticMsg: ChatMessage = {
            id: msgId,
            senderId: currentUser.username,
            senderName: currentUser.name,
            receiverId: receiver,
            message: `${msgPrefix}${msgText}`,
            timestamp: timestamp,
            status: 'Sending'
        };

        setMessages(prev => [...prev, optimisticMsg]);
        setInput('');
        setIsSending(true);

        const payload = {
            action: 'create', sheet: 'Messages',
            headers: ['ID', 'SenderID', 'SenderName', 'ReceiverID', 'Message', 'Timestamp', 'Status'],
            row: ["M-" + Date.now(), currentUser.username, currentUser.name, receiver, `${msgPrefix}${msgText}`, timestamp, 'Sent']
        };

        try {
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload), mode: 'no-cors' });
            // 2. Mark as Delivered (2 ticks) locally immediately after response
            setMessages(prev => prev.map(m => m.id === msgId ? { ...m, status: 'Sent' } : m));
            fetchData();
        } catch (e) {
            // Revert on real failure
            setMessages(prev => prev.filter(m => m.id !== msgId));
            setInput(msgText);
        } finally { 
            setIsSending(false); 
        }
    };

    // Component for Ticks
    const MessageTicks = ({ status }: { status: string }) => {
        if (status === 'Sending') return <div className="w-3 h-3 border border-slate-300 border-t-transparent rounded-full animate-spin ml-1" />;

        const isRead = status === 'Read';
        const isSent = status === 'Sent' || status === 'Read';

        return (
            <div className="flex items-center ml-1">
                {/* First Tick */}
                <svg className={`w-2.5 h-2.5 ${isRead ? 'text-indigo-400' : 'text-slate-400'}`} fill="none" stroke="currentColor" strokeWidth="3" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                </svg>
                {/* Second Tick (Only if Sent/Read - i.e. "Delivered" logic) */}
                {isSent && (
                    <svg className={`w-2.5 h-2.5 -ml-1 ${isRead ? 'text-indigo-400' : 'text-slate-400'}`} fill="none" stroke="currentColor" strokeWidth="3" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                    </svg>
                )}
            </div>
        );
    };

    useEffect(() => {
        if (messagesEndRef.current) messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }, [filteredMessagesForView]);

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end font-sans">
            {isOpen && (
                <div className="mb-4 w-[330px] sm:w-[350px] h-[480px] bg-white rounded-[2rem] shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">
                    <div className="bg-[#0f172a] p-4 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 bg-[#4f46e5] rounded-xl flex items-center justify-center text-white shadow-lg"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg></div>
                            <h3 className="text-[10px] font-bold text-white tracking-widest uppercase">System Chat</h3>
                        </div>
                        <div className="flex items-center gap-1">
                            <button onClick={() => { setIsOpen(false); onNavigate?.('support'); }} className="bg-slate-800 hover:bg-slate-700 text-white px-2 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider transition-all border border-white/10">Support</button>
                            {isAdmin && <button onClick={() => { setSelectedStaff(null); setView('chat'); }} className="bg-[#4f46e5] hover:bg-[#4338ca] text-white px-2 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider transition-all">Broadcast</button>}
                            <button onClick={() => setIsOpen(false)} className="p-1 text-slate-400 hover:text-white transition-colors"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
                        </div>
                    </div>

                    {view === 'list' ? (
                        <div className="flex-1 overflow-y-auto scrollbar-hide bg-white">
                            <div className="divide-y divide-slate-50">
                                {sortedStaff.map((member, i) => {
                                    const unread = chatOnlyMessages.filter(m => normalize(m.senderId) === normalize(member.username) && normalize(m.receiverId) === normalize(currentUser?.username || '') && m.status === 'Sent').length;
                                    const online = isUserOnline(member);
                                    const statusText = online ? (member.isTyping ? 'Typing...' : 'Online') : (member.lastSeen ? 'Last seen ' + new Date(member.lastSeen).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : 'Offline');
                                    return (
                                        <button key={i} onClick={() => { setSelectedStaff(member); setView('chat'); }} className={`w-full px-4 py-3 hover:bg-slate-50 transition-all flex items-center gap-3 relative ${unread > 0 ? 'bg-indigo-50/20' : ''}`}>
                                            <div className="relative shrink-0">
                                                <div className={`w-9 h-9 rounded-xl border flex items-center justify-center ${unread > 0 ? 'bg-indigo-100 border-indigo-200 text-indigo-700' : 'bg-slate-50 border-slate-200 text-slate-400'}`}><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2" /></svg></div>
                                                <span className={`absolute -bottom-0.5 -right-0.5 w-2.5 h-2.5 border-2 border-white rounded-full ${online ? 'bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]' : 'bg-slate-300'}`} />
                                            </div>
                                            <div className="flex-1 text-left min-w-0">
                                                <h4 className={`text-[10px] uppercase tracking-tight truncate ${unread > 0 ? 'font-black text-indigo-900' : 'font-bold text-slate-800'}`}>{member.name}</h4>
                                                <p className={`text-[9px] font-medium truncate mt-0.5 ${online ? 'text-emerald-600' : 'text-slate-400'}`}>{member.role} • {statusText}</p>
                                            </div>
                                            {unread > 0 && <div className="h-5 min-w-[20px] bg-indigo-600 text-white text-[8px] font-black rounded-full px-1.5 flex items-center justify-center border border-white shadow-sm">{unread}</div>}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    ) : (
                        <>
                            <div className="p-3 bg-slate-50 border-b border-slate-100 flex items-center justify-between shrink-0">
                                <div className="flex items-center gap-2 overflow-hidden">
                                    <button onClick={() => setView('list')} className="p-1 text-slate-400 hover:text-indigo-600 transition-colors shrink-0"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M15 19l-7-7 7-7" /></svg></button>
                                    <div className="min-w-0">
                                        <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest truncate">{selectedStaff ? selectedStaff.name : 'Announcements'}</h4>
                                        <p className="text-[7px] text-slate-400 font-bold uppercase tracking-widest mt-0.5">
                                            {selectedStaff ? (isUserOnline(selectedStaff) ? (selectedStaff.isTyping ? 'Typing...' : 'Online') : 'Offline') : 'Broadcast Channel'}
                                        </p>
                                    </div>
                                </div>
                                <div className="px-2 py-1 bg-white border border-slate-100 rounded-lg shadow-sm">
                                    <p className="text-[7px] text-slate-400 font-bold uppercase tracking-widest">Limit: {sentTodayCount}/{DAILY_LIMIT_PER_CONVERSATION}</p>
                                </div>
                            </div>

                            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/30 scrollbar-hide">
                                {filteredMessagesForView.map((msg, idx) => {
                                    const isMe = normalize(msg.senderId) === normalize(currentUser?.username);
                                    const isB = (msg.message || '').startsWith('[BROADCAST]:');
                                    return (
                                        <div key={idx} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                                            {!isMe && <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1">{msg.senderName}</span>}
                                            <div className={`max-w-[220px] p-3 text-[10px] font-medium leading-relaxed shadow-sm border ${isMe ? 'bg-[#0f172a] text-white rounded-2xl rounded-tr-none border-[#0f172a]' : isB ? 'bg-indigo-50 text-indigo-900 border-indigo-100 rounded-2xl rounded-tl-none' : 'bg-white text-slate-700 border-slate-200 rounded-2xl rounded-tl-none'}`}>
                                                {msg.message.replace('[BROADCAST]: ', '').replace('[CRITICAL ALERT]: ', '')}
                                            </div>
                                            <div className="flex items-center gap-1 mt-1 px-1">
                                                <span className="text-[6px] text-slate-300 font-bold">{new Date(msg.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                                {isMe && <MessageTicks status={msg.status} />}
                                            </div>
                                        </div>
                                    );
                                })}
                                <div ref={messagesEndRef} />
                            </div>

                            <div className="px-3 bg-white border-t border-slate-100">
                                {limitReached && (
                                    <div className="bg-amber-50 border border-amber-100 rounded-xl p-3 my-2 animate-fadeIn"><p className="text-[9px] text-amber-700 font-black uppercase tracking-tight leading-tight">Daily limit of {DAILY_LIMIT_PER_CONVERSATION} messages reached.</p></div>
                                )}
                                <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(view === 'chat' && !selectedStaff); }} className={`py-3 flex gap-2 shrink-0 ${limitReached ? 'opacity-40 grayscale pointer-events-none' : ''}`}>
                                    <input type="text" value={input} onChange={(e) => handleInputChange(e.target.value)} disabled={limitReached} placeholder={limitReached ? "Limit reached" : "Type a message..."} className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 text-[11px] outline-none focus:ring-2 focus:ring-indigo-100 transition-all font-medium" />
                                    <button type="submit" disabled={!input.trim() || isSending || limitReached} className="w-10 h-10 bg-[#0f172a] text-white rounded-xl flex items-center justify-center hover:bg-black transition-all active:scale-95 disabled:bg-slate-200">
                                        {isSending ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>}
                                    </button>
                                </form>
                            </div>
                        </>
                    )}
                </div>
            )}

            <button onClick={() => setIsOpen(!isOpen)} className={`h-14 w-14 rounded-2xl shadow-2xl flex items-center justify-center transition-all duration-500 relative border-t border-white/10 ${isOpen ? 'bg-[#4f46e5] rotate-180' : 'bg-[#0f172a] hover:scale-110 active:scale-95'}`}>
                {isOpen ? <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg> : (
                    <div className="relative"><svg className="w-7 h-7 text-white" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg>
                        {totalUnreadCount > 0 && <div className="absolute -top-3 -right-3 h-5 min-w-[20px] bg-[#ef4444] text-white text-[9px] font-black flex items-center justify-center rounded-full border-2 border-[#0f172a] px-1">{totalUnreadCount}</div>}
                    </div>
                )}
            </button>
        </div>
    );
};

export default ChatAssistant;

export const CODE_2_AUTH_AND_ADMIN = `/**
 * 2_AuthAndAdmin.gs
 * Handles authentication and staff management.
 */

const AuthHandlers = {
  handleLogin: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.error("Configuration Error: 'Users' sheet not found.");
    const data = userSheet.getDataRange().getValues();
    const username = body.username.toLowerCase();
    for (let i = 1; i < data.length; i++) {
        if (data[i][1].toLowerCase() === username && data[i][2] === body.password) {
            return ResponseBuilder.success({ 
              user: { 
                id: data[i][0], 
                username: data[i][1], 
                name: data[i][3], 
                role: data[i][4],
                position: data[i][5]
              } 
            });
        }
    }
    return ResponseBuilder.error("Invalid credentials.");
  },

  /**
   * Optimized Heartbeat: Updates a specific cell in the Users sheet 
   * instead of appending rows to the database.
   */
  handleHeartbeat: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.error("Users sheet missing");

    const data = userSheet.getDataRange().getValues();
    const username = body.username.toLowerCase();

    for (let i = 1; i < data.length; i++) {
      if (data[i][1].toLowerCase() === username) {
        // Column 7 is LastSeen, Column 10 (index 9) is Typing Status
        userSheet.getRange(i + 1, 7).setValue(new Date().toISOString());
        userSheet.getRange(i + 1, 10).setValue(body.isTyping ? "TRUE" : "FALSE");
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("User not found");
  },

  handleMarkRead: function(ss, body) {
    let msgSheet = ss.getSheetByName('Messages');
    if (!msgSheet) return ResponseBuilder.error("Messages sheet missing");
    const data = msgSheet.getDataRange().getValues();
    const myId = body.username.toLowerCase();
    const senderId = body.senderId.toLowerCase();

    let updated = false;
    for (let i = data.length - 1; i >= 1; i--) {
        if (String(data[i][3]).toLowerCase() === myId && 
            String(data[i][1]).toLowerCase() === senderId && 
            data[i][6] === 'Sent') {
            msgSheet.getRange(i + 1, 7).setValue('Read');
            updated = true;
        }
        if (i < data.length - 100) break; 
    }
    return ResponseBuilder.success({ updated });
  },

  handleRegisterUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.error("Database Error: 'Users' sheet missing.");
    const id = "USR-" + Date.now();
    // Headers: ID, Username, Password, Name, Role, Position, LastSeen, Preferences, IsActive, IsTyping
    sheet.appendRow([
      id, 
      body.username.toLowerCase(), 
      body.password, 
      body.name, 
      body.role, 
      body.position, 
      new Date().toISOString(), 
      JSON.stringify(body.preferences || {}), 
      "TRUE",
      "FALSE"
    ]);
    return ResponseBuilder.success();
  },

  handleGetUsers: function(ss) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.success({ users: [] });

    const userData = userSheet.getDataRange().getValues();
    const users = userData.slice(1).map(r => {
      return { 
        id: r[0],
        username: r[1], 
        name: r[3], 
        role: r[4], 
        position: r[5], 
        lastSeen: r[6],
        isActive: String(r[8]).toUpperCase() === "TRUE",
        isTyping: String(r[9]).toUpperCase() === "TRUE"
      };
    });

    return ResponseBuilder.success({ users });
  },

  handleDeleteUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.error("Database Error.");
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][1].toLowerCase() === body.username.toLowerCase()) {
        sheet.deleteRow(i + 1);
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("Target user not found.");
  },

  handleUpdateUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.error("Users sheet missing");
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][1].toLowerCase() === (body.originalUsername || body.username).toLowerCase()) {
        if (body.username) sheet.getRange(i + 1, 2).setValue(body.username);
        if (body.password) sheet.getRange(i + 1, 3).setValue(body.password);
        if (body.name) sheet.getRange(i + 1, 4).setValue(body.name);
        if (body.role) sheet.getRange(i + 1, 5).setValue(body.role);
        if (body.position) sheet.getRange(i + 1, 6).setValue(body.position);
        if (body.isActive !== undefined) sheet.getRange(i + 1, 9).setValue(body.isActive ? "TRUE" : "FALSE");
        if (body.preferences) sheet.getRange(i + 1, 8).setValue(JSON.stringify(body.preferences));
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("User not found");
  }
};`;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { User, ChatMessage } from '../../types';

interface ChatAssistantProps {
    currentUser: User | null;
    appScriptUrl: string;
    onNavigate?: (module: string) => void;
}

// Optimization Constants
const ACTIVE_POLLING_MS = 6000; 
const HEARTBEAT_INTERVAL_MS = 15000; 
const IDLE_POLLING_MS = 60000;   
const MAX_MESSAGES_PER_CONVERSATION = 50; 
const DAILY_LIMIT_PER_CONVERSATION = 30;

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentUser, appScriptUrl, onNavigate }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [view, setView] = useState<'list' | 'chat'>('list');
    const [selectedStaff, setSelectedStaff] = useState<User | null>(null);
    const [input, setInput] = useState('');

    // Core Data State
    const [messages, setMessages] = useState<ChatMessage[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_messages');
        return cached ? JSON.parse(cached) : [];
    });

    const [staff, setStaff] = useState<User[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_staff');
        return cached ? JSON.parse(cached) : [];
    });

    const [isSending, setIsSending] = useState(false);
    const [limitReached, setLimitReached] = useState(false);
    const [isTyping, setIsTyping] = useState(false);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const lastFetchRef = useRef<number>(0);
    const pollTimerRef = useRef<number | null>(null);
    const typingTimeoutRef = useRef<number | null>(null);

    const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
    const normalize = (id: string) => (id || '').toLowerCase().trim();

    // 1. Filter out HB messages and keep only chats
    const chatOnlyMessages = useMemo(() => {
        return messages.filter(m => 
            m.message !== 'HB' && m.status !== 'Presence' && m.status !== 'Typing'
        );
    }, [messages]);

    // 2. Real-time Status Sorting (Recency Based)
    const sortedStaff = useMemo(() => {
        if (!currentUser) return staff;
        const myUid = normalize(currentUser.username);

        return [...staff].sort((a, b) => {
            const uidA = normalize(a.username);
            const uidB = normalize(b.username);

            const lastMsgA = [...chatOnlyMessages].reverse().find(m => 
                (normalize(m.senderId) === uidA && normalize(m.receiverId) === myUid) ||
                (normalize(m.senderId) === myUid && normalize(m.receiverId) === uidA)
            );

            const lastMsgB = [...chatOnlyMessages].reverse().find(m => 
                (normalize(m.senderId) === uidB && normalize(m.receiverId) === myUid) ||
                (normalize(m.senderId) === myUid && normalize(m.receiverId) === uidB)
            );

            const timeA = lastMsgA ? new Date(lastMsgA.timestamp).getTime() : 0;
            const timeB = lastMsgB ? new Date(lastMsgB.timestamp).getTime() : 0;

            return timeB - timeA;
        });
    }, [staff, chatOnlyMessages, currentUser]);

    // Daily Limit Logic
    const sentTodayCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : 'ALL';
        const today = new Date().toISOString().split('T')[0];

        return chatOnlyMessages.filter(m => {
            const isToday = m.timestamp.startsWith(today);
            return isToday && normalize(m.senderId) === myUid && normalize(m.receiverId) === partnerUid;
        }).length;
    }, [chatOnlyMessages, currentUser, selectedStaff]);

    useEffect(() => {
        setLimitReached(sentTodayCount >= DAILY_LIMIT_PER_CONVERSATION);
    }, [sentTodayCount]);

    // Mark as Read Logic (Immediate local UI update)
    useEffect(() => {
        if (selectedStaff && view === 'chat' && currentUser) {
            const myUid = normalize(currentUser.username);
            const partnerUid = normalize(selectedStaff.username);

            const hasUnread = messages.some(m => 
                normalize(m.senderId) === partnerUid && 
                normalize(m.receiverId) === myUid && 
                m.status === 'Sent'
            );

            if (hasUnread) {
                setMessages(prev => prev.map(m => {
                    if (normalize(m.senderId) === partnerUid && normalize(m.receiverId) === myUid && m.status === 'Sent') {
                        return { ...m, status: 'Read' };
                    }
                    return m;
                }));

                fetch(appScriptUrl, { 
                    method: 'POST', 
                    body: JSON.stringify({ action: 'mark_read', username: myUid, senderId: partnerUid }),
                    mode: 'no-cors'
                }).catch(() => {});
            }
        }
    }, [selectedStaff, view]);

    const filteredMessagesForView = useMemo(() => {
        if (!currentUser) return [];
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : null;

        const relevant = chatOnlyMessages.filter(m => {
            const isBroadcast = (m.message || '').startsWith('[BROADCAST]:') || normalize(m.receiverId) === 'all' || normalize(m.receiverId) === 'all';
            if (!selectedStaff) return isBroadcast;
            const senderUid = normalize(m.senderId);
            const receiverUid = normalize(m.receiverId);
            return (senderUid === myUid && receiverUid === partnerUid) || 
                   (senderUid === partnerUid && receiverUid === myUid);
        });

        return relevant.slice(-MAX_MESSAGES_PER_CONVERSATION);
    }, [chatOnlyMessages, selectedStaff, currentUser]);

    const totalUnreadCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        return new Set(
            chatOnlyMessages
                .filter(m => normalize(m.receiverId) === myUid && m.status === 'Sent')
                .map(m => normalize(m.senderId))
        ).size;
    }, [chatOnlyMessages, currentUser]);

    const isUserOnline = (member: User) => {
        if (!member.lastSeen) return false;
        return Date.now() - new Date(member.lastSeen).getTime() < 45000;
    };

    // Professional Heartbeat: Updates Users sheet directly
    const sendHeartbeat = async () => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ 
                    action: 'heartbeat', 
                    username: currentUser.username, 
                    isTyping: isTyping 
                }),
                mode: 'no-cors'
            });
        } catch (e) {}
    };

    const fetchData = async () => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        const now = Date.now();
        if (now - lastFetchRef.current < 4000) return; 
        lastFetchRef.current = now;

        try {
            const [uResp, mResp] = await Promise.all([
                fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) }),
                fetch(`${appScriptUrl}?t=${now}`)
            ]);

            if (uResp.ok) {
                const uData = await uResp.json();
                if (uData.status === 'success') {
                    const filtered = uData.users.filter((u: User) => normalize(u.username) !== normalize(currentUser.username));
                    setStaff(filtered);
                    localStorage.setItem('sc_chat_cache_staff', JSON.stringify(filtered));
                }
            }

            if (mResp.ok) {
                const json = await mResp.json();
                const chatData = json['Messages'];
                if (Array.isArray(chatData) && chatData.length > 1) {
                    const serverMsgs: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                        id: String(row[0]), senderId: row[1], senderName: row[2],
                        receiverId: row[3], message: row[4] || '', timestamp: row[5], status: row[6] || 'Sent'
                    }));

                    setMessages(prev => {
                        const serverIds = new Set(serverMsgs.map(m => m.id));
                        // Retain local "Sending" messages that haven't appeared on server yet
                        const localOnly = prev.filter(m => m.status === 'Sending' && !serverIds.has(m.id));
                        const combined = [...serverMsgs, ...localOnly].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
                        localStorage.setItem('sc_chat_cache_messages', JSON.stringify(combined));
                        return combined;
                    });
                }
            }
        } catch (e) {}
    };

    useEffect(() => {
        fetchData();
        if (pollTimerRef.current) window.clearInterval(pollTimerRef.current);
        const interval = isOpen ? ACTIVE_POLLING_MS : IDLE_POLLING_MS;
        pollTimerRef.current = window.setInterval(fetchData, interval);
        const hbTimer = window.setInterval(sendHeartbeat, HEARTBEAT_INTERVAL_MS);
        return () => { 
            if (pollTimerRef.current) window.clearInterval(pollTimerRef.current);
            window.clearInterval(hbTimer);
        };
    }, [isOpen, appScriptUrl, currentUser?.username]);

    const handleInputChange = (val: string) => {
        setInput(val);
        if (!isTyping) {
            setIsTyping(true);
            sendHeartbeat(); // Trigger immediate typing status update
        }
        if (typingTimeoutRef.current) window.clearTimeout(typingTimeoutRef.current);
        typingTimeoutRef.current = window.setTimeout(() => setIsTyping(false), 3000);
    };

    const handleSendMessage = async (isGlobalAnnouncement = false) => {
        if (!input.trim() || isSending || !currentUser || limitReached) return;
        if (isGlobalAnnouncement && !isAdmin) return;

        const msgText = input.trim();
        const receiver = isGlobalAnnouncement ? 'ALL' : selectedStaff ? selectedStaff.username : 'ALL';
        const msgPrefix = isGlobalAnnouncement ? '[BROADCAST]: ' : '';
        const msgId = "LOCAL-" + Date.now();
        const timestamp = new Date().toISOString();

        // 1. Optimistic UI Update (Immediate)
        const optimisticMsg: ChatMessage = {
            id: msgId,
            senderId: currentUser.username,
            senderName: currentUser.name,
            receiverId: receiver,
            message: `${msgPrefix}${msgText}`,
            timestamp: timestamp,
            status: 'Sending'
        };

        setMessages(prev => [...prev, optimisticMsg]);
        const originalInput = input;
        setInput('');
        setIsSending(true);

        const payload = {
            action: 'create', sheet: 'Messages',
            headers: ['ID', 'SenderID', 'SenderName', 'ReceiverID', 'Message', 'Timestamp', 'Status'],
            row: ["M-" + Date.now(), currentUser.username, currentUser.name, receiver, `${msgPrefix}${msgText}`, timestamp, 'Sent']
        };

        try {
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload), mode: 'no-cors' });
            // 2. Mark as Delivered (2 ticks) locally
            setMessages(prev => prev.map(m => m.id === msgId ? { ...m, status: 'Sent' } : m));
            fetchData();
        } catch (e) {
            setMessages(prev => prev.filter(m => m.id !== msgId));
            setInput(originalInput);
        } finally { 
            setIsSending(false); 
        }
    };

    // Professional Tick Component
    const MessageTicks = ({ status }: { status: string }) => {
        if (status === 'Sending') return <div className="w-2.5 h-2.5 border border-slate-300 border-t-transparent rounded-full animate-spin ml-1" />;

        const isRead = status === 'Read';
        const isDelivered = status === 'Sent' || status === 'Read';

        return (
            <div className="flex items-center ml-1 shrink-0">
                {/* Tick 1 */}
                <svg className={`w-3 h-3 ${isRead ? 'text-indigo-400' : 'text-slate-300'}`} fill="none" stroke="currentColor" strokeWidth="3" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                </svg>
                {/* Tick 2 (Stacked for delivered/read) */}
                {isDelivered && (
                    <svg className={`w-3 h-3 -ml-1.5 ${isRead ? 'text-indigo-400' : 'text-slate-300'}`} fill="none" stroke="currentColor" strokeWidth="3" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                    </svg>
                )}
            </div>
        );
    };

    useEffect(() => {
        if (messagesEndRef.current) messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }, [filteredMessagesForView]);

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end font-sans">
            {isOpen && (
                <div className="mb-4 w-[330px] sm:w-[350px] h-[480px] bg-white rounded-[2rem] shadow-2xl border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">
                    {/* Header */}
                    <div className="bg-[#0f172a] p-4 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 bg-[#4f46e5] rounded-xl flex items-center justify-center text-white shadow-lg">
                                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg>
                            </div>
                            <h3 className="text-[10px] font-bold text-white tracking-widest uppercase">System Chat</h3>
                        </div>
                        <div className="flex items-center gap-1">
                            {isAdmin && <button onClick={() => { setSelectedStaff(null); setView('chat'); }} className="bg-[#4f46e5] hover:bg-[#4338ca] text-white px-2.5 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider transition-all">Broadcast</button>}
                            <button onClick={() => setIsOpen(false)} className="p-1 text-slate-400 hover:text-white transition-colors"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
                        </div>
                    </div>

                    {view === 'list' ? (
                        <div className="flex-1 overflow-y-auto scrollbar-hide bg-white">
                            <div className="divide-y divide-slate-50">
                                {sortedStaff.map((member, i) => {
                                    const unread = chatOnlyMessages.filter(m => normalize(m.senderId) === normalize(member.username) && normalize(m.receiverId) === normalize(currentUser?.username || '') && m.status === 'Sent').length;
                                    const online = isUserOnline(member);
                                    const statusText = online ? (member.isTyping ? 'Typing...' : 'Online') : (member.lastSeen ? 'Last seen ' + new Date(member.lastSeen).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}) : 'Offline');

                                    return (
                                        <button key={i} onClick={() => { setSelectedStaff(member); setView('chat'); }} className={`w-full px-5 py-4 hover:bg-slate-50 transition-all flex items-center gap-4 relative ${unread > 0 ? 'bg-indigo-50/20' : ''}`}>
                                            <div className="relative shrink-0">
                                                <div className={`w-10 h-10 rounded-xl border flex items-center justify-center transition-all ${unread > 0 ? 'bg-indigo-100 border-indigo-200 text-indigo-700' : 'bg-slate-50 border-slate-200 text-slate-400'}`}>
                                                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>
                                                </div>
                                                <span className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 border-2 border-white rounded-full transition-colors ${online ? 'bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]' : 'bg-slate-300'}`} />
                                            </div>
                                            <div className="flex-1 text-left min-w-0">
                                                <h4 className={`text-[11px] uppercase tracking-tight truncate ${unread > 0 ? 'font-black text-indigo-900' : 'font-bold text-slate-800'}`}>{member.name}</h4>
                                                <p className={`text-[9px] font-medium truncate mt-0.5 ${online ? 'text-emerald-600' : 'text-slate-400'}`}>{member.role} • {statusText}</p>
                                            </div>
                                            {unread > 0 && <div className="h-5 min-w-[20px] bg-indigo-600 text-white text-[8px] font-black rounded-full px-1.5 flex items-center justify-center border border-white shadow-sm">{unread}</div>}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    ) : (
                        <>
                            {/* Chat Header */}
                            <div className="p-3.5 bg-slate-50 border-b border-slate-100 flex items-center justify-between shrink-0">
                                <div className="flex items-center gap-3 overflow-hidden">
                                    <button onClick={() => setView('list')} className="p-1.5 text-slate-400 hover:text-indigo-600 transition-all rounded-lg hover:bg-white shrink-0"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M15 19l-7-7 7-7" /></svg></button>
                                    <div className="min-w-0">
                                        <h4 className="text-[11px] font-black text-slate-800 uppercase tracking-widest truncate">{selectedStaff ? selectedStaff.name : 'System Announcements'}</h4>
                                        <p className="text-[8px] font-bold uppercase tracking-widest mt-0.5">
                                            {selectedStaff ? (isUserOnline(selectedStaff) ? (selectedStaff.isTyping ? 'Typing...' : 'Live Now') : 'Status: Offline') : 'Public Broadcast Channel'}
                                        </p>
                                    </div>
                                </div>
                            </div>

                            {/* Message Area */}
                            <div className="flex-1 overflow-y-auto p-4 space-y-5 bg-slate-50/40 scrollbar-hide">
                                {filteredMessagesForView.map((msg, idx) => {
                                    const isMe = normalize(msg.senderId) === normalize(currentUser?.username);
                                    const isB = (msg.message || '').startsWith('[BROADCAST]:');
                                    return (
                                        <div key={msg.id || idx} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                                            {!isMe && <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1.5">{msg.senderName}</span>}
                                            <div className={`max-w-[80%] p-3.5 text-[11px] font-medium leading-relaxed shadow-sm border transition-all ${isMe ? 'bg-[#0f172a] text-white rounded-2xl rounded-tr-none border-[#0f172a]' : isB ? 'bg-indigo-50 text-indigo-900 border-indigo-100 rounded-2xl rounded-tl-none' : 'bg-white text-slate-700 border-slate-200 rounded-2xl rounded-tl-none'}`}>
                                                {msg.message.replace('[BROADCAST]: ', '').replace('[CRITICAL ALERT]: ', '')}
                                            </div>
                                            <div className="flex items-center gap-1.5 mt-1.5 px-1.5">
                                                <span className="text-[7px] text-slate-300 font-bold uppercase">{new Date(msg.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                                                {isMe && <MessageTicks status={msg.status} />}
                                            </div>
                                        </div>
                                    );
                                })}
                                <div ref={messagesEndRef} />
                            </div>

                            {/* Input Area */}
                            <div className="px-4 py-3 bg-white border-t border-slate-100">
                                {limitReached && (
                                    <div className="bg-rose-50 border border-rose-100 rounded-xl p-3 mb-3 animate-fadeIn flex items-center gap-2">
                                        <svg className="w-3.5 h-3.5 text-rose-500 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="3"/></svg>
                                        <p className="text-[9px] text-rose-700 font-black uppercase tracking-tight leading-tight">Daily limit of {DAILY_LIMIT_PER_CONVERSATION} messages reached.</p>
                                    </div>
                                )}
                                <div className="flex items-center justify-between mb-2">
                                    <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full border ${limitReached ? 'bg-rose-50 text-rose-500 border-rose-100' : 'bg-indigo-50 text-indigo-500 border-indigo-100'}`}>
                                        Quota: {sentTodayCount}/{DAILY_LIMIT_PER_CONVERSATION}
                                    </span>
                                    {isTyping && <span className="text-[8px] text-indigo-400 font-bold uppercase animate-pulse">Syncing Input...</span>}
                                </div>
                                <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(view === 'chat' && !selectedStaff); }} className={`flex gap-3 shrink-0 ${limitReached ? 'opacity-40 grayscale pointer-events-none' : ''}`}>
                                    <input 
                                        type="text" 
                                        value={input} 
                                        onChange={(e) => handleInputChange(e.target.value)} 
                                        disabled={limitReached || isSending} 
                                        placeholder={limitReached ? "Transmission Lock Active" : "Type a message..."} 
                                        className="flex-1 bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3 text-xs outline-none focus:ring-4 focus:ring-indigo-50 transition-all font-medium placeholder:text-slate-300" 
                                    />
                                    <button 
                                        type="submit" 
                                        disabled={!input.trim() || isSending || limitReached} 
                                        className="w-12 h-12 bg-[#0f172a] text-white rounded-2xl flex items-center justify-center hover:bg-black transition-all active:scale-95 disabled:bg-slate-200 shadow-lg border-t border-white/10"
                                    >
                                        {isSending ? (
                                            <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                                        ) : (
                                            <svg className="w-5 h-5 rotate-45 -translate-x-0.5 translate-y-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
                                        )}
                                    </button>
                                </form>
                            </div>
                        </>
                    )}
                </div>
            )}

            <button onClick={() => setIsOpen(!isOpen)} className={`h-14 w-14 rounded-2xl shadow-2xl flex items-center justify-center transition-all duration-500 relative border-t border-white/10 ${isOpen ? 'bg-[#4f46e5] rotate-180' : 'bg-[#0f172a] hover:scale-110 active:scale-95'}`}>
                {isOpen ? <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg> : (
                    <div className="relative">
                        <svg className="w-7 h-7 text-white" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg>
                        {totalUnreadCount > 0 && <div className="absolute -top-3 -right-3 h-5 min-w-[20px] bg-[#ef4444] text-white text-[9px] font-black flex items-center justify-center rounded-full border-2 border-[#0f172a] px-1">{totalUnreadCount}</div>}
                    </div>
                )}
            </button>
        </div>
    );
};

export default ChatAssistant;

export const CODE_2_AUTH_AND_ADMIN = `/**
 * 2_AuthAndAdmin.gs
 * Handles authentication and staff management.
 */

const AuthHandlers = {
  handleLogin: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.error("Configuration Error: 'Users' sheet not found.");
    const data = userSheet.getDataRange().getValues();
    const username = body.username.toLowerCase();
    for (let i = 1; i < data.length; i++) {
        if (data[i][1].toLowerCase() === username && data[i][2] === body.password) {
            return ResponseBuilder.success({ 
              user: { 
                id: data[i][0], 
                username: data[i][1], 
                name: data[i][3], 
                role: data[i][4],
                position: data[i][5]
              } 
            });
        }
    }
    return ResponseBuilder.error("Invalid credentials.");
  },

  /**
   * Professional Heartbeat: Handles everything in the 'Messages' sheet.
   * Finds the user's existing presence row and updates it to prevent sheet flooding.
   */
  handleHeartbeat: function(ss, body) {
    let msgSheet = ss.getSheetByName('Messages');
    if (!msgSheet) return ResponseBuilder.error("Messages sheet missing");

    const data = msgSheet.getDataRange().getValues();
    const username = body.username.toLowerCase();
    const statusType = body.isTyping ? "Typing" : "Presence";
    const now = new Date().toISOString();

    // Search the last 500 rows for this user's presence record to update it
    let foundIndex = -1;
    const searchLimit = Math.max(1, data.length - 500);
    for (let i = data.length - 1; i >= searchLimit; i--) {
      if (String(data[i][1]).toLowerCase() === username && data[i][4] === "HB") {
        foundIndex = i;
        break;
      }
    }

    if (foundIndex !== -1) {
      // Update existing row: Timestamp (6) and Status (7)
      msgSheet.getRange(foundIndex + 1, 6).setValue(now);
      msgSheet.getRange(foundIndex + 1, 7).setValue(statusType);
    } else {
      // Create new presence record if none exists
      msgSheet.appendRow(["ST-" + Date.now(), body.username, body.name || "User", "ALL", "HB", now, statusType]);
    }
    return ResponseBuilder.success();
  },

  handleMarkRead: function(ss, body) {
    let msgSheet = ss.getSheetByName('Messages');
    if (!msgSheet) return ResponseBuilder.error("Messages sheet missing");
    const data = msgSheet.getDataRange().getValues();
    const myId = body.username.toLowerCase();
    const senderId = body.senderId.toLowerCase();

    let updated = false;
    for (let i = data.length - 1; i >= 1; i--) {
        if (String(data[i][3]).toLowerCase() === myId && 
            String(data[i][1]).toLowerCase() === senderId && 
            data[i][6] === 'Sent') {
            msgSheet.getRange(i + 1, 7).setValue('Read');
            updated = true;
        }
        if (i < data.length - 100) break; 
    }
    return ResponseBuilder.success({ updated });
  },

  handleRegisterUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.error("Database Error: 'Users' sheet missing.");
    const id = "USR-" + Date.now();
    sheet.appendRow([
      id, 
      body.username.toLowerCase(), 
      body.password, 
      body.name, 
      body.role, 
      body.position, 
      new Date().toISOString(), 
      JSON.stringify(body.preferences || {}), 
      "TRUE"
    ]);
    return ResponseBuilder.success();
  },

  handleGetUsers: function(ss) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.success({ users: [] });

    const userData = userSheet.getDataRange().getValues();
    const users = userData.slice(1).map(r => {
      return { 
        id: r[0],
        username: r[1], 
        name: r[3], 
        role: r[4], 
        position: r[5], 
        isActive: String(r[8]).toUpperCase() === "TRUE"
      };
    });

    return ResponseBuilder.success({ users });
  },

  handleDeleteUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.error("Database Error.");
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][1].toLowerCase() === body.username.toLowerCase()) {
        sheet.deleteRow(i + 1);
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("Target user not found.");
  },

  handleUpdateUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.error("Users sheet missing");
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][1].toLowerCase() === (body.originalUsername || body.username).toLowerCase()) {
        if (body.username) sheet.getRange(i + 1, 2).setValue(body.username);
        if (body.password) sheet.getRange(i + 1, 3).setValue(body.password);
        if (body.name) sheet.getRange(i + 1, 4).setValue(body.name);
        if (body.role) sheet.getRange(i + 1, 5).setValue(body.role);
        if (body.position) sheet.getRange(i + 1, 6).setValue(body.position);
        if (body.isActive !== undefined) sheet.getRange(i + 1, 9).setValue(body.isActive ? "TRUE" : "FALSE");
        if (body.preferences) sheet.getRange(i + 1, 8).setValue(JSON.stringify(body.preferences));
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("User not found");
  }
};`;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { User, ChatMessage } from '../../types';

interface ChatAssistantProps {
    currentUser: User | null;
    appScriptUrl: string;
    onNavigate?: (module: string) => void;
}

// Optimization Constants
const ACTIVE_POLLING_MS = 6000; 
const HEARTBEAT_INTERVAL_MS = 15000; 
const MAX_MESSAGES_PER_CONVERSATION = 50; 
const DAILY_LIMIT_PER_CONVERSATION = 30;

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentUser, appScriptUrl, onNavigate }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [view, setView] = useState<'list' | 'chat'>('list');
    const [selectedStaff, setSelectedStaff] = useState<User | null>(null);
    const [input, setInput] = useState('');

    // Use a combined state for staff to track their live status derived from messages
    const [staffStatuses, setStaffStatuses] = useState<Record<string, { lastSeen?: string, isTyping?: boolean }>>({});

    const [messages, setMessages] = useState<ChatMessage[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_messages');
        return cached ? JSON.parse(cached) : [];
    });

    const [staff, setStaff] = useState<User[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_staff');
        return cached ? JSON.parse(cached) : [];
    });

    const [isSending, setIsSending] = useState(false);
    const [isLocalTyping, setIsLocalTyping] = useState(false);
    const [limitReached, setLimitReached] = useState(false);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const lastFetchRef = useRef<number>(0);
    const pollTimerRef = useRef<number | null>(null);
    const typingTimeoutRef = useRef<number | null>(null);

    const isAdmin = currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin';
    const normalize = (id: string) => (id || '').toLowerCase().trim();

    // 1. Separate actual chat messages from system presence signals
    const chatOnlyMessages = useMemo(() => {
        return messages.filter(m => m.message !== 'HB' && m.status !== 'Presence' && m.status !== 'Typing');
    }, [messages]);

    // 2. Derive staff presence and sort by recency
    const sortedStaff = useMemo(() => {
        if (!currentUser) return staff;
        const myUid = normalize(currentUser.username);

        return [...staff].sort((a, b) => {
            const uidA = normalize(a.username);
            const uidB = normalize(b.username);

            const lastMsgA = [...chatOnlyMessages].reverse().find(m => 
                (normalize(m.senderId) === uidA && normalize(m.receiverId) === myUid) ||
                (normalize(m.senderId) === myUid && normalize(m.receiverId) === uidA)
            );

            const lastMsgB = [...chatOnlyMessages].reverse().find(m => 
                (normalize(m.senderId) === uidB && normalize(m.receiverId) === myUid) ||
                (normalize(m.senderId) === myUid && normalize(m.receiverId) === uidB)
            );

            const timeA = lastMsgA ? new Date(lastMsgA.timestamp).getTime() : 0;
            const timeB = lastMsgB ? new Date(lastMsgB.timestamp).getTime() : 0;

            return timeB - timeA;
        });
    }, [staff, chatOnlyMessages, currentUser]);

    // Update staff presence status from messages sheet
    useEffect(() => {
        const newStatuses: Record<string, { lastSeen?: string, isTyping?: boolean }> = {};
        messages.filter(m => m.message === 'HB').forEach(m => {
            const uid = normalize(m.senderId);
            const ts = m.timestamp;
            const isTyping = m.status === 'Typing';

            if (!newStatuses[uid] || new Date(ts) > new Date(newStatuses[uid].lastSeen || 0)) {
                newStatuses[uid] = { lastSeen: ts, isTyping };
            }
        });
        setStaffStatuses(newStatuses);
    }, [messages]);

    const sentTodayCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : 'ALL';
        const today = new Date().toISOString().split('T')[0];
        return chatOnlyMessages.filter(m => m.timestamp.startsWith(today) && normalize(m.senderId) === myUid && normalize(m.receiverId) === partnerUid).length;
    }, [chatOnlyMessages, currentUser, selectedStaff]);

    useEffect(() => { setLimitReached(sentTodayCount >= DAILY_LIMIT_PER_CONVERSATION); }, [sentTodayCount]);

    const filteredMessagesForView = useMemo(() => {
        if (!currentUser) return [];
        const myUid = normalize(currentUser.username);
        const partnerUid = selectedStaff ? normalize(selectedStaff.username) : null;
        const relevant = chatOnlyMessages.filter(m => {
            if (!selectedStaff) return (m.message || '').startsWith('[BROADCAST]:') || normalize(m.receiverId) === 'all';
            return (normalize(m.senderId) === myUid && normalize(m.receiverId) === partnerUid) || (normalize(m.senderId) === partnerUid && normalize(m.receiverId) === myUid);
        });
        return relevant.slice(-MAX_MESSAGES_PER_CONVERSATION);
    }, [chatOnlyMessages, selectedStaff, currentUser]);

    const totalUnreadCount = useMemo(() => {
        if (!currentUser) return 0;
        const myUid = normalize(currentUser.username);
        return new Set(chatOnlyMessages.filter(m => normalize(m.receiverId) === myUid && m.status === 'Sent').map(m => normalize(m.senderId))).size;
    }, [chatOnlyMessages, currentUser]);

    const isUserOnline = (username: string) => {
        const status = staffStatuses[normalize(username)];
        if (!status?.lastSeen) return false;
        return Date.now() - new Date(status.lastSeen).getTime() < 45000;
    };

    const sendHeartbeat = async () => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ action: 'heartbeat', username: currentUser.username, name: currentUser.name, isTyping: isLocalTyping }),
                mode: 'no-cors'
            });
        } catch (e) {}
    };

    const fetchData = async () => {
        if (!appScriptUrl || !currentUser || !navigator.onLine) return;
        const now = Date.now();
        if (now - lastFetchRef.current < 4000) return; 
        lastFetchRef.current = now;

        try {
            const [uResp, mResp] = await Promise.all([
                fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) }),
                fetch(`${appScriptUrl}?t=${now}`)
            ]);

            if (uResp.ok) {
                const uData = await uResp.json();
                if (uData.status === 'success') {
                    const filtered = uData.users.filter((u: User) => normalize(u.username) !== normalize(currentUser.username));
                    setStaff(filtered);
                    localStorage.setItem('sc_chat_cache_staff', JSON.stringify(filtered));
                }
            }

            if (mResp.ok) {
                const json = await mResp.json();
                const chatData = json['Messages'];
                if (Array.isArray(chatData) && chatData.length > 1) {
                    const serverMsgs: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                        id: String(row[0]), senderId: row[1], senderName: row[2],
                        receiverId: row[3], message: row[4] || '', timestamp: row[5], status: row[6] || 'Sent'
                    }));
                    setMessages(prev => {
                        const serverIds = new Set(serverMsgs.map(m => m.id));
                        const localOnly = prev.filter(m => m.status === 'Sending' && !serverIds.has(m.id));
                        const combined = [...serverMsgs, ...localOnly].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
                        localStorage.setItem('sc_chat_cache_messages', JSON.stringify(combined));
                        return combined;
                    });
                }
            }
        } catch (e) {}
    };

