      SystemLogger.log("Admin", "INVITE_SENT", "Invitation sent to " + email, "Success");
    } catch (e) {
      SystemLogger.log("Admin", "INVITE_FAILED", "Failed to send invitation to " + email + ": " + e.toString(), "Critical");
    }
  }
};`;

export const CODE_3_CORE_OPERATIONS = `/**
 * 3_CoreOperations.gs
 * Handles data flow, fleet assets, and system configuration.
 */

const DataHandlers = {
  handleDataSubmission: function(ss, body) {
    const sheetName = body.sheet;
    const rowData = body.row;
    let sheet = ss.getSheetByName(sheetName);

    if (!sheet) return ResponseBuilder.error("Target registry '" + sheetName + "' not found.");

    const safeRow = rowData.map(r => (r === null || r === undefined) ? "" : String(r));
    sheet.appendRow(safeRow);

    if (body.requestId) {
        const reqSheet = ss.getSheetByName('Inspection_Requests');
        if (reqSheet) {
            const reqData = reqSheet.getDataRange().getValues();
            for (let i = 1; i < reqData.length; i++) {
                if (String(reqData[i][0]) === String(body.requestId)) {
                    reqSheet.getRange(i + 1, 10).setValue('Completed');
                    break;
                }
            }
        }
    }

    if (body.reportData) { 
      SystemLogger.log(body.reportData.inspectedBy, "DATA_SUBMITTED", "Inspection saved for unit " + body.reportData.truckNo + " in registry " + sheetName, "Success");
      EmailDispatcher.sendInspectionReport(body.reportData); 
    } else {
      SystemLogger.log("System", "DATA_SUBMITTED", "Row added to " + sheetName, "Success");
    }

    return ResponseBuilder.success({ sheet: sheetName });
  },

  handleGetRequest: function(ss) {
    const sheets = ss.getSheets();
    const data = {};
    sheets.forEach(sheet => {
      const name = sheet.getName();
      if (name === 'Users' || name === 'System_Logs' || name === 'Acknowledgements') return;
      const lastRow = sheet.getLastRow();
      if (lastRow === 0) { data[name] = []; return; }

      if (name === 'Validation_Data') {
         if (lastRow > 1) {
            const range = sheet.getRange(2, 1, lastRow - 1, sheet.getLastColumn());
            const values = range.getValues();
            const columns = {};
            const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
            headers.forEach((h, colIndex) => {
               columns[h] = [...new Set(values.map(row => row[colIndex]).filter(c => c !== ""))]; 
            });
            data[name] = columns;
         } else { data[name] = {}; }
      } else if (name === 'Subscription_Data') {
          const values = sheet.getDataRange().getValues();
          if (values.length > 1) {
            const history = [];
            for (let i = 1; i < values.length; i++) {
                const row = values[i];
                let expiry = row[2];
                if (expiry instanceof Date) expiry = Utilities.formatDate(expiry, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
                history.push({ status: row[0], plan: row[1], expiryDate: expiry, processedBy: row[3], timestamp: row[4] });
            }
            data[name] = { current: history[history.length - 1], history: history };
          } else { data[name] = { current: { status: "Expired", plan: "None", expiryDate: "" }, history: [] }; }
      } else {
         const startRow = Math.max(1, lastRow - 150);
         const values = sheet.getRange(startRow, 1, lastRow - startRow + 1, sheet.getLastColumn()).getValues();
         if (startRow > 1) values.unshift(sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0]);
         data[name] = values;
      }
    });
    return ResponseBuilder.build(data);
  }
};

const SystemHandlers = {
  handleUpdateSettings: function(ss, body) {
    let settingsSheet = ss.getSheetByName('System_Settings');
    if (!settingsSheet) return ResponseBuilder.error("System_Settings sheet missing.");
    const updateRow = [
      body.companyName || '', body.managerEmail || '', new Date(), body.updatedBy || "Admin", 
      body.companyLogo || '', body.mobileApkLink || '', body.webAppUrl || '', 
      body.maintenanceMode ? "TRUE" : "FALSE", body.maintenanceMessage || '', 
      body.flutterwaveSecretKey || ''
    ];
    if (settingsSheet.getLastRow() < 2) settingsSheet.appendRow(updateRow);
    else settingsSheet.getRange(2, 1, 1, updateRow.length).setValues([updateRow]);

    SystemLogger.log(body.updatedBy || "Admin", "SETTINGS_UPDATED", "System configuration synchronized", "Success");
    return ResponseBuilder.success();
  },
  handleManageFleet: function(ss, body) {
    const sheet = ss.getSheetByName('Validation_Data');
    if (!sheet) return ResponseBuilder.error("Validation_Data sheet missing.");
    const col = body.type === 'truck' ? 1 : 2;
    sheet.getRange(sheet.getLastRow() + 1, col).setValue(body.value);
    SystemLogger.log("Admin", "FLEET_UPDATE", "Added " + body.type + ": " + body.value, "Success");
    return ResponseBuilder.success();
  },
  handleBulkManageFleet: function(ss, body) {
    const sheet = ss.getSheetByName('Validation_Data');
    if (!sheet) return ResponseBuilder.error("Validation_Data sheet missing.");
    if (body.trucks) body.trucks.forEach(t => sheet.getRange(sheet.getLastRow() + 1, 1).setValue(t));
    if (body.trailers) body.trailers.forEach(t => sheet.getRange(sheet.getLastRow() + 1, 2).setValue(t));
    SystemLogger.log("Admin", "FLEET_BULK_UPDATE", "Imported bulk equipment registry", "Success");
    return ResponseBuilder.success();
  },
  handleRequestInspection: function(ss, body) {
    const sheet = ss.getSheetByName('Inspection_Requests');
    if (!sheet) return ResponseBuilder.error("Inspection_Requests sheet missing.");
    const requestId = "REQ-" + Date.now();
    sheet.appendRow([
      requestId, body.requester, body.role, body.truckNo, body.trailerNo, 
      body.type, body.reason, body.priority, body.assignedInspector || "Unassigned", 
      "Pending", new Date().toISOString()
    ]);
    SystemLogger.log(body.requester, "INSPECTION_REQUESTED", "Created request " + requestId + " for unit " + body.truckNo, "Success");
    return ResponseBuilder.success();
  },
  handleBroadcast: function(ss, body) {
    const sheet = ss.getSheetByName('Messages');
    if (!sheet) return ResponseBuilder.error("Messages sheet missing.");

    const id = "BC-" + Date.now();
    const broadcastTag = body.type === 'critical' ? '[CRITICAL ALERT]: ' : '[BROADCAST]: ';
    const messageContent = broadcastTag + body.message;

    sheet.appendRow([
      id,
      "SYSTEM", 
      "Broadcast Hub",
      "ALL",
      messageContent, 
      new Date().toISOString(),
      "Sent"
    ]);

    SystemLogger.log("System", "BROADCAST", body.message, "Success");
    return ResponseBuilder.success();
  },
  handleAcknowledgeNotification: function(ss, body) {
    const sheet = ss.getSheetByName('Acknowledgements');
    if (sheet) sheet.appendRow([body.notificationId, body.user, new Date().toISOString()]);
    return ResponseBuilder.success();
  }
};

const PaymentHandlers = {
  handleMobileMoney: function(ss, body) {
    const settingsSheet = ss.getSheetByName('System_Settings');
    if (!settingsSheet) return ResponseBuilder.error("Settings missing.");
    const secretKey = settingsSheet.getRange(2, 10).getValue(); 
    if (!secretKey) return ResponseBuilder.error("Payment system not configured.");
    const payload = {
      "amount": body.amount, "currency": "ZMW", "phone_number": body.phoneNumber,
      "network": body.network, "email": body.email, "tx_ref": "TXN-" + Date.now(),
      "order_id": "SUB-" + Date.now(), "description": body.description, "country": "ZM"
    };
    try {
      const response = UrlFetchApp.fetch("https://api.flutterwave.com/v3/charges?type=mobile_money_zambia", {
        "method": "post", "contentType": "application/json",
        "headers": { "Authorization": "Bearer " + secretKey },
        "payload": JSON.stringify(payload), "muteHttpExceptions": true
      });
      const resData = JSON.parse(response.getContentText());
      if (resData.status === "success") {
        SystemLogger.log(body.email, "PAYMENT_INITIATED", "Renewal prompt sent to " + body.phoneNumber, "Success");
        return ResponseBuilder.success({ message: "Prompt dispatched." });
      } else {
        SystemLogger.log(body.email, "PAYMENT_ERROR", resData.message, "Error");
        return ResponseBuilder.error(resData.message);
      }
    } catch (e) { return ResponseBuilder.error("Gateway timeout."); }
  }
};

const SubscriptionHandlers = {
  handleCheckSubscription: function(ss) {
    let subSheet = ss.getSheetByName('Subscription_Data');
    if (!subSheet || subSheet.getLastRow() < 2) return ResponseBuilder.success({ subscription: { status: 'Expired', daysRemaining: 0 } });
    const data = subSheet.getRange(subSheet.getLastRow(), 1, 1, 4).getValues()[0];
    const expiry = new Date(data[2]);
    const diff = Math.ceil((expiry.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
    return ResponseBuilder.success({ subscription: { status: diff > 0 ? data[0] : 'Expired', plan: data[1], expiryDate: data[2], daysRemaining: Math.max(0, diff) } });
  },
  handleExtendSubscription: function(ss, body) {
    let subSheet = ss.getSheetByName('Subscription_Data');
    if (subSheet) subSheet.appendRow([body.status, body.plan, body.expiryDate, "System", new Date().toISOString()]);
    SystemLogger.log("System", "SUBSCRIPTION_UPDATED", "License extended to " + body.expiryDate, "Success");
    return ResponseBuilder.success();
  }
};`;

import { GoogleGenAI } from "@google/genai";
import { InspectionData, InspectionStatus } from "../types";
import { INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS } from "../constants";

export const analyzeInspection = async (data: InspectionData): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Identify which items set belongs to this data
  let allItems = INSPECTION_ITEMS;
  if (data.petro_1) allItems = PETROLEUM_INSPECTION_ITEMS;
  else if (data.petro2_1) allItems = PETROLEUM_V2_ITEMS;
  else if (data.acid_1) allItems = ACID_INSPECTION_ITEMS;

  // Extract failed or warning items for the prompt
  const failedItems = allItems.filter(item => data[item.id] === InspectionStatus.BAD).map(i => i.label);
  const attentionItems = allItems.filter(item => data[item.id] === InspectionStatus.ATTENTION).map(i => i.label);

  const prompt = `
    As a professional Fleet Safety Auditor, provide a brief, authoritative safety explanation for the following vehicle inspection response.

    VEHICLE DETAILS:
    - Truck No: ${data.truckNo}
    - Trailer No: ${data.trailerNo}
    - Overall Rating: ${data.rate}/5
    - Safe to Load: ${data.safeToLoad}

    CRITICAL FAULTS DETECTED:
    ${failedItems.length > 0 ? failedItems.join(', ') : 'None'}

    ITEMS REQUIRING ATTENTION:
    ${attentionItems.length > 0 ? attentionItems.join(', ') : 'None'}

    USER'S BRIEF EXPLANATION:
    "${data.remarks || 'No additional notes'}"

    TASK:
    Generate a 2-3 sentence "Brief Explanation" summarizing the safety state. If grounded (Safe to Load: No), explain the primary risk. If clear, validate the condition. Be concise and professional.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    return response.text || "Safety analysis complete. Verification successful.";
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    // Fallback logic if API fails
    if (data.safeToLoad === 'No' || failedItems.length > 0) {
      return "CRITICAL: Vehicle safety thresholds not met. Maintenance required before deployment.";
    }
    return "OPERATIONAL: Vehicle condition satisfies standard safety protocols.";
  }
};

import React, { useState, useEffect } from 'react';
import { InspectionData, InspectionStatus, InspectionItemConfig, ValidationLists, SystemSettings } from '../types';
import { INSPECTION_ITEMS, INSPECTION_CATEGORIES, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_CATEGORIES, ACID_INSPECTION_ITEMS, ACID_CATEGORIES, PETROLEUM_V2_ITEMS, PETROLEUM_V2_CATEGORIES, SECTIONS } from '../constants';
import CameraCapture from '../components/CameraCapture';
import SignaturePad from '../components/SignaturePad';
import StatusButton from '../components/ui/StatusButton';
import Input from '../components/ui/Input';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface InspectionFormViewProps {
    initialData: InspectionData;
    activeModule: string;
    validationLists: ValidationLists;
    settings: SystemSettings;
    onSaveDraft: (data: InspectionData) => void;
    onSubmit: (data: InspectionData) => void;
    onExit: () => void;
    submissionStatus: 'idle' | 'submitting' | 'success' | 'offline_saved';
    onViewReport: (data: InspectionData) => void;
}

const InspectionFormView: React.FC<InspectionFormViewProps> = ({ 
    initialData, activeModule, validationLists, onSaveDraft, onSubmit, onExit, submissionStatus
}) => {
    const [formData, setFormData] = useState<InspectionData & any>(initialData);
    const [currentSection, setCurrentSection] = useState(0);
    const [errors, setErrors] = useState<Record<string, boolean>>({});
    const [showDraftSaved, setShowDraftSaved] = useState(false);

    const updateField = (field: string, value: any) => {
        setFormData((prev: any) => ({ ...prev, [field]: value }));
        if (errors[field]) {
            setErrors(prev => {
                const next = {...prev};
                delete next[field];
                return next;
            });
        }
    };

    const handleSaveDraftLocal = () => {
        onSaveDraft(formData);
        setShowDraftSaved(true);
        setTimeout(() => setShowDraftSaved(false), 2000);
    };

    const getItemsForStep = (stepIndex: number): InspectionItemConfig[] => {
        let categories: string[] = [];
        let sourceItems: InspectionItemConfig[] = [];

        if (activeModule === 'general') sourceItems = INSPECTION_ITEMS;
        else if (activeModule === 'petroleum') sourceItems = PETROLEUM_INSPECTION_ITEMS;
        else if (activeModule === 'petroleum_v2') sourceItems = PETROLEUM_V2_ITEMS;
        else if (activeModule === 'acid') sourceItems = ACID_INSPECTION_ITEMS;

        if (activeModule === 'general') {
            if (stepIndex === 2) categories = [INSPECTION_CATEGORIES.PPE, INSPECTION_CATEGORIES.DOCUMENTATION];
            if (stepIndex === 3) categories = [INSPECTION_CATEGORIES.VEHICLE_EXTERIOR, INSPECTION_CATEGORIES.LIGHTS_ELECTRICAL];
            if (stepIndex === 4) categories = [INSPECTION_CATEGORIES.MECHANICAL, INSPECTION_CATEGORIES.TRAILER];
        } else if (activeModule === 'petroleum') {
            if (stepIndex === 2) categories = [PETROLEUM_CATEGORIES.TRUCK_EQUIPMENT];
            if (stepIndex === 3) categories = [PETROLEUM_CATEGORIES.TYRES, PETROLEUM_CATEGORIES.PPE_ID];
            if (stepIndex === 4) categories = [PETROLEUM_CATEGORIES.DOCUMENTS, PETROLEUM_CATEGORIES.ONBOARD];
        } else if (activeModule === 'petroleum_v2') {
            if (stepIndex === 2) categories = [PETROLEUM_V2_CATEGORIES.PRIME_MOVER];
            if (stepIndex === 3) categories = [PETROLEUM_V2_CATEGORIES.TRAILER_TANKS];
            if (stepIndex === 4) categories = [PETROLEUM_V2_CATEGORIES.DRIVER, PETROLEUM_V2_CATEGORIES.SAFETY_SIGNS, PETROLEUM_V2_CATEGORIES.DOCUMENTS];
        } else if (activeModule === 'acid') {
            if (stepIndex === 2) categories = [ACID_CATEGORIES.PPE];
            if (stepIndex === 3) categories = [ACID_CATEGORIES.VEHICLE];
            if (stepIndex === 4) categories = [ACID_CATEGORIES.SPILL_KIT, ACID_CATEGORIES.DOCUMENTATION];
        }

        return sourceItems.filter(item => categories.includes(item.category));
    };

    const validateSection = (sectionIndex: number): boolean => {
        const newErrors: Record<string, boolean> = {};

        if (sectionIndex === 0) {
            if (!formData.truckNo) newErrors.truckNo = true;
            if (!formData.trailerNo) newErrors.trailerNo = true;
            if (!formData.driverName) newErrors.driverName = true;
            if (!formData.location) newErrors.location = true;
            if (!formData.odometer) newErrors.odometer = true;
            if (activeModule !== 'general' && !formData.jobCard) newErrors.jobCard = true;
        }

        if (sectionIndex >= 2 && sectionIndex <= 4) {
            const requiredItems = getItemsForStep(sectionIndex);
            requiredItems.forEach(item => {
                if (!formData[item.id]) newErrors[item.id] = true;
            });
        }

        if (sectionIndex === 5) {
             if (!formData.remarks || formData.remarks.trim() === '') newErrors.remarks = true;
             if (!formData.rate || formData.rate === 0) newErrors.rate = true;
             if (!formData.safeToLoad) newErrors.safeToLoad = true;
             if (!formData.inspectorSignature) newErrors.inspectorSignature = true;
             if (!formData.driverSignature) newErrors.driverSignature = true;
        }

        if (Object.keys(newErrors).length > 0) {
            setErrors(newErrors);
            // Scroll to the first missing field
            setTimeout(() => {
                const firstErrorKey = Object.keys(newErrors)[0];
                const errorElement = document.querySelector(`[data-field-id="${firstErrorKey}"]`);
                if (errorElement) {
                    errorElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
                } else {
                    window.scrollTo({ top: 0, behavior: 'smooth' });
                }
            }, 100);
            return false;
        }

        setErrors({});
        return true;
    };

    const handleNext = () => {
        if (!validateSection(currentSection)) return;
        window.scrollTo({ top: 0, behavior: 'smooth' });
        setCurrentSection(prev => Math.min(prev + 1, SECTIONS.length - 1));
    };

    const handleBack = () => {
        if (currentSection === 0) onExit();
        else {
            window.scrollTo({ top: 0, behavior: 'smooth' });
            setCurrentSection(prev => Math.max(prev - 1, 0));
        }
    };

    const handleSubmitInspection = () => {
        if (validateSection(currentSection)) onSubmit(formData);
    };

    return (
        <div className="flex flex-col min-h-[calc(100vh-56px)] bg-slate-50/50">
             {/* COMPACT FLOW INDICATOR */}
             <div className="bg-white border-b border-slate-100 sticky top-14 z-30 shadow-sm shrink-0">
                <div className="max-w-5xl mx-auto px-4 py-4 sm:py-5 overflow-hidden">
                    <div className="flex justify-between items-center gap-1 sm:gap-4">
                        {SECTIONS.slice(0, 6).map((section, idx) => {
                            const isActive = idx === currentSection;
                            const isCompleted = idx < currentSection;
                            return (
                                <React.Fragment key={section.id}>
                                    <div className="flex flex-col items-center gap-1.5 min-w-0 transition-all duration-500">
                                        <div className={`
                                            w-6 h-6 sm:w-8 sm:h-8 rounded-lg flex items-center justify-center text-[8px] sm:text-xs font-black transition-all
                                            ${isActive ? 'bg-slate-900 text-white shadow-lg scale-110' : isCompleted ? 'bg-emerald-500 text-white' : 'bg-slate-100 text-slate-300'}
                                        `}>
                                            {isCompleted ? '✓' : idx + 1}
                                        </div>
                                        <span className={`text-[7px] font-black uppercase tracking-tighter sm:tracking-widest truncate w-full text-center hidden xs:block ${isActive ? 'text-slate-900' : 'text-slate-300'}`}>
                                            {section.title}
                                        </span>
                                    </div>
                                    {idx < 5 && (
                                        <div className={`h-px flex-1 rounded-full ${isCompleted ? 'bg-emerald-500' : 'bg-slate-100'}`} />
                                    )}
                                </React.Fragment>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* FLUID CONTENT AREA */}
            <div className="flex-1 p-4 sm:p-8 w-full max-w-5xl mx-auto pb-32">
                {currentSection === 0 && (
                    <div className="space-y-4 animate-fadeIn">
                        <div className="bg-white p-6 sm:p-10 rounded-[2rem] border border-slate-100 shadow-sm">
                            <h2 className="text-xl sm:text-2xl font-black text-slate-800 mb-8 uppercase tracking-tight">Inspection Details</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 sm:gap-8">
                                <div data-field-id="truckNo"><AutocompleteInput label="Truck Registration *" value={formData.truckNo} onChange={v => updateField('truckNo', v)} options={validationLists.trucks} isRegNo={true} error={errors.truckNo} /></div>
                                <div data-field-id="trailerNo"><AutocompleteInput label="Trailer ID *" value={formData.trailerNo} onChange={v => updateField('trailerNo', v)} options={validationLists.trailers} isRegNo={true} error={errors.trailerNo} /></div>
                                <div data-field-id="jobCard"><Input label="Job Card (if any)" value={formData.jobCard || ''} onChange={v => updateField('jobCard', v)} error={errors.jobCard} /></div>
                                <div data-field-id="inspectedBy"><AutocompleteInput label="Inspector" value={formData.inspectedBy} onChange={v => updateField('inspectedBy', v)} options={validationLists.inspectors} readOnly={true} /></div>
                                <div data-field-id="driverName"><AutocompleteInput label="Driver Name *" value={formData.driverName} onChange={v => updateField('driverName', v)} options={validationLists.drivers} isTitleCase={true} error={errors.driverName} /></div>
                                <div data-field-id="location"><AutocompleteInput label="Location *" value={formData.location} onChange={v => updateField('location', v)} options={validationLists.locations} isTitleCase={true} error={errors.location} /></div>
                                <div data-field-id="odometer"><Input label="Odometer Reading (KM) *" type="number" value={formData.odometer} onChange={v => updateField('odometer', v)} error={errors.odometer} /></div>
                            </div>
                        </div>
                    </div>
                )}

                {currentSection === 1 && (
                    <div className="space-y-4 animate-fadeIn">
                        <div className="bg-white p-6 sm:p-10 rounded-[2rem] border border-slate-100 shadow-sm">
                            <h2 className="text-xl sm:text-2xl font-black text-slate-800 mb-8 uppercase tracking-tight">Vehicle Photos</h2>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6">
                                <CameraCapture label="Front View" existingImage={formData.photoFront} onCapture={img => updateField('photoFront', img)} />
                                <CameraCapture label="Left Side" existingImage={formData.photoLS} onCapture={img => updateField('photoLS', img)} />
                                <CameraCapture label="Right Side" existingImage={formData.photoRS} onCapture={img => updateField('photoRS', img)} />
                                <CameraCapture label="Rear View" existingImage={formData.photoBack} onCapture={img => updateField('photoBack', img)} />
                            </div>
                        </div>
                    </div>
                )}

                {(currentSection >= 2 && currentSection <= 4) && (
                    <div className="space-y-6 animate-fadeIn">
                        {Array.from(new Set(getItemsForStep(currentSection).map(i => i.category))).map(cat => (
                            <div key={cat} className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
                                <div className="bg-slate-50/50 px-6 py-4 border-b border-slate-100 flex justify-between items-center">
                                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{cat}</h3>
                                </div>
                                <div className="divide-y divide-slate-50">
                                    {getItemsForStep(currentSection).filter(i => i.category === cat).map(item => (
                                        <div key={item.id} data-field-id={item.id} className={`p-6 sm:p-8 transition-colors ${errors[item.id] ? 'bg-rose-50/30' : ''}`}>
                                            <p className="font-bold text-xs sm:text-sm text-slate-700 uppercase tracking-tight mb-5 leading-snug">{item.label}</p>
                                            <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 sm:gap-4 max-w-2xl">
                                                <StatusButton label="Good" status={InspectionStatus.GOOD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.GOOD)} colorClass="green" />
                                                <StatusButton label="Fault" status={InspectionStatus.BAD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.BAD)} colorClass="red" />
                                                <StatusButton label="Review" status={InspectionStatus.ATTENTION} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.ATTENTION)} colorClass="yellow" />
                                                <StatusButton label="N/A" status={InspectionStatus.NIL} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.NIL)} colorClass="gray" />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {currentSection === 5 && (
                    <div className="space-y-4 animate-fadeIn">
