};

const SystemLogger = {
  log: function(user, action, details, status) {
    try {
      const ss = SpreadsheetApp.getActiveSpreadsheet();
      let logSheet = ss.getSheetByName('System_Logs');
      if (!logSheet) {
        logSheet = ss.insertSheet('System_Logs');
        logSheet.appendRow(['Timestamp', 'User', 'Action', 'Details', 'Status']);
        logSheet.getRange(1, 1, 1, 5).setFontWeight('bold').setBackground('#f3f3f3');
        logSheet.setFrozenRows(1);
      }
      logSheet.appendRow([new Date(), user || "System", action, details, status || "Info"]);
    } catch (e) {
      Logger.log("Logger Failure: " + e.toString());
    }
  }
};

const EmailDispatcher = {
  sendInspectionReport: function(data) {
    try {
      const ss = SpreadsheetApp.getActiveSpreadsheet();
      const settingsSheet = ss.getSheetByName('System_Settings');
      const userSheet = ss.getSheetByName('Users');

      let orgName = "SafetyCheck Pro";
      if (settingsSheet && settingsSheet.getLastRow() > 1) {
        orgName = settingsSheet.getRange(2, 1).getValue() || orgName;
      }

      if (!userSheet) {
        SystemLogger.log(data.inspectedBy, "EMAIL_FAILED", "Users sheet missing", "Error");
        return;
      }

      const userData = userSheet.getDataRange().getValues();
      const recipients = [];

      // Determine preference key based on module title
      let prefKey = 'notifyGeneral';
      const title = data.title || "";
      if (title.includes('V2')) prefKey = 'notifyPetroleumV2';
      else if (title.includes('Petroleum')) prefKey = 'notifyPetroleum';
      else if (title.includes('Acid')) prefKey = 'notifyAcid';

      // Scan all users for active notification permissions
      for (let i = 1; i < userData.length; i++) {
        const userEmail = String(userData[i][1]).toLowerCase();
        const rawPrefs = userData[i][7];
        const isActive = String(userData[i][8]).toUpperCase() === 'TRUE';

        if (!isActive || !userEmail.includes('@')) continue;

        try {
          const prefs = JSON.parse(rawPrefs || '{}');
          if (prefs.emailNotifications === true && prefs[prefKey] === true) {
            recipients.push(userEmail);
          }
        } catch (e) {
          // Skip users with malformed preferences
        }
