export const CODE_3_CORE_OPERATIONS = `/**
 * 3_CoreOperations.gs
 * Handles data flow, fleet assets, and system configuration.
 */

const DataHandlers = {
  handleDataSubmission: function(ss, body) {
    const sheetName = body.sheet;
    const rowData = body.row;
    let sheet = ss.getSheetByName(sheetName);

    if (!sheet) return ResponseBuilder.error("Target registry '" + sheetName + "' not found.");

    const safeRow = rowData.map(r => (r === null || r === undefined) ? "" : String(r));
    sheet.appendRow(safeRow);

    // Auto-update Validation Data lists
    Validation.updateFromRow(ss, body);

    if (body.requestId) {
        const reqSheet = ss.getSheetByName('Inspection_Requests');
        if (reqSheet) {
            const reqData = reqSheet.getDataRange().getValues();
            for (let i = 1; i < reqData.length; i++) {
                if (String(reqData[i][0]) === String(body.requestId)) {
                    reqSheet.getRange(i + 1, 10).setValue('Completed');
                    break;
                }
            }
        }
    }

    // Logging and Email dispatch using User-provided logic
    const inspector = body.reportData ? body.reportData.inspectedBy : "System";
    const truck = body.reportData ? body.reportData.truckNo : "Unknown";

    SystemLogger.log(inspector, "DATA_SUBMITTED", "Inspection saved for unit " + truck + " in " + sheetName, "Success");

    // Trigger the broadcast notification logic
    EmailHandlers.sendEmailNotifications(ss, body, sheetName);

    return ResponseBuilder.success({ sheet: sheetName });
  },

  handleGetRequest: function(ss) {
    const sheets = ss.getSheets();
    const data = {};
    sheets.forEach(sheet => {
      const name = sheet.getName();
      if (name === 'Users' || name === 'System_Logs' || name === 'Acknowledgements' || name === 'Support_Tickets') return;
      const lastRow = sheet.getLastRow();
      if (lastRow === 0) { data[name] = []; return; }

      if (name === 'Validation_Data') {
         if (lastRow > 1) {
            const range = sheet.getRange(2, 1, lastRow - 1, sheet.getLastColumn());
            const values = range.getValues();
            const columns = {};
            const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
            headers.forEach((h, colIndex) => {
               columns[h] = [...new Set(values.map(row => row[colIndex]).filter(c => c !== ""))]; 
            });
            data[name] = columns;
         } else { data[name] = {}; }
      } else if (name === 'Subscription_Data') {
          const values = sheet.getDataRange().getValues();
          if (values.length > 1) {
            const history = [];
            for (let i = 1; i < values.length; i++) {
                const row = values[i];
                let expiry = row[2];
                if (expiry instanceof Date) expiry = Utilities.formatDate(expiry, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
                history.push({ status: row[0], plan: row[1], expiryDate: expiry, processedBy: row[3], timestamp: row[4] });
            }
            data[name] = { current: history[history.length - 1], history: history };
          } else { data[name] = { current: { status: "Expired", plan: "None", expiryDate: "" }, history: [] }; }
      } else {
         const startRow = Math.max(1, lastRow - 150);
         const values = sheet.getRange(startRow, 1, lastRow - startRow + 1, sheet.getLastColumn()).getValues();
         if (startRow > 1) values.unshift(sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0]);
         data[name] = values;
      }
    });
    return ResponseBuilder.build(data);
  }
};

const SystemHandlers = {
  handleUpdateSettings: function(ss, body) {
    let settingsSheet = ss.getSheetByName('System_Settings');
    if (!settingsSheet) return ResponseBuilder.error("System_Settings sheet missing.");
    const updateRow = [
      body.companyName || '', body.managerEmail || '', new Date(), body.updatedBy || "Admin", 
      body.companyLogo || '', body.mobileApkLink || '', body.webAppUrl || '', 
      body.maintenanceMode ? "TRUE" : "FALSE", body.maintenanceMessage || '', 
      body.flutterwaveSecretKey || ''
    ];
    if (settingsSheet.getLastRow() < 2) settingsSheet.appendRow(updateRow);
    else settingsSheet.getRange(2, 1, 1, updateRow.length).setValues([updateRow]);

    SystemLogger.log(body.updatedBy || "Admin", "SETTINGS_UPDATED", "System configuration synchronized", "Success");
    return ResponseBuilder.success();
  },
  handleManageFleet: function(ss, body) {
    const sheet = ss.getSheetByName('Validation_Data');
    if (!sheet) return ResponseBuilder.error("Validation_Data sheet missing.");
    const col = body.type === 'truck' ? 1 : 2;
    sheet.getRange(sheet.getLastRow() + 1, col).setValue(body.value);
    SystemLogger.log("Admin", "FLEET_UPDATE", "Added " + body.type + ": " + body.value, "Success");
    return ResponseBuilder.success();
  },
  handleBulkManageFleet: function(ss, body) {
    const sheet = ss.getSheetByName('Validation_Data');
    if (!sheet) return ResponseBuilder.error("Validation_Data sheet missing.");
    if (body.trucks) body.trucks.forEach(t => sheet.getRange(sheet.getLastRow() + 1, 1).setValue(t));
    if (body.trailers) body.trailers.forEach(t => sheet.getRange(sheet.getLastRow() + 1, 2).setValue(t));
    SystemLogger.log("Admin", "FLEET_BULK_UPDATE", "Imported bulk equipment registry", "Success");
    return ResponseBuilder.success();
  },
  handleRequestInspection: function(ss, body) {
    const sheet = ss.getSheetByName('Inspection_Requests');
    if (!sheet) return ResponseBuilder.error("Inspection_Requests sheet missing.");
    const requestId = "REQ-" + Date.now();
    sheet.appendRow([
      requestId, body.requester, body.role, body.truckNo, body.trailerNo, 
      body.type, body.reason, body.priority, body.assignedInspector || "Unassigned", 
      "Pending", new Date().toISOString()
    ]);
    SystemLogger.log(body.requester, "INSPECTION_REQUESTED", "Created request " + requestId + " for unit " + body.truckNo, "Success");
    return ResponseBuilder.success();
  },
  handleBroadcast: function(ss, body) {
    const sheet = ss.getSheetByName('Messages');
    if (!sheet) return ResponseBuilder.error("Messages sheet missing.");

    const id = "BC-" + Date.now();
    const broadcastTag = body.type === 'critical' ? '[CRITICAL ALERT]: ' : '[BROADCAST]: ';
    const messageContent = broadcastTag + body.message;

    sheet.appendRow([
      id,
      "SYSTEM", 
      "Broadcast Hub",
      "ALL",
      messageContent, 
      new Date().toISOString(),
      "Sent"
    ]);

    SystemLogger.log("System", "BROADCAST", body.message, "Success");
    return ResponseBuilder.success();
  },
  handleAcknowledgeNotification: function(ss, body) {
    const sheet = ss.getSheetByName('Acknowledgements');
    if (sheet) sheet.appendRow([body.notificationId, body.user, new Date().toISOString()]);
    return ResponseBuilder.success();
  }
};

const PaymentHandlers = {
  handleMobileMoney: function(ss, body) {
    const settingsSheet = ss.getSheetByName('System_Settings');
    if (!settingsSheet) return ResponseBuilder.error("Settings missing.");
    const secretKey = settingsSheet.getRange(2, 10).getValue(); 
    if (!secretKey) return ResponseBuilder.error("Payment system not configured.");
    const payload = {
      "amount": body.amount, "currency": "ZMW", "phone_number": body.phoneNumber,
      "network": body.network, "email": body.email, "tx_ref": "TXN-" + Date.now(),
      "order_id": "SUB-" + Date.now(), "description": body.description, "country": "ZM"
    };
    try {
      const response = UrlFetchApp.fetch("https://api.flutterwave.com/v3/charges?type=mobile_money_zambia", {
        "method": "post", "contentType": "application/json",
        "headers": { "Authorization": "Bearer " + secretKey },
        "payload": JSON.stringify(payload), "muteHttpExceptions": true
      });
      const resData = JSON.parse(response.getContentText());
      if (resData.status === "success") {
        SystemLogger.log(body.email, "PAYMENT_INITIATED", "Renewal prompt sent to " + body.phoneNumber, "Success");
        return ResponseBuilder.success({ message: "Prompt dispatched." });
      } else {
        SystemLogger.log(body.email, "PAYMENT_ERROR", resData.message, "Error");
        return ResponseBuilder.error(resData.message);
      }
    } catch (e) { return ResponseBuilder.error("Gateway timeout."); }
  }
};

const SubscriptionHandlers = {
  handleCheckSubscription: function(ss) {
    let subSheet = ss.getSheetByName('Subscription_Data');
    if (!subSheet || subSheet.getLastRow() < 2) return ResponseBuilder.success({ subscription: { status: 'Expired', daysRemaining: 0 } });
    const data = subSheet.getRange(subSheet.getLastRow(), 1, 1, 4).getValues()[0];
    const expiry = new Date(data[2]);
    const diff = Math.ceil((expiry.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
    return ResponseBuilder.success({ subscription: { status: diff > 0 ? data[0] : 'Expired', plan: data[1], expiryDate: data[2], daysRemaining: Math.max(0, diff) } });
  },
  handleExtendSubscription: function(ss, body) {
    let subSheet = ss.getSheetByName('Subscription_Data');
    if (subSheet) subSheet.appendRow([body.status, body.plan, body.expiryDate, "System", new Date().toISOString()]);
    SystemLogger.log("System", "SUBSCRIPTION_UPDATED", "License extended to " + body.expiryDate, "Success");
    return ResponseBuilder.success();
  }
};`;

export const CODE_5_LIB_AND_UTILS = `// =========================================================
// 5. UTILITIES & LIBRARIES (Helpers, Email, PDF)
// =========================================================

const ResponseBuilder = {
  success: function(data = {}) { return this.build({ status: "success", ...data }); },
  error: function(message, code = null) {
    const response = { status: "error", message: message };
    if (code) response.code = code;
    return this.build(response);
  },
  build: function(data) {
    return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
  }
};

const SystemLogger = {
  log: function(user, action, details, status) {
    try {
      const ss = SpreadsheetApp.getActiveSpreadsheet();
      let logSheet = ss.getSheetByName('System_Logs');
      if (!logSheet) {
        logSheet = ss.insertSheet('System_Logs');
        logSheet.appendRow(['Timestamp', 'User', 'Action', 'Details', 'Status']);
        logSheet.getRange(1, 1, 1, 5).setFontWeight('bold').setBackground('#f3f3f3');
        logSheet.setFrozenRows(1);
      }
      logSheet.appendRow([new Date(), user || "System", action, details, status || "Info"]);
    } catch (e) {
      Logger.log("Logger Failure: " + e.toString());
    }
  }
};

const Validation = {
  updateFromRow: function(ss, body) {
     try {
       const row = body.row;
       const sheetName = body.sheet;
       let truck, trailer, driver, inspector, location;
       if (sheetName === 'General') {
           truck = row[2]; trailer = row[3]; inspector = row[4]; driver = row[5]; location = row[6];
       } else {
           truck = row[2]; trailer = row[3]; location = row[5]; inspector = row[7]; driver = row[8];
       }
       this.updateSingle(ss, 'Truck_Reg_No', truck);
       this.updateSingle(ss, 'Trailer_Reg_No', trailer);
       this.updateSingle(ss, 'Driver_Name', driver);
       this.updateSingle(ss, 'Inspector_Name', inspector);
       this.updateSingle(ss, 'Location', location);
     } catch (e) {}
  },
  updateSingle: function(ss, headerName, value) {
     if (!value || String(value).trim() === "") return;
     const valStr = String(value).trim();
     let vSheet = ss.getSheetByName('Validation_Data');
     if (!vSheet) {
        vSheet = ss.insertSheet('Validation_Data');
        vSheet.appendRow(['Truck_Reg_No', 'Trailer_Reg_No', 'Driver_Name', 'Inspector_Name', 'Location', 'Position']);
        vSheet.setFrozenRows(1);
     }
     const headers = vSheet.getRange(1, 1, 1, vSheet.getLastColumn()).getValues()[0];
     let colIndex = headers.indexOf(headerName) + 1;
     if (colIndex < 1) {
         colIndex = headers.length + 1;
         vSheet.getRange(1, colIndex).setValue(headerName);
     }
     const fullCol = vSheet.getRange(1, colIndex, vSheet.getMaxRows(), 1).getValues().flat().map(String);
     if (!fullCol.includes(valStr)) {
         let targetRow = 1;
         for(let i=1; i<fullCol.length; i++) {
             if(fullCol[i] === "") { targetRow = i + 1; break; }
         }
         if (targetRow === 1) targetRow = vSheet.getLastRow() + 1;
         vSheet.getRange(targetRow, colIndex).setValue(valStr);
     }
  }
};

const Logger = {
  log: function(ss, action, details) {
    SystemLogger.log("System", action, details, "Info");
  }
};

const EmailHandlers = {
  sendEmailNotifications: function(ss, data, moduleName) {
    SystemLogger.log("System", "EMAIL_START", "Module: " + moduleName, "Info");

    try {
      var userSheet = ss.getSheetByName("Users");
      if (!userSheet) {
          SystemLogger.log("System", "EMAIL_SKIP", "No Users sheet", "Warning");
          return;
      }

      var users = userSheet.getDataRange().getValues();
      var recipients = [];

      for (var i = 1; i < users.length; i++) {
         var userEmail = String(users[i][1]).toLowerCase(); // Username is in column 2
         var rawPrefs = users[i][7]; // Preferences in column 8
         var isActive = String(users[i][8]).toUpperCase() === 'TRUE'; // Enabled in column 9

         if (isActive && userEmail && userEmail.indexOf("@") > -1) {
             try {
                 var prefs = rawPrefs ? JSON.parse(rawPrefs) : {};
                 var emailsEnabled = (prefs.emailNotifications !== false); 

                 if (emailsEnabled) {
                     var shouldSend = false;
                     if (moduleName === "General" && (prefs.notifyGeneral !== false)) shouldSend = true;
                     if (moduleName === "Petroleum" && (prefs.notifyPetroleum !== false)) shouldSend = true;
                     if (moduleName === "Petroleum_V2" && (prefs.notifyPetroleumV2 !== false)) shouldSend = true;
                     if (moduleName === "Acid" && (prefs.notifyAcid !== false)) shouldSend = true;

                     if (shouldSend) recipients.push(userEmail);
                 }
             } catch(e) {
                 // Skip users with malformed preferences
             }
         }
      }

      if (recipients.length === 0) {
          SystemLogger.log("System", "EMAIL_SKIP", "No recipients found for " + moduleName, "Info");
          return;
      }

      SystemLogger.log("System", "EMAIL_RECIPIENTS", recipients.join(", "), "Info");

      // Extract Info
      var row = data.row;
      var truckNo = "N/A", driver = "N/A", inspector = "N/A", rating = "N/A";

      if (moduleName === "General") {
          truckNo = row[2]; driver = row[5]; inspector = row[4]; rating = row[8];
      } else {
          truckNo = row[2]; driver = row[8]; inspector = row[7]; rating = row[9];
      }

      var statusColor = "#10b981"; // Green
      var statusText = "PASSED";
      if (rating <= 3) { statusColor = "#f59e0b"; statusText = "WARNING"; } 
      if (rating <= 2) { statusColor = "#ef4444"; statusText = "CRITICAL FAIL"; }

      // Professional HTML Email Body
      var htmlBody = 
          "<div style='font-family: Helvetica, Arial, sans-serif; max-width: 600px; margin: 0 auto; border: 1px solid #e2e8f0; border-radius: 8px; overflow: hidden; background-color: #ffffff;'>" +
              // Header
              "<div style='background-color: #0f172a; padding: 25px; text-align: center;'>" +
                  "<h2 style='color: white; margin: 0; font-size: 20px; font-weight: 600; letter-spacing: 0.5px;'>INSPECTION ALERT</h2>" +
              "</div>" +

              // Content
              "<div style='padding: 30px; color: #334155;'>" +
                  "<p style='margin-top: 0; font-size: 15px; color: #475569;'>A new " + moduleName + " inspection report has been submitted.</p>" +

                  "<div style='background-color: #f8fafc; padding: 20px; border-radius: 8px; border: 1px solid #e2e8f0; margin: 20px 0;'>" +
                      "<table style='width: 100%; border-collapse: collapse;'>" +
                          "<tr>" +
                              "<td style='padding: 5px 0; color: #64748b; font-size: 12px; font-weight: 700; text-transform: uppercase;'>Vehicle</td>" +
                              "<td style='padding: 5px 0; color: #0f172a; font-size: 14px; font-weight: 600; text-align: right;'>" + truckNo + "</td>" +
                          "</tr>" +
                          "<tr>" +
                              "<td style='padding: 5px 0; color: #64748b; font-size: 12px; font-weight: 700; text-transform: uppercase;'>Inspector</td>" +
                              "<td style='padding: 5px 0; color: #0f172a; font-size: 14px; font-weight: 600; text-align: right;'>" + inspector + "</td>" +
                          "</tr>" +
                          "<tr>" +
                              "<td style='padding: 5px 0; color: #64748b; font-size: 12px; font-weight: 700; text-transform: uppercase;'>Result</td>" +
                              "<td style='padding: 5px 0; text-align: right;'>" +
                                  "<span style='color: " + statusColor + "; font-weight: 800; font-size: 14px;'>" + statusText + " (" + rating + "/5)</span>" +
                              "</td>" +
                          "</tr>" +
                      "</table>" +
                  "</div>" +

                  "<p style='font-size: 14px; line-height: 1.5;'>The official PDF report is attached to this email. Please review the findings.</p>" +

                  "<div style='margin-top: 30px; text-align: center;'>" +
                      "<a href='#' style='background-color: #0f172a; color: white; padding: 12px 24px; text-decoration: none; border-radius: 6px; font-weight: bold; font-size: 14px; display: inline-block;'>View Dashboard</a>" +
                  "</div>" +

                  "<hr style='border: 0; border-top: 1px solid #e2e8f0; margin: 30px 0;' />" +
                  "<p style='font-size: 11px; color: #94a3b8; text-align: center; margin: 0;'>Sent by SafetyCheck Pro Alerts System.</p>" +
              "</div>" +
          "</div>";

      var blobs = [];
      if (data.reportData) {
          try {
              var reportHtml = PDFGenerator.create(data.reportData);
              // CRITICAL: Fixed MimeType enum issues by using direct strings
              var pdfBlob = Utilities.newBlob(reportHtml, 'text/html')
                  .getAs('application/pdf')
                  .setName(truckNo.replace(/\s/g, '_') + '_' + moduleName + '_Report.pdf');

              blobs.push(pdfBlob);
              SystemLogger.log(inspector, "PDF_GENERATED", "Success: " + pdfBlob.getBytes().length + " bytes", "Info");
          } catch (e) {
              SystemLogger.log(inspector, "PDF_ERROR", e.toString(), "Error");
          }
      } else {
          SystemLogger.log(inspector, "PDF_MISSING", "No reportData provided", "Warning");
      }

      var subject = "Inspection Report: " + truckNo + " [" + statusText + "]";
      var senderName = "Alerts"; 
      var senderEmail = "notification@sallychanza.com";

      var emailOptions = {
          htmlBody: htmlBody,
          name: senderName, 
          attachments: blobs,
          bcc: recipients.slice(1).join(","),
          // Reply to the alias, regardless of how it's sent
          replyTo: senderEmail,
          // Attempt to send FROM the alias
          from: senderEmail
      };

      // --- SENDING STRATEGY ---
