  sendInvitation: function(email, role, orgName) {
    let safeOrgName = orgName;
    let managerEmail = "";

    try {
      const ss = SpreadsheetApp.getActiveSpreadsheet();
      const settingsSheet = ss.getSheetByName('System_Settings');
      if (settingsSheet && settingsSheet.getLastRow() > 1) {
        const rowData = settingsSheet.getRange(2, 1, 1, 2).getValues()[0];
        if (!safeOrgName) safeOrgName = String(rowData[0]);
        managerEmail = String(rowData[1]);
      }
    } catch (e) {
      SystemLogger.log("System", "INVITE_CONFIG_ERROR", e.toString(), "Warning");
    }

    if (!safeOrgName) safeOrgName = "Fleet Portal";
    const subject = "Invitation: SafetyCheck Pro Access - " + safeOrgName;

    const htmlBody = '<div style="font-family: Arial, sans-serif; padding: 24px; border: 1px solid #e2e8f0; border-radius: 16px; max-width: 600px; color: #1e293b;">' +
      '<h2 style="color: #4f46e5; margin-bottom: 16px; font-size: 20px; font-weight: bold;">Welcome to SafetyCheck Pro</h2>' +
      '<p style="font-size: 14px; line-height: 1.5;">Hello,</p>' +
      '<p style="font-size: 14px; line-height: 1.5;">An account has been provisioned for you on the <strong>' + safeOrgName + '</strong> Fleet Management System.</p>' +
      '<div style="background: #f8fafc; padding: 20px; border-radius: 12px; margin: 24px 0; border: 1px solid #f1f5f9;">' +
        '<p style="margin: 0 0 8px 0; font-size: 13px;"><strong>Access Role:</strong> ' + role + '</p>' +
        '<p style="margin: 0; font-size: 13px;"><strong>Login ID:</strong> ' + email + '</p>' +
      '</div>' +
      '<p style="font-size: 14px; line-height: 1.5;">You can now sign in to the portal using your email address. Since this is your first entry, you may leave the <strong>password field blank</strong> to begin your profile setup.</p>' +
      '<p style="font-size: 12px; color: #64748b; margin-top: 24px; border-top: 1px solid #f1f5f9; padding-top: 16px;">Please set a secure password immediately after your first sign-in.</p>' +
    '</div>';

    const plainBody = "Hello, your account has been created on " + safeOrgName + ". Role: " + role + ". Login ID: " + email + ". Sign in with your email and leave the password blank for your first entry.";

    try {
      const mailOptions = {
        htmlBody: htmlBody,
        name: safeOrgName + " Administrator"
      };

      if (managerEmail && managerEmail.includes('@')) {
        mailOptions.replyTo = managerEmail;
      }

      MailApp.sendEmail(email, subject, plainBody, mailOptions);
      SystemLogger.log("Admin", "INVITE_SENT", "Invitation sent to " + email, "Success");
    } catch (e) {
      SystemLogger.log("Admin", "INVITE_FAILED", "Failed to send invitation to " + email + ": " + e.toString(), "Critical");
    }
