const PDFGenerator = {
  create: function(data) {
    if (data.title && (data.title.indexOf('General') > -1 || data.title.indexOf('GENERAL') > -1)) {
       return this.createGeneralReport(data);
    }
    if (data.title && data.title.indexOf('Petroleum Tanker Inspection V2') > -1) {
       return this.createPetroleumV2Report(data);
    }
    if (data.title && data.title.indexOf('Petroleum Tanker Inspection') > -1) {
       return this.createPetroleumReport(data);
    }
    if (data.title && data.title.indexOf('Acid Tanker Inspection') > -1) {
       return this.createAcidReport(data);
    }
    return this.createGenericReport(data);
  },

  createAcidReport: function(data) {
      var dateStr = new Date(data.timestamp).toLocaleString('en-GB');
      var itemsHtml = "";
      var currentCategory = "";
      (data.items || []).forEach(function(item) {
          if (item.category !== currentCategory) {
              currentCategory = item.category;
              itemsHtml += "<tr><td colspan='3' style='background-color:#E0E0E0; font-weight:bold; border:1px solid black; padding:4px 5px; font-size:11px;'>" + currentCategory + "</td></tr>";
          }
          var status = item.status;
          var statusStyle = status === 'Good' ? "color:#008000;font-weight:bold;" : status === 'Bad' ? "color:#D32F2F;font-weight:bold;" : "color:#EF6C00;font-weight:bold;";
          itemsHtml += "<tr><td style='border:1px solid black; text-align:center; padding:3px;'>" + item.label.split('.')[0] + "</td><td style='border:1px solid black; padding:3px 5px;'>" + item.label + "</td><td style='border:1px solid black; padding:3px 5px; " + statusStyle + "'>" + (status || "") + "</td></tr>";
      });
      return "<html><body><h2>ACID TANKER CHECKLIST</h2><table border='1' style='border-collapse:collapse;width:100%;'>" + itemsHtml + "</table></body></html>";
  },

  createPetroleumV2Report: function(data) {
      var itemsHtml = "";
      (data.items || []).forEach(function(item) {
          itemsHtml += "<tr><td style='border:1px solid black; padding:5px;'>" + item.label + "</td><td style='border:1px solid black; padding:5px;'>" + item.status + "</td></tr>";
      });
      return "<html><body><h2>PETROLEUM TANKER CHECKLIST</h2><table border='1' style='border-collapse:collapse;width:100%;'>" + itemsHtml + "</table></body></html>";
  },

  createPetroleumReport: function(data) { return this.createPetroleumV2Report(data); },

  createGeneralReport: function(data) {
      var itemsHtml = "";
      (data.items || []).forEach(function(item) {
          itemsHtml += "<tr><td style='border:1px solid black; padding:5px;'>" + item.label + "</td><td style='border:1px solid black; padding:5px;'>" + item.status + "</td></tr>";
      });
      return "<html><body><h2>GENERAL VEHICLE CHECKLIST</h2><table border='1' style='border-collapse:collapse;width:100%;'>" + itemsHtml + "</table></body></html>";
  },

  createGenericReport: function(data) {
    return "<html><body><h2>" + data.title + "</h2></body></html>";
  }
};

