const DataHandlers = {
  handleDataSubmission: function(ss, body) {
    const sheetName = body.sheet;
    const rowData = body.row;
    let sheet = ss.getSheetByName(sheetName);
    if (!sheet) return ResponseBuilder.error("Registry not found.");
    const safeRow = rowData.map(r => (r === null || r === undefined) ? "" : String(r));
    sheet.appendRow(safeRow);
    Validation.updateFromRow(ss, body);

    if (body.requestId) {
        const reqSheet = ss.getSheetByName('Inspection_Requests');
        if (reqSheet) {
            const reqData = reqSheet.getDataRange().getValues();
            for (let i = 1; i < reqData.length; i++) {
                if (String(reqData[i][0]) === String(body.requestId)) {
                    reqSheet.getRange(i + 1, 10).setValue('Completed');
                    break;
                }
            }
        }
    }

    const inspector = body.reportData ? body.reportData.inspectedBy : "System";
    const truck = body.reportData ? body.reportData.truckNo : "Unknown";
    SystemLogger.log(inspector, "DATA_SUBMITTED", "Inspection saved for " + truck, "Success");
    EmailHandlers.sendEmailNotifications(ss, body, sheetName);
    return ResponseBuilder.success({ sheet: sheetName });
  },

  handleGetRequest: function(ss) {
    const sheets = ss.getSheets();
    const data = {};
    sheets.forEach(sheet => {
      const name = sheet.getName();
      if (['Users', 'System_Logs', 'Acknowledgements', 'Support_Tickets'].indexOf(name) > -1) return;
      const lastRow = sheet.getLastRow();
      if (lastRow === 0) { data[name] = []; return; }

      if (name === 'Validation_Data') {
         if (lastRow > 1) {
            const range = sheet.getRange(2, 1, lastRow - 1, sheet.getLastColumn());
            const values = range.getValues();
            const columns = {};
            const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
            headers.forEach((h, colIndex) => { columns[h] = [...new Set(values.map(row => row[colIndex]).filter(c => c !== ""))]; });
            data[name] = columns;
         } else { data[name] = {}; }
      } else if (name === 'Subscription_Data') {
          const values = sheet.getDataRange().getValues();
          if (values.length > 1) {
            const history = values.slice(1).map(r => {
                let expiry = r[2];
                if (expiry instanceof Date) expiry = Utilities.formatDate(expiry, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
                return { status: r[0], plan: r[1], expiryDate: expiry, processedBy: r[3], timestamp: r[4] };
            });
            data[name] = { current: history[history.length - 1], history: history };
          } else { data[name] = { current: { status: "Expired", plan: "None", expiryDate: "" }, history: [] }; }
      } else {
         const startRow = Math.max(1, lastRow - 150);
         const values = sheet.getRange(startRow, 1, lastRow - startRow + 1, sheet.getLastColumn()).getValues();
         if (startRow > 1) values.unshift(sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0]);
         data[name] = values;
      }
    });
    return ResponseBuilder.build(data);
  }
};

const SystemHandlers = {
  handleUpdateSettings: function(ss, body) {
    let settingsSheet = ss.getSheetByName('System_Settings');
    if (!settingsSheet) return ResponseBuilder.error("Sheet missing.");
    const updateRow = [body.companyName || '', body.managerEmail || '', new Date(), body.updatedBy || "Admin", body.companyLogo || '', body.mobileApkLink || '', body.webAppUrl || '', body.maintenanceMode ? "TRUE" : "FALSE", body.maintenanceMessage || '', body.flutterwaveSecretKey || ''];
    if (settingsSheet.getLastRow() < 2) settingsSheet.appendRow(updateRow);
    else settingsSheet.getRange(2, 1, 1, updateRow.length).setValues([updateRow]);
    SystemLogger.log("Admin", "SETTINGS_UPDATED", "System state synced", "Success");
    return ResponseBuilder.success();
  },
  handleManageFleet: function(ss, body) {
    const sheet = ss.getSheetByName('Validation_Data');
    const col = body.type === 'truck' ? 1 : 2;
    sheet.getRange(sheet.getLastRow() + 1, col).setValue(body.value);
    return ResponseBuilder.success();
  },
  handleBulkManageFleet: function(ss, body) {
    const sheet = ss.getSheetByName('Validation_Data');
    if (body.trucks) body.trucks.forEach(t => sheet.getRange(sheet.getLastRow() + 1, 1).setValue(t));
    if (body.trailers) body.trailers.forEach(t => sheet.getRange(sheet.getLastRow() + 1, 2).setValue(t));
    return ResponseBuilder.success();
  },
  handleRequestInspection: function(ss, body) {
    const sheet = ss.getSheetByName('Inspection_Requests');
    const id = "REQ-" + Date.now();
    sheet.appendRow([id, body.requester, body.role, body.truckNo, body.trailerNo, body.type, body.reason, body.priority, body.assignedInspector || "Unassigned", "Pending", new Date().toISOString()]);
    return ResponseBuilder.success();
  },
  handleBroadcast: function(ss, body) {
    const sheet = ss.getSheetByName('Messages');
    const tag = body.type === 'critical' ? '[CRITICAL ALERT]: ' : '[BROADCAST]: ';
    sheet.appendRow(["BC-" + Date.now(), "SYSTEM", "Broadcast Hub", "ALL", tag + body.message, new Date().toISOString(), "Sent"]);
    return ResponseBuilder.success();
  },
  handleAcknowledgeNotification: function(ss, body) {
    const sheet = ss.getSheetByName('Acknowledgements');
    if (sheet) sheet.appendRow([body.notificationId, body.user, new Date().toISOString()]);
    return ResponseBuilder.success();
  }
};

const PaymentHandlers = {
  handleMobileMoney: function(ss, body) {
    const settingsSheet = ss.getSheetByName('System_Settings');
    const secretKey = settingsSheet.getRange(2, 10).getValue(); 
    if (!secretKey) return ResponseBuilder.error("Gateway not configured.");
    const payload = { "amount": body.amount, "currency": "ZMW", "phone_number": body.phoneNumber, "network": body.network, "email": body.email, "tx_ref": "TXN-" + Date.now(), "order_id": "SUB-" + Date.now(), "description": body.description, "country": "ZM" };
    try {
      const response = UrlFetchApp.fetch("https://api.flutterwave.com/v3/charges?type=mobile_money_zambia", { "method": "post", "contentType": "application/json", "headers": { "Authorization": "Bearer " + secretKey }, "payload": JSON.stringify(payload), "muteHttpExceptions": true });
      const resData = JSON.parse(response.getContentText());
      if (resData.status === "success") return ResponseBuilder.success({ message: "Prompt dispatched." });
      return ResponseBuilder.error(resData.message);
    } catch (e) { return ResponseBuilder.error("Gateway timeout."); }
  }
};

const SubscriptionHandlers = {
  handleCheckSubscription: function(ss) {
    let subSheet = ss.getSheetByName('Subscription_Data');
    if (!subSheet || subSheet.getLastRow() < 2) return ResponseBuilder.success({ subscription: { status: 'Expired', daysRemaining: 0 } });
    const data = subSheet.getRange(subSheet.getLastRow(), 1, 1, 4).getValues()[0];
    const expiry = new Date(data[2]);
    const diff = Math.ceil((expiry.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
    return ResponseBuilder.success({ subscription: { status: diff > 0 ? data[0] : 'Expired', plan: data[1], expiryDate: data[2], daysRemaining: Math.max(0, diff) } });
  },
  handleExtendSubscription: function(ss, body) {
    let subSheet = ss.getSheetByName('Subscription_Data');
    if (subSheet) subSheet.appendRow([body.status, body.plan, body.expiryDate, "System", new Date().toISOString()]);
    return ResponseBuilder.success();
  }
};

