         if (String(users[i][8]).toUpperCase() === 'TRUE' && users[i][1].indexOf("@") > -1) recipients.push(users[i][1]);
      }
      if (recipients.length === 0) return;
      var row = data.row;
      var truckNo = row[2];
      var rating = moduleName === "General" ? row[8] : row[9];
