const PDFGenerator = {
  create: function(data) {
    if (data.title && (data.title.indexOf('General') > -1 || data.title.indexOf('GENERAL') > -1)) return this.createGeneralReport(data);
    if (data.title && data.title.indexOf('Petroleum Tanker Inspection V2') > -1) return this.createPetroleumV2Report(data);
    if (data.title && data.title.indexOf('Petroleum Tanker Inspection') > -1) return this.createPetroleumReport(data);
    if (data.title && data.title.indexOf('Acid Tanker Inspection') > -1) return this.createAcidReport(data);
    return this.createGenericReport(data);
  },

  createAcidReport: function(data) {
      var dateStr = new Date(data.timestamp).toLocaleString('en-GB');
      var itemsHtml = "";
      var currentCategory = "";
      (data.items || []).forEach(function(item) {
          if (item.category !== currentCategory) {
              currentCategory = item.category;
              itemsHtml += "<tr><td colspan='3' style='background-color:#E0E0E0; font-weight:bold; border:1px solid black; padding:4px 5px; font-size:11px;'>" + currentCategory + "</td></tr>";
          }
          var status = item.status;
          var statusStyle = status === 'Good' ? "color:#008000;" : status === 'Bad' ? "color:#D32F2F;" : "color:#EF6C00;";
          itemsHtml += "<tr><td style='border:1px solid black; text-align:center; padding:3px;'>" + item.label.split('.')[0] + "</td><td style='border:1px solid black; padding:3px 5px;'>" + item.label + "</td><td style='border:1px solid black; padding:3px 5px; font-weight:bold; " + statusStyle + "'>" + (status || "") + "</td></tr>";
      });
      return "<html><head><style>body { font-family: Arial; font-size: 10px; padding: 20px; } table { width: 100%; border-collapse: collapse; } </style></head><body>" +
             "<table border='1' style='width:100%; margin-bottom:10px;'><tr><td rowspan='4' style='width:20%; text-align:center; font-weight:bold;'>" + data.companyName + "</td><td style='font-weight:bold;'>Doc No: MNT – F – 013</td><td>Issue Date</td><td>03/02/2017</td></tr><tr><td rowspan='3' style='font-size:16px; font-weight:bold; text-align:center;'>ACID TANKER CHECKLIST</td><td>Rev Date</td><td>15/03/2022</td></tr><tr><td>Rev No</td><td>05</td></tr><tr><td>Next Rev</td><td>15/03/2023</td></tr></table>" +
             "<p><b>Unit:</b> " + data.truckNo + " | <b>Trailer:</b> " + data.trailerNo + " | <b>Date:</b> " + dateStr + "</p>" +
             "<table border='1'>" + itemsHtml + "</table><p><b>Remarks:</b> " + (data.remarks || "") + "</p></body></html>";
  },

  createPetroleumV2Report: function(data) {
      var itemsHtml = "";
      var currentCategory = "";
      (data.items || []).forEach(function(item) {
          if (item.category !== currentCategory) {
              currentCategory = item.category;
              itemsHtml += "<tr><td colspan='7' style='background-color:#E0E0E0; font-weight:bold; border:1px solid black; text-align:center; padding:4px; font-size:11px;'>" + currentCategory.toUpperCase() + "</td></tr>";
          }
          var status = item.status;
          var c = (status === 'Good' || status === 'Compliant') ? '✔' : '';
          var nc = (status === 'Bad' || status === 'Non-Compliant') ? '✔' : '';
          itemsHtml += "<tr><td style='border:1px solid black; text-align:center;'>" + item.label.split('.')[0] + "</td><td style='border:1px solid black; padding:2px 5px;'>" + item.label + "</td><td style='border:1px solid black; text-align:center;'>" + c + "</td><td style='border:1px solid black; text-align:center;'>" + nc + "</td><td style='border:1px solid black;'></td><td style='border:1px solid black;'></td><td style='border:1px solid black;'>" + (nc ? "NON-COMPLIANT" : "") + "</td></tr>";
      });
      return "<html><head><style>body { font-family: Arial; font-size: 10px; padding: 10px; } table { width:100%; border-collapse:collapse; } </style></head><body>" +
             "<h2 style='text-align:center;'>PETROLEUM TANKER CHECKLIST</h2>" +
             "<p><b>TRUCK:</b> " + data.truckNo + " | <b>TRAILER:</b> " + data.trailerNo + "</p>" +
             "<table><tr style='background:#eee; font-weight:bold;'><td>No</td><td>Item</td><td>C</td><td>NC</td><td>NI</td><td>NA</td><td>Comment</td></tr>" + itemsHtml + "</table></body></html>";
  },

  createPetroleumReport: function(data) { return this.createPetroleumV2Report(data); },

  createGeneralReport: function(data) {
      var itemsHtml = "";
      (data.items || []).forEach(function(item) {
          var status = item.status || 'N/A';
          var color = (status === 'Bad' || status === 'Fail') ? '#D32F2F' : '#000';
          itemsHtml += "<tr><td style='border-bottom:1px solid #ccc; padding:8px 4px;'>" + item.label + "</td><td style='border-bottom:1px solid #ccc; padding:8px 4px; text-align:right; font-weight:bold; color:" + color + ";'>" + status + "</td></tr>";
      });
      return "<html><head><style>body { font-family: Arial; padding: 20px; } </style></head><body>" +
             "<h2 style='text-align:center;'>GENERAL VEHICLE CHECKLIST</h2>" +
             "<p><b>Unit:</b> " + data.truckNo + " | <b>Driver:</b> " + data.driverName + "</p>" +
             "<table style='width:100%; border-collapse:collapse;'>" + itemsHtml + "</table>" +
             "<p><b>Safety Decision:</b> SAFE TO LOAD: " + data.safeToLoad + "</p></body></html>";
  },

  createGenericReport: function(data) {
    return "<html><body><h2>" + (data.title || "Inspection Report") + "</h2><p><b>Unit:</b> " + data.truckNo + "</p></body></html>";
  }
};
