/**
 * 2_AuthAndAdmin.gs
 * Handles authentication and staff management.
 */

const AuthHandlers = {
  handleLogin: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.error("Configuration Error: 'Users' sheet not found.");
    const data = userSheet.getDataRange().getValues();
    const username = body.username.toLowerCase();

    for (let i = 1; i < data.length; i++) {
        const storedUser = String(data[i][1]).toLowerCase();
        const storedPass = String(data[i][2]);
        const storedName = String(data[i][3]);
        const userRole = data[i][4];
        const userPos = data[i][5];
        const userId = data[i][0];

        if (storedUser === username) {
            const passwordMatch = (storedPass === body.password);
            const isNewUserInvite = (storedName === "" && storedPass === "" && body.password === "");

            if (passwordMatch || isNewUserInvite) {
                return ResponseBuilder.success({ 
                  user: { id: userId, username: storedUser, name: storedName, role: userRole, position: userPos } 
                });
            }
        }
    }
    return ResponseBuilder.error("Invalid credentials.");
  },

  handleHeartbeat: function(ss, body) {
    let msgSheet = ss.getSheetByName('Messages');
    if (!msgSheet) return ResponseBuilder.error("Messages sheet missing");
    const data = msgSheet.getDataRange().getValues();
    const username = body.username.toLowerCase();
    const statusType = body.isTyping ? "Typing" : "Presence";
    const now = new Date().toISOString();

    let foundIndex = -1;
    const searchLimit = Math.max(1, data.length - 200);
    for (let i = data.length - 1; i >= searchLimit; i--) {
      if (String(data[i][1]).toLowerCase() === username && data[i][4] === "HB") {
        foundIndex = i;
        break;
      }
    }

    if (foundIndex !== -1) {
      msgSheet.getRange(foundIndex + 1, 6).setValue(now);
      msgSheet.getRange(foundIndex + 1, 7).setValue(statusType);
    } else {
      msgSheet.appendRow(["ST-" + Date.now(), body.username, body.name || "User", "ALL", "HB", now, statusType]);
    }
    return ResponseBuilder.success();
  },

  handleMarkRead: function(ss, body) {
    let msgSheet = ss.getSheetByName('Messages');
    if (!msgSheet) return ResponseBuilder.error("Messages sheet missing");
    const data = msgSheet.getDataRange().getValues();
    const myId = body.username.toLowerCase();
    const senderId = body.senderId.toLowerCase();
    for (let i = data.length - 1; i >= 1; i--) {
        if (String(data[i][3]).toLowerCase() === myId && String(data[i][1]).toLowerCase() === senderId && data[i][6] === 'Sent') {
            msgSheet.getRange(i + 1, 7).setValue('Read');
        }
        if (i < data.length - 100) break; 
    }
    return ResponseBuilder.success();
  },

  handleRegisterUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.error("Database Error: 'Users' sheet missing.");
    const data = sheet.getDataRange().getValues();
    const newUsername = String(body.username || '').toLowerCase().trim();
    for (let i = 1; i < data.length; i++) {
      if (String(data[i][1]).toLowerCase() === newUsername) return ResponseBuilder.error("User exists.");
    }
    const id = "USR-" + Date.now();
    sheet.appendRow([id, newUsername, body.password || "", body.name || "", body.role, body.position, new Date().toISOString(), JSON.stringify(body.preferences || {}), "TRUE"]);

    let orgName = "Fleet Portal";
    const settingsSheet = ss.getSheetByName('System_Settings');
    if (settingsSheet && settingsSheet.getLastRow() > 1) {
      const val = settingsSheet.getRange(2, 1).getValue();
      if (val) orgName = String(val);
    }

    // Call the specific EmailHandlers method from your snippet
    EmailHandlers.sendInvitation(newUsername, body.role, orgName);
    return ResponseBuilder.success();
  },

  handleGetUsers: function(ss) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.success({ users: [] });
    const userData = userSheet.getDataRange().getValues();
    const users = userData.slice(1).map(r => ({ id: r[0], username: r[1], name: r[3], role: r[4], position: r[5], isActive: String(r[8]).toUpperCase() === "TRUE" }));
    return ResponseBuilder.success({ users });
  },

  handleDeleteUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][1].toLowerCase() === body.username.toLowerCase()) {
        sheet.deleteRow(i + 1);
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("Not found.");
  },

  handleUpdateUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][1].toLowerCase() === (body.originalUsername || body.username).toLowerCase()) {
        if (body.username) sheet.getRange(i + 1, 2).setValue(body.username);
        if (body.password) sheet.getRange(i + 1, 3).setValue(body.password);
        if (body.name) sheet.getRange(i + 1, 4).setValue(body.name);
        if (body.role) sheet.getRange(i + 1, 5).setValue(body.role);
        if (body.position) sheet.getRange(i + 1, 6).setValue(body.position);
        if (body.isActive !== undefined) sheet.getRange(i + 1, 9).setValue(body.isActive ? "TRUE" : "FALSE");
        if (body.preferences) sheet.getRange(i + 1, 8).setValue(JSON.stringify(body.preferences));
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("Not found");
  }
};

/**
 * 3_CoreOperations.gs
 * Handles data flow, fleet assets, and system configuration.
 */

const DataHandlers = {
  handleDataSubmission: function(ss, body) {
    const sheetName = body.sheet;
    const rowData = body.row;
    let sheet = ss.getSheetByName(sheetName);

    if (!sheet) return ResponseBuilder.error("Target registry '" + sheetName + "' not found.");

    const safeRow = rowData.map(r => (r === null || r === undefined) ? "" : String(r));
    sheet.appendRow(safeRow);

    // Auto-update Validation Data lists
    Validation.updateFromRow(ss, body);

    if (body.requestId) {
        const reqSheet = ss.getSheetByName('Inspection_Requests');
        if (reqSheet) {
            const reqData = reqSheet.getDataRange().getValues();
            for (let i = 1; i < reqData.length; i++) {
                if (String(reqData[i][0]) === String(body.requestId)) {
                    reqSheet.getRange(i + 1, 10).setValue('Completed');
                    break;
                }
            }
        }
    }

    // Logging and Email dispatch using user's specific logic
    const truck = body.reportData ? body.reportData.truckNo : "Unknown";
    Logger.log(ss, "DATA_SUBMITTED", "Inspection saved for " + truck);

    // Trigger the professional broadcast notification logic
    EmailHandlers.sendEmailNotifications(ss, body, sheetName);

    return ResponseBuilder.success({ sheet: sheetName });
  },

  handleGetRequest: function(ss) {
    const sheets = ss.getSheets();
    const data = {};
    sheets.forEach(sheet => {
      const name = sheet.getName();
      if (['Users', 'System_Logs', 'Acknowledgements', 'Support_Tickets'].indexOf(name) > -1) return;
      const lastRow = sheet.getLastRow();
      if (lastRow === 0) { data[name] = []; return; }

      if (name === 'Validation_Data') {
         if (lastRow > 1) {
            const range = sheet.getRange(2, 1, lastRow - 1, sheet.getLastColumn());
            const values = range.getValues();
            const columns = {};
            const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
            headers.forEach((h, colIndex) => { columns[h] = [...new Set(values.map(row => row[colIndex]).filter(c => c !== ""))]; });
            data[name] = columns;
         } else { data[name] = {}; }
      } else if (name === 'Subscription_Data') {
          const values = sheet.getDataRange().getValues();
          if (values.length > 1) {
            const history = values.slice(1).map(r => {
                let expiry = r[2];
                if (expiry instanceof Date) expiry = Utilities.formatDate(expiry, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
                return { status: r[0], plan: r[1], expiryDate: expiry, processedBy: r[3], timestamp: r[4] };
            });
            data[name] = { current: history[history.length - 1], history: history };
          } else { data[name] = { current: { status: "Expired", plan: "None", expiryDate: "" }, history: [] }; }
      } else {
         const startRow = Math.max(1, lastRow - 150);
         const values = sheet.getRange(startRow, 1, lastRow - startRow + 1, sheet.getLastColumn()).getValues();
         if (startRow > 1) values.unshift(sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0]);
         data[name] = values;
      }
    });
    return ResponseBuilder.build(data);
  }
};

const SystemHandlers = {
  handleUpdateSettings: function(ss, body) {
    let settingsSheet = ss.getSheetByName('System_Settings');
    if (!settingsSheet) return ResponseBuilder.error("Sheet missing.");
    const updateRow = [body.companyName || '', body.managerEmail || '', new Date(), body.updatedBy || "Admin", body.companyLogo || '', body.mobileApkLink || '', body.webAppUrl || '', body.maintenanceMode ? "TRUE" : "FALSE", body.maintenanceMessage || '', body.flutterwaveSecretKey || ''];
    if (settingsSheet.getLastRow() < 2) settingsSheet.appendRow(updateRow);
    else settingsSheet.getRange(2, 1, 1, updateRow.length).setValues([updateRow]);
    Logger.log(ss, "SETTINGS_UPDATED", "System state synced");
    return ResponseBuilder.success();
  },
  handleManageFleet: function(ss, body) {
    const sheet = ss.getSheetByName('Validation_Data');
    const col = body.type === 'truck' ? 1 : 2;
    sheet.getRange(sheet.getLastRow() + 1, col).setValue(body.value);
    return ResponseBuilder.success();
  },
  handleBulkManageFleet: function(ss, body) {
    const sheet = ss.getSheetByName('Validation_Data');
    if (body.trucks) body.trucks.forEach(t => sheet.getRange(sheet.getLastRow() + 1, 1).setValue(t));
    if (body.trailers) body.trailers.forEach(t => sheet.getRange(sheet.getLastRow() + 1, 2).setValue(t));
    return ResponseBuilder.success();
  },
  handleRequestInspection: function(ss, body) {
    const sheet = ss.getSheetByName('Inspection_Requests');
    const id = "REQ-" + Date.now();
    sheet.appendRow([id, body.requester, body.role, body.truckNo, body.trailerNo, body.type, body.reason, body.priority, body.assignedInspector || "Unassigned", "Pending", new Date().toISOString()]);
    return ResponseBuilder.success();
  },
  handleBroadcast: function(ss, body) {
    const sheet = ss.getSheetByName('Messages');
    const tag = body.type === 'critical' ? '[CRITICAL ALERT]: ' : '[BROADCAST]: ';
    sheet.appendRow(["BC-" + Date.now(), "SYSTEM", "Broadcast Hub", "ALL", tag + body.message, new Date().toISOString(), "Sent"]);
    return ResponseBuilder.success();
  },
  handleAcknowledgeNotification: function(ss, body) {
    const sheet = ss.getSheetByName('Acknowledgements');
    if (sheet) sheet.appendRow([body.notificationId, body.user, new Date().toISOString()]);
    return ResponseBuilder.success();
  }
};

const PaymentHandlers = {
  handleMobileMoney: function(ss, body) {
    const settingsSheet = ss.getSheetByName('System_Settings');
    const secretKey = settingsSheet.getRange(2, 10).getValue(); 
    if (!secretKey) return ResponseBuilder.error("Gateway not configured.");
